UPDATE words SET example_en_2 = 'Phenolic compounds give wine its color and structure.', example_ko_2 = '페놀 화합물이 와인에 색상과 구조를 줘요.', example_en_3 = 'Higher phenolic content means better aging potential.', example_ko_3 = '페놀 함량이 높을수록 숙성 잠재력이 좋아요.', example_en_4 = 'Phenolic compounds are antioxidants found in red wine.', example_ko_4 = '페놀 화합물은 레드 와인에 있는 항산화 물질이에요.', example_en_5 = 'The analysis revealed rich phenolic compound levels.', example_ko_5 = '분석 결과 풍부한 페놀 화합물 수준이 나타났어요.' WHERE id = 'w_cafe_C2_11';
