UPDATE words SET example_en_2 = 'Malolactic fermentation softens sharp malic acid into lactic.', example_ko_2 = '유산 발효는 날카로운 사과산을 유산으로 부드럽게 변환해요.', example_en_3 = 'Most Chardonnays undergo malolactic fermentation.', example_ko_3 = '대부분의 샤르도네는 유산 발효를 거쳐요.', example_en_4 = 'Malolactic fermentation reduces acidity in wine.', example_ko_4 = '유산 발효는 와인의 산도를 줄여요.', example_en_5 = 'The buttery note in this Chardonnay comes from malolactic fermentation.', example_ko_5 = '이 샤르도네의 버터 같은 향은 유산 발효에서 나와요.' WHERE id = 'w_cafe_C2_13';
UPDATE words SET example_en_2 = 'Aging on the lees adds complexity and creaminess.', example_ko_2 = '효모 찌꺼기 위에서 숙성하면 복잡성과 크리미함이 더해져요.', example_en_3 = 'Champagne gains richness from extended lees contact.', example_ko_3 = '샴페인은 효모 찌꺼기와의 오랜 접촉으로 풍성함을 얻어요.', example_en_4 = 'The winemaker left the wine on its lees for 18 months.', example_ko_4 = '양조자는 18개월간 와인을 효모 찌꺼기 위에 두었어요.', example_en_5 = 'Lees stirring, called bâtonnage, creates a richer texture.', example_ko_5 = '바토나주라는 효모 찌꺼기 젓기는 더 풍부한 질감을 만들어요.' WHERE id = 'w_cafe_C2_14';
UPDATE words SET example_en_2 = 'A refractometer measures brix in the field.', example_ko_2 = '굴절계로 현장에서 브릭스를 측정해요.', example_en_3 = 'Brix tells winemakers the sugar level of the grapes.', example_ko_3 = '브릭스는 양조자에게 포도의 당도 수준을 알려줘요.', example_en_4 = 'Harvesting at the right brix is crucial for balance.', example_ko_4 = '적절한 브릭스에서 수확하는 게 균형을 위해 중요해요.', example_en_5 = 'The brix reading was 24 — perfect for late harvest wine.', example_ko_5 = '브릭스 측정값이 24였어요. 레이트 하베스트 와인에 완벽해요.' WHERE id = 'w_cafe_C2_15';
UPDATE words SET example_en_2 = 'Elevated volatile acidity can make wine smell like vinegar.', example_ko_2 = '높은 휘발성 산도는 와인이 식초 냄새가 나게 할 수 있어요.', example_en_3 = 'A small amount of volatile acidity adds complexity.', example_ko_3 = '소량의 휘발성 산도는 복잡성을 더해요.', example_en_4 = 'Controlling volatile acidity is a key winemaking challenge.', example_ko_4 = '휘발성 산도를 조절하는 것이 양조의 주요 과제예요.', example_en_5 = 'The panel noted slightly elevated volatile acidity.', example_ko_5 = '패널은 약간 높은 휘발성 산도를 기록했어요.' WHERE id = 'w_cafe_C2_16';
UPDATE words SET example_en_2 = 'Biodynamic farming follows lunar planting calendars.', example_ko_2 = '바이오다이나믹 농업은 달 파종 달력을 따라요.', example_en_3 = 'Biodynamic vineyards avoid synthetic chemicals.', example_ko_3 = '바이오다이나믹 포도밭은 합성 화학물질을 피해요.', example_en_4 = 'Biodynamic wines are said to express terroir more clearly.', example_ko_4 = '바이오다이나믹 와인은 테루아를 더 명확하게 표현한다고 해요.', example_en_5 = 'She converted her vineyard to fully biodynamic farming.', example_ko_5 = '그녀는 포도밭을 완전 바이오다이나믹 농업으로 전환했어요.' WHERE id = 'w_cafe_C2_17';
UPDATE words SET example_en_2 = 'Remuage gradually tilts the bottle to collect sediment.', example_ko_2 = '르뮈아주는 침전물을 모으기 위해 병을 점차 기울여요.', example_en_3 = 'Modern gyropalettes automate the remuage process.', example_ko_3 = '현대의 자이로팔레트는 르뮈아주 과정을 자동화해요.', example_en_4 = 'Traditional remuage was done entirely by hand.', example_ko_4 = '전통적인 르뮈아주는 전부 손으로 했어요.', example_en_5 = 'Remuage is critical to producing clear sparkling wine.', example_ko_5 = '르뮈아주는 맑은 스파클링 와인 생산에 필수적이에요.' WHERE id = 'w_cafe_C2_18';
UPDATE words SET example_en_2 = 'Disgorgement removes the frozen plug of sediment from Champagne.', example_ko_2 = '데고르주망은 샴페인에서 얼어붙은 침전물 덩어리를 제거해요.', example_en_3 = 'The disgorgement date tells you how fresh the wine is.', example_ko_3 = '데고르주망 날짜는 와인이 얼마나 신선한지 알려줘요.', example_en_4 = 'Disgorgement is followed by adding the dosage.', example_ko_4 = '데고르주망 후에 도사주를 첨가해요.', example_en_5 = 'Late disgorgement wines have more developed flavor.', example_ko_5 = '늦은 데고르주망 와인은 더 발전된 풍미를 가져요.' WHERE id = 'w_cafe_C2_19';
UPDATE words SET example_en_2 = 'Micro-oxygenation mimics slow oxygen exposure in barrels.', example_ko_2 = '마이크로산소 주입법은 배럴에서의 느린 산소 노출을 모방해요.', example_en_3 = 'Micro-oxygenation softens tannins in young red wines.', example_ko_3 = '마이크로산소 주입법은 어린 레드 와인의 타닌을 부드럽게 해요.', example_en_4 = 'Some winemakers use micro-oxygenation instead of oak.', example_ko_4 = '일부 양조자는 오크 대신 마이크로산소 주입법을 사용해요.', example_en_5 = 'Controlled micro-oxygenation improves wine stability.', example_ko_5 = '조절된 마이크로산소 주입법은 와인 안정성을 개선해요.' WHERE id = 'w_cafe_C2_20';
UPDATE words SET example_en_2 = 'The élevage in new oak contributed vanilla and spice.', example_ko_2 = '새 오크에서의 엘르바주가 바닐라와 스파이스를 더해줬어요.', example_en_3 = 'The winemaker chose an élevage of 18 months in barrel.', example_ko_3 = '양조자는 배럴에서 18개월 엘르바주를 선택했어요.', example_en_4 = 'Élevage decisions define the final character of the wine.', example_ko_4 = '엘르바주 결정이 와인의 최종 특성을 결정해요.', example_en_5 = 'Concrete tank élevage preserves more fresh fruit character.', example_ko_5 = '콘크리트 탱크 엘르바주는 신선한 과일 특성을 더 잘 보존해요.' WHERE id = 'w_cafe_C2_21';
UPDATE words SET example_en_2 = 'The mouthfeel of this aged wine was silky and round.', example_ko_2 = '이 숙성 와인의 입안 느낌이 실키하고 둥글었어요.', example_en_3 = 'Mouthfeel in wine ranges from thin to full-bodied.', example_ko_3 = '와인의 마우스필은 가벼운 것부터 풀바디까지 다양해요.', example_en_4 = 'Glycerol contributes to a smooth, oily mouthfeel.', example_ko_4 = '글리세롤이 부드럽고 오일리한 마우스필에 기여해요.', example_en_5 = 'Tannins and alcohol both influence mouthfeel.', example_ko_5 = '타닌과 알코올 모두 마우스필에 영향을 줘요.' WHERE id = 'w_cafe_C2_22';
UPDATE words SET example_en_2 = 'Phenolics give structure, color, and bitterness to wine.', example_ko_2 = '페놀류는 와인에 구조, 색상, 쓴맛을 줘요.', example_en_3 = 'The phenolics were well-integrated in this reserve.', example_ko_3 = '이 리저브에서는 페놀류가 잘 통합되어 있었어요.', example_en_4 = 'Extraction of phenolics during fermentation requires careful management.', example_ko_4 = '발효 중 페놀류 추출은 세심한 관리가 필요해요.', example_en_5 = 'Oak aging polymerizes phenolics, making them softer.', example_ko_5 = '오크 숙성은 페놀류를 중합시켜 더 부드럽게 만들어요.' WHERE id = 'w_cafe_C2_23';
UPDATE words SET example_en_2 = 'Polyphenols in red wine are associated with health benefits.', example_ko_2 = '레드 와인의 폴리페놀은 건강상 이점과 관련이 있어요.', example_en_3 = 'The dark color indicates high levels of polyphenols.', example_ko_3 = '짙은 색상은 높은 폴리페놀 수준을 나타내요.', example_en_4 = 'Grape skins are a major source of polyphenols.', example_ko_4 = '포도 껍질은 폴리페놀의 주요 원천이에요.', example_en_5 = 'Processing methods affect polyphenol retention in olive oil.', example_ko_5 = '가공 방법이 올리브 오일의 폴리페놀 보존에 영향을 줘요.' WHERE id = 'w_cafe_C2_24';
UPDATE words SET example_en_2 = 'Extraction of color and tannin requires careful temperature control.', example_ko_2 = '색상과 타닌 추출은 세심한 온도 조절이 필요해요.', example_en_3 = 'Over-extraction can make a wine harsh and bitter.', example_ko_3 = '과도한 추출은 와인을 거칠고 쓴맛이 나게 할 수 있어요.', example_en_4 = 'Gentle extraction preserves freshness and aromatic lift.', example_ko_4 = '부드러운 추출은 신선함과 향기로운 리프트를 보존해요.', example_en_5 = 'The winemaker preferred shorter extraction for elegance.', example_ko_5 = '양조자는 우아함을 위해 짧은 추출을 선호했어요.' WHERE id = 'w_cafe_C2_25';
UPDATE words SET example_en_2 = 'Terpenes contribute floral and citrus aromas to wine.', example_ko_2 = '테르펜이 와인에 꽃향기와 시트러스 향을 기여해요.', example_en_3 = 'Riesling is particularly rich in terpenes.', example_ko_3 = '리슬링은 테르펜이 특히 풍부해요.', example_en_4 = 'Terpenes are also found in hops, cannabis, and herbs.', example_ko_4 = '테르펜은 홉, 대마초, 허브에서도 발견돼요.', example_en_5 = 'The distinctive aroma of this wine is due to its terpene profile.', example_ko_5 = '이 와인의 독특한 향기는 테르펜 프로파일 때문이에요.' WHERE id = 'w_cafe_C2_26';
UPDATE words SET example_en_2 = 'Oxidative aging develops complex nutty and dried fruit notes.', example_ko_2 = '산화 숙성은 복잡한 견과류와 말린 과일 향을 개발해요.', example_en_3 = 'Sherry undergoes deliberate oxidative aging.', example_ko_3 = '셰리주는 의도적인 산화 숙성을 거쳐요.', example_en_4 = 'Oxidative aging in old barrels adds texture and depth.', example_ko_4 = '오래된 배럴에서의 산화 숙성은 질감과 깊이를 더해요.', example_en_5 = 'Some winemakers embrace oxidative aging for distinctiveness.', example_ko_5 = '일부 양조자는 독특함을 위해 산화 숙성을 받아들여요.' WHERE id = 'w_cafe_C2_27';
UPDATE words SET example_en_2 = 'The encépagement of this blend is 70% Merlot.', example_ko_2 = '이 블렌드의 포도 품종 비율은 메를로 70%예요.', example_en_3 = 'Encépagement decisions shape the wine''s style significantly.', example_ko_3 = '포도 품종 비율 결정이 와인의 스타일에 크게 영향을 줘요.', example_en_4 = 'Regulations in some appellations prescribe the encépagement.', example_ko_4 = '일부 원산지 명칭 보호에서는 포도 품종 비율을 규정해요.', example_en_5 = 'Changing the encépagement changed the entire character of the wine.', example_ko_5 = '포도 품종 비율을 바꾸자 와인의 전체 특성이 달라졌어요.' WHERE id = 'w_cafe_C2_28';
UPDATE words SET example_en_2 = 'Extended autolysis adds toasty, biscuit-like notes.', example_ko_2 = '연장된 자가 분해는 구수하고 비스킷 같은 향을 더해요.', example_en_3 = 'Autolysis contributes to the creaminess of Champagne.', example_ko_3 = '자가 분해가 샴페인의 크리미함에 기여해요.', example_en_4 = 'Longer autolysis contact creates more complex sparkling wines.', example_ko_4 = '더 긴 자가 분해 접촉은 더 복잡한 스파클링 와인을 만들어요.', example_en_5 = 'The yeasty complexity here is the result of autolysis.', example_ko_5 = '여기 이스트 같은 복잡성은 자가 분해의 결과예요.' WHERE id = 'w_cafe_C2_29';
UPDATE words SET example_en_2 = 'The final assemblage defines the house style.', example_ko_2 = '최종 아상블라주가 하우스 스타일을 정의해요.', example_en_3 = 'Assemblage is the art of blending different lots into a whole.', example_ko_3 = '아상블라주는 다양한 로트를 전체로 블렌딩하는 예술이에요.', example_en_4 = 'The chef de cave oversees the assemblage each year.', example_ko_4 = '셀러 마스터가 매년 아상블라주를 감독해요.', example_en_5 = 'The assemblage this year includes more Pinot Noir for freshness.', example_ko_5 = '올해 아상블라주는 신선함을 위해 피노 누아가 더 많이 포함돼요.' WHERE id = 'w_cafe_C2_30';
UPDATE words SET example_en_2 = 'Volatile esters contribute fruity aromas to young wines.', example_ko_2 = '휘발성 에스테르가 어린 와인에 과일향을 기여해요.', example_en_3 = 'Yeast strains influence the volatile ester profile.', example_ko_3 = '효모 균주가 휘발성 에스테르 프로파일에 영향을 줘요.', example_en_4 = 'Volatile esters can be lost if the wine is kept too warm.', example_ko_4 = '와인이 너무 따뜻하면 휘발성 에스테르가 사라질 수 있어요.', example_en_5 = 'The isoamyl acetate gave the wine a banana-like aroma.', example_ko_5 = '이소아밀 아세테이트가 와인에 바나나 같은 향을 줬어요.' WHERE id = 'w_cafe_C2_31';
UPDATE words SET example_en_2 = 'A premier cru vineyard occupies a particularly favored cru.', example_ko_2 = '프리미어 크뤼 포도밭은 특히 뛰어난 크뤼를 차지해요.', example_en_3 = 'Each cru expresses a unique sense of place.', example_ko_3 = '각 크뤼는 독특한 장소성을 표현해요.', example_en_4 = 'The cru system in Burgundy classifies vineyards by quality.', example_ko_4 = '부르고뉴의 크뤼 시스템은 포도밭을 품질로 분류해요.', example_en_5 = 'Wines from a grand cru command premium prices.', example_ko_5 = '그랑 크뤼 와인은 프리미엄 가격을 받아요.' WHERE id = 'w_cafe_C2_32';
UPDATE words SET example_en_2 = 'A négociant buys grapes or wine and sells under their own label.', example_ko_2 = '네고시앙은 포도나 와인을 구매해 자체 라벨로 판매해요.', example_en_3 = 'Large négociants dominate the Burgundy market.', example_ko_3 = '대형 네고시앙이 부르고뉴 시장을 장악해요.', example_en_4 = 'The négociant model allows scale without owning vineyards.', example_ko_4 = '네고시앙 모델은 포도밭 없이도 규모를 키울 수 있게 해요.', example_en_5 = 'Some négociants also own estate vineyards.', example_ko_5 = '일부 네고시앙은 포도밭도 직접 소유해요.' WHERE id = 'w_cafe_C2_33';
UPDATE words SET example_en_2 = 'Bâtonnage was performed weekly throughout the aging period.', example_ko_2 = '숙성 기간 동안 매주 바토나주를 했어요.', example_en_3 = 'Regular bâtonnage adds richness and a creamy texture.', example_ko_3 = '정기적인 바토나주는 풍성함과 크리미한 질감을 더해요.', example_en_4 = 'Bâtonnage must be done gently to avoid oxidation.', example_ko_4 = '바토나주는 산화를 피하기 위해 조심스럽게 해야 해요.', example_en_5 = 'She stopped bâtonnage at six months to preserve freshness.', example_ko_5 = '신선함을 보존하기 위해 6개월에 바토나주를 멈췄어요.' WHERE id = 'w_cafe_C2_34';
