UPDATE words SET example_en_2 = 'The diaspora community maintains strong cultural ties.', example_ko_2 = '이산 공동체는 강한 문화적 유대를 유지해요.', example_en_3 = 'She explored the Korean diaspora in her doctoral research.', example_ko_3 = '그녀는 박사 연구에서 코리안 디아스포라를 탐구했어요.', example_en_4 = 'The festival celebrates the creativity of the diaspora.', example_ko_4 = '그 축제는 이산 사람들의 창의성을 기려요.', example_en_5 = 'Diaspora literature often grapples with questions of belonging.', example_ko_5 = '디아스포라 문학은 종종 소속감의 문제를 다뤄요.' WHERE id = 'w_travel_C1_09';
