UPDATE words SET example_en_2 = 'Her peregrination across the Silk Road took eighteen months.', example_ko_2 = '실크로드 전역을 여행하는 데 18개월이 걸렸어요.', example_en_3 = 'The philosopher documented his peregrination in careful journals.', example_ko_3 = '그 철학자는 자신의 방랑을 상세한 일기로 기록했어요.', example_en_4 = 'His peregrination left him enriched but rootless.', example_ko_4 = '그의 방랑은 그를 풍요롭게 했지만 뿌리 없이 만들었어요.', example_en_5 = 'Such a peregrination demands both courage and humility.', example_ko_5 = '그러한 방랑에는 용기와 겸손이 모두 필요해요.' WHERE id = 'w_travel_C2_01';
UPDATE words SET example_en_2 = 'Ferdinand Magellan was the first to circumnavigate the Earth.', example_ko_2 = '페르디난드 마젤란은 지구를 최초로 일주한 사람이에요.', example_en_3 = 'She set out alone to circumnavigate the Mediterranean.', example_ko_3 = '그녀는 홀로 지중해를 일주하기 위해 출발했어요.', example_en_4 = 'To circumnavigate the globe by sail takes immense preparation.', example_ko_4 = '범선으로 지구를 일주하려면 엄청난 준비가 필요해요.', example_en_5 = 'The robot was programmed to circumnavigate the obstacle course.', example_ko_5 = '로봇은 장애물 코스를 일주하도록 프로그래밍됐어요.' WHERE id = 'w_travel_C2_02';
UPDATE words SET example_en_2 = 'The festival attracted a cosmopolitan crowd from around the globe.', example_ko_2 = '그 축제는 전 세계에서 온 세계적인 인파를 끌어모았어요.', example_en_3 = 'She developed a cosmopolitan sensibility through her years abroad.', example_ko_3 = '해외에서의 생활을 통해 세계적인 감각을 키웠어요.', example_en_4 = 'The city''s cosmopolitan character sets it apart from its neighbours.', example_ko_4 = '그 도시의 세계적인 특성이 인근 도시들과 차별화해요.', example_en_5 = 'A truly cosmopolitan perspective challenges parochial thinking.', example_ko_5 = '진정한 세계적 시각은 편협한 사고에 도전해요.' WHERE id = 'w_travel_C2_03';
UPDATE words SET example_en_2 = 'As an expatriate, he struggled with a divided sense of identity.', example_ko_2 = '해외 거주자로서 그는 분열된 정체성 감각으로 어려움을 겪었어요.', example_en_3 = 'The expatriate community gathered to celebrate their shared culture.', example_ko_3 = '해외 거주자 커뮤니티가 공유된 문화를 기리기 위해 모였어요.', example_en_4 = 'Expatriate life can be both liberating and profoundly isolating.', example_ko_4 = '해외 거주자 생활은 해방적이면서도 깊이 고립감을 줄 수 있어요.', example_en_5 = 'She wrote about the expatriate condition with unflinching honesty.', example_ko_5 = '그녀는 해외 거주자의 상황에 대해 흔들림 없는 솔직함으로 썼어요.' WHERE id = 'w_travel_C2_04';
UPDATE words SET example_en_2 = 'Transhumance routes are still used in parts of Europe.', example_ko_2 = '이목 경로는 아직도 유럽 일부 지역에서 사용되고 있어요.', example_en_3 = 'The practice of transhumance has shaped the Alpine landscape.', example_ko_3 = '이목 관행이 알프스 풍경을 형성했어요.', example_en_4 = 'Researchers study transhumance to understand ancient migration patterns.', example_ko_4 = '연구자들은 고대 이동 패턴을 이해하기 위해 이목을 연구해요.', example_en_5 = 'Transhumance is a form of seasonal migration tied to grazing.', example_ko_5 = '이목은 방목과 연결된 계절적 이동의 한 형태예요.' WHERE id = 'w_travel_C2_05';
UPDATE words SET example_en_2 = 'The study explored nomadism as an adaptive ecological strategy.', example_ko_2 = '그 연구는 유목주의를 생태적 적응 전략으로 탐구했어요.', example_en_3 = 'Digital nomadism has redefined what it means to have a home.', example_ko_3 = '디지털 유목주의가 집이 무엇인지에 대한 의미를 재정의했어요.', example_en_4 = 'Nomadism challenges the concept of fixed national identity.', example_ko_4 = '유목주의는 고정된 국가 정체성의 개념에 도전해요.', example_en_5 = 'Cultural nomadism thrives in cities with high migrant populations.', example_ko_5 = '문화적 유목주의는 이민자 인구가 많은 도시에서 번성해요.' WHERE id = 'w_travel_C2_06';
UPDATE words SET example_en_2 = 'Her xenophilia led her to dedicate her career to cross-cultural work.', example_ko_2 = '외국 문화 사랑이 그녀를 문화 간 교류 직업으로 이끌었어요.', example_en_3 = 'Xenophilia, not xenophobia, should define our response to migration.', example_ko_3 = '이민에 대한 우리의 반응은 외국인 혐오가 아닌 외국 문화 사랑이어야 해요.', example_en_4 = 'His xenophilia was evident in his diverse circle of friends.', example_ko_4 = '그의 다양한 친구 범위에서 외국 문화 사랑이 분명히 드러났어요.', example_en_5 = 'Xenophilia can be cultivated through education and exposure.', example_ko_5 = '외국 문화 사랑은 교육과 경험을 통해 키울 수 있어요.' WHERE id = 'w_travel_C2_07';
UPDATE words SET example_en_2 = 'The wanderer in the poem is an allegory for spiritual seeking.', example_ko_2 = '시 속의 방랑자는 정신적 추구에 대한 우화예요.', example_en_3 = 'She described herself as a wanderer caught between worlds.', example_ko_3 = '그녀는 자신을 세계 사이에 끼인 방랑자라고 묘사했어요.', example_en_4 = 'The eternal wanderer archetype appears across many cultures.', example_ko_4 = '영원한 방랑자 원형은 많은 문화에 걸쳐 나타나요.', example_en_5 = 'Every wanderer eventually must confront the concept of belonging.', example_ko_5 = '모든 방랑자는 결국 소속감의 개념과 마주해야 해요.' WHERE id = 'w_travel_C2_08';
UPDATE words SET example_en_2 = 'The odyssey of the refugees was documented by journalists.', example_ko_2 = '난민들의 오디세이가 언론에 의해 기록됐어요.', example_en_3 = 'The startup''s odyssey from idea to IPO took seven years.', example_ko_3 = '그 스타트업의 아이디어에서 IPO까지의 여정은 7년이 걸렸어요.', example_en_4 = 'The odyssey of grief took her across three continents.', example_ko_4 = '슬픔의 여정이 그녀를 세 대륙에 걸쳐 이끌었어요.', example_en_5 = 'Every great odyssey transforms the traveller irreversibly.', example_ko_5 = '모든 위대한 오디세이는 여행자를 돌이킬 수 없이 변화시켜요.' WHERE id = 'w_travel_C2_09';
UPDATE words SET example_en_2 = 'The cartography of empire reflected ideological assumptions.', example_ko_2 = '제국의 지도학은 이념적 가정들을 반영했어요.', example_en_3 = 'Early cartography was as much art as science.', example_ko_3 = '초기 지도학은 과학인 동시에 예술이었어요.', example_en_4 = 'Digital cartography has democratised access to spatial data.', example_ko_4 = '디지털 지도학이 공간 데이터에 대한 접근을 민주화했어요.', example_en_5 = 'Her thesis examined the cartography of colonial imagination.', example_ko_5 = '그녀의 논문은 식민지 상상의 지도학을 검토했어요.' WHERE id = 'w_travel_C2_10';
UPDATE words SET example_en_2 = 'The terroir of Burgundy cannot be replicated elsewhere.', example_ko_2 = '부르고뉴의 테루아르는 다른 곳에서 복제할 수 없어요.', example_en_3 = 'She could taste the terroir in every sip of the wine.', example_ko_3 = '그녀는 와인 한 모금 한 모금에서 테루아르를 느낄 수 있었어요.', example_en_4 = 'Terroir is not only about soil — it includes climate and culture.', example_ko_4 = '테루아르는 토양만의 문제가 아니에요. 기후와 문화도 포함해요.', example_en_5 = 'The chef was passionate about terroir-driven cooking.', example_ko_5 = '그 셰프는 테루아르 기반 요리에 열정적이었어요.' WHERE id = 'w_travel_C2_11';
UPDATE words SET example_en_2 = 'As a polyglot, she navigated every city with ease.', example_ko_2 = '다국어 구사자로서 그녀는 어느 도시에서나 어렵지 않게 돌아다녔어요.', example_en_3 = 'The polyglot traveller can access a far deeper experience of a culture.', example_ko_3 = '다국어를 구사하는 여행자는 문화를 훨씬 더 깊이 경험할 수 있어요.', example_en_4 = 'He was a self-taught polyglot who spoke eight languages.', example_ko_4 = '그는 8개 언어를 구사하는 독학 다국어 구사자였어요.', example_en_5 = 'Being a polyglot opens doors that money cannot.', example_ko_5 = '다국어 구사자가 되면 돈으로는 열 수 없는 문이 열려요.' WHERE id = 'w_travel_C2_12';
UPDATE words SET example_en_2 = 'The airport is a space of liminality — neither here nor there.', example_ko_2 = '공항은 여기도 저기도 아닌 경계적 공간이에요.', example_en_3 = 'Long-term travel induces a lasting sense of liminality.', example_ko_3 = '장기 여행은 지속적인 경계의 감각을 불러일으켜요.', example_en_4 = 'The concept of liminality is central to rites of passage.', example_ko_4 = '경계성 개념은 통과 의례의 핵심이에요.', example_en_5 = 'She embraced the liminality of border zones as a creative space.', example_ko_5 = '그녀는 국경 지역의 경계성을 창의적 공간으로 받아들였어요.' WHERE id = 'w_travel_C2_13';
UPDATE words SET example_en_2 = 'Globalisation has started to deterritorialise many cultural practices.', example_ko_2 = '세계화가 많은 문화적 관행을 탈영토화하기 시작했어요.', example_en_3 = 'Migration tends to deterritorialise identities over generations.', example_ko_3 = '이주는 세대를 거치면서 정체성을 탈영토화하는 경향이 있어요.', example_en_4 = 'The internet has helped deterritorialise diaspora communities.', example_ko_4 = '인터넷이 이산 커뮤니티를 탈영토화하는 데 도움을 줬어요.', example_en_5 = 'To deterritorialise is to loosen the bond between culture and place.', example_ko_5 = '탈영토화는 문화와 장소 사이의 유대를 느슨하게 만드는 거예요.' WHERE id = 'w_travel_C2_14';
UPDATE words SET example_en_2 = 'Wayfinding has become a discipline in environmental design.', example_ko_2 = '길 찾기는 환경 디자인의 한 분야가 됐어요.', example_en_3 = 'Indigenous peoples developed sophisticated wayfinding techniques.', example_ko_3 = '원주민들은 정교한 길 찾기 기술을 발전시켰어요.', example_en_4 = 'Airport wayfinding design directly affects passenger stress levels.', example_ko_4 = '공항의 길 안내 디자인이 승객의 스트레스 수준에 직접 영향을 미쳐요.', example_en_5 = 'The app uses augmented reality for real-time wayfinding.', example_ko_5 = '그 앱은 실시간 길 찾기를 위해 증강 현실을 사용해요.' WHERE id = 'w_travel_C2_15';
UPDATE words SET example_en_2 = 'His peripatetic research methods shaped groundbreaking work.', example_ko_2 = '그의 소요 연구 방법이 획기적인 작업을 만들었어요.', example_en_3 = 'The peripatetic lifestyle suited her restless intellectual curiosity.', example_ko_3 = '소요적 생활 방식이 그녀의 불안한 지적 호기심에 잘 맞았어요.', example_en_4 = 'Peripatetic teaching was practiced in ancient Athens.', example_ko_4 = '소요파 교육은 고대 아테네에서 행해졌어요.', example_en_5 = 'She adopted a peripatetic approach to her journalism.', example_ko_5 = '그녀는 저널리즘에 소요파적 접근 방식을 채택했어요.' WHERE id = 'w_travel_C2_16';
UPDATE words SET example_en_2 = 'Deleuze used the rhizome as a metaphor for non-linear thought.', example_ko_2 = '들뢰즈는 리좀을 비선형적 사고의 은유로 사용했어요.', example_en_3 = 'A rhizome spreads without a centre or hierarchy.', example_ko_3 = '리좀은 중심이나 계층 없이 퍼져나가요.', example_en_4 = 'Her travel writing adopted a rhizome structure — no beginning, no end.', example_ko_4 = '그녀의 여행 글쓰기는 시작도 끝도 없는 리좀 구조를 채택했어요.', example_en_5 = 'The rhizome model challenges the idea of a fixed narrative journey.', example_ko_5 = '리좀 모델은 고정된 서사적 여정의 개념에 도전해요.' WHERE id = 'w_travel_C2_17';
UPDATE words SET example_en_2 = 'Her research examined place attachment among long-term migrants.', example_ko_2 = '그녀의 연구는 장기 이주민들 사이의 장소 애착을 조사했어요.', example_en_3 = 'Strong place attachment can make leaving a location feel like loss.', example_ko_3 = '강한 장소 애착은 어떤 장소를 떠나는 것을 상실처럼 느끼게 해요.', example_en_4 = 'Place attachment shapes how we remember the places we have travelled.', example_ko_4 = '장소 애착은 우리가 여행한 장소를 기억하는 방식을 형성해요.', example_en_5 = 'Place attachment is disrupted by forced displacement.', example_ko_5 = '강제 이주는 장소 애착을 파괴해요.' WHERE id = 'w_travel_C2_18';
UPDATE words SET example_en_2 = 'She used ethnography to document nomadic communities.', example_ko_2 = '그녀는 유목 공동체를 기록하기 위해 민족지학을 사용했어요.', example_en_3 = 'Ethnography requires extended engagement with a community.', example_ko_3 = '민족지학은 커뮤니티와의 지속적인 참여가 필요해요.', example_en_4 = 'The ethnography of pilgrimage routes is a growing field.', example_ko_4 = '순례 경로의 민족지학은 성장하는 분야예요.', example_en_5 = 'Careful ethnography reveals what tourism statistics cannot.', example_ko_5 = '세심한 민족지학은 관광 통계가 드러낼 수 없는 것을 보여줘요.' WHERE id = 'w_travel_C2_19';
UPDATE words SET example_en_2 = 'Topophilia describes the deep bond between people and place.', example_ko_2 = '토포필리아는 사람과 장소 사이의 깊은 유대감을 묘사해요.', example_en_3 = 'Her topophilia for the Scottish Highlands was evident in her writing.', example_ko_3 = '스코틀랜드 고지대에 대한 그녀의 토포필리아가 글에서 뚜렷하게 드러났어요.', example_en_4 = 'Topophilia can make it almost impossible to leave a beloved place.', example_ko_4 = '토포필리아는 사랑하는 장소를 떠나는 것을 거의 불가능하게 만들 수 있어요.', example_en_5 = 'The geographer Yi-Fu Tuan introduced topophilia as a concept.', example_ko_5 = '지리학자 이-푸 투안이 토포필리아를 개념으로 도입했어요.' WHERE id = 'w_travel_C2_20';
UPDATE words SET example_en_2 = 'The sublunary world, with all its impermanence, is where travel exists.', example_ko_2 = '모든 무상함을 가진 지상 세계가 바로 여행이 존재하는 곳이에요.', example_en_3 = 'He sought experiences that transcended the sublunary and the mundane.', example_ko_3 = '그는 지상적이고 평범한 것을 초월하는 경험을 추구했어요.', example_en_4 = 'Philosophers once contrasted the sublunary with the divine realm.', example_ko_4 = '철학자들은 한때 지상 세계를 신성한 영역과 대비시켰어요.', example_en_5 = 'The poet described travel as the sublunary path to transcendence.', example_ko_5 = '시인은 여행을 지상적 초월로 가는 길로 묘사했어요.' WHERE id = 'w_travel_C2_21';
UPDATE words SET example_en_2 = 'The polyphonic festival featured voices from thirty nations.', example_ko_2 = '다성적 축제에는 30개국의 목소리가 담겼어요.', example_en_3 = 'Travel literature at its best is polyphonic — no single truth.', example_ko_3 = '최고의 여행 문학은 다성적이에요. 하나의 진실만 있지 않아요.', example_en_4 = 'The anthology presented a polyphonic account of the region.', example_ko_4 = '그 선집은 그 지역에 대한 다성적 설명을 제시했어요.', example_en_5 = 'A polyphonic approach to storytelling honours multiple perspectives.', example_ko_5 = '다성적 이야기 방식은 다양한 관점을 존중해요.' WHERE id = 'w_travel_C2_22';
UPDATE words SET example_en_2 = 'The autochthonous people''s connection to the land is ancient.', example_ko_2 = '그 토착민들과 땅의 연결은 고대에서 비롯돼요.', example_en_3 = 'Autochthonous knowledge systems offer vital insights into the environment.', example_ko_3 = '토착 지식 체계는 환경에 대한 중요한 통찰을 제공해요.', example_en_4 = 'Tourism can threaten autochthonous cultures if not managed carefully.', example_ko_4 = '잘 관리되지 않으면 관광이 토착 문화를 위협할 수 있어요.', example_en_5 = 'The documentary centred on autochthonous land rights.', example_ko_5 = '그 다큐멘터리는 토착민 토지 권리에 초점을 맞췄어요.' WHERE id = 'w_travel_C2_23';
UPDATE words SET example_en_2 = 'His exilic writing captures a longing for the homeland.', example_ko_2 = '그의 망명 글쓰기는 고향에 대한 그리움을 담아내요.', example_en_3 = 'The exilic condition shapes identity in complex ways.', example_ko_3 = '망명 상태는 정체성을 복잡한 방식으로 형성해요.', example_en_4 = 'Exilic literature has produced some of the most powerful novels.', example_ko_4 = '망명 문학은 가장 강렬한 소설들을 탄생시켰어요.', example_en_5 = 'She explored the exilic experience in her acclaimed memoir.', example_ko_5 = '그녀는 극찬받은 회고록에서 망명 경험을 탐구했어요.' WHERE id = 'w_travel_C2_24';
UPDATE words SET example_en_2 = 'The transit zone of an airport is a kind of heterotopia.', example_ko_2 = '공항 환승 구역은 일종의 헤테로토피아예요.', example_en_3 = 'Foucault defined the heterotopia as a space outside normal social order.', example_ko_3 = '푸코는 헤테로토피아를 정상적 사회 질서 밖의 공간으로 정의했어요.', example_en_4 = 'Theme parks function as heterotopias — spaces of escape and fantasy.', example_ko_4 = '테마파크는 탈출과 환상의 공간으로서 헤테로토피아 역할을 해요.', example_en_5 = 'The ship was both transport and heterotopia during the long voyage.', example_ko_5 = '배는 긴 항해 동안 교통수단이자 헤테로토피아였어요.' WHERE id = 'w_travel_C2_25';
UPDATE words SET example_en_2 = 'Psychogeography invites us to experience cities in unexpected ways.', example_ko_2 = '심리지리학은 우리가 도시를 예상치 못한 방식으로 경험하도록 초대해요.', example_en_3 = 'The Situationists developed psychogeography as an act of resistance.', example_ko_3 = '상황주의자들은 저항의 행위로서 심리지리학을 발전시켰어요.', example_en_4 = 'He walked the city in a psychogeographic drift with no map.', example_ko_4 = '그는 지도 없이 심리지리학적 표류 방식으로 도시를 걸었어요.', example_en_5 = 'Psychogeography asks: what does this place make you feel?', example_ko_5 = '심리지리학은 묻습니다. 이 장소가 당신에게 무엇을 느끼게 하는가요?' WHERE id = 'w_travel_C2_26';
UPDATE words SET example_en_2 = 'The flaneur moves through the city without purpose or destination.', example_ko_2 = '플라뇌르는 목적이나 목적지 없이 도시를 이동해요.', example_en_3 = 'She adopted the flaneur''s gaze as a research methodology.', example_ko_3 = '그녀는 연구 방법론으로서 플라뇌르의 시선을 채택했어요.', example_en_4 = 'Baudelaire immortalised the flaneur as an icon of modernity.', example_ko_4 = '보들레르는 플라뇌르를 근대성의 아이콘으로 불멸화했어요.', example_en_5 = 'The flaneur belongs to no place and yet belongs to every place.', example_ko_5 = '플라뇌르는 어느 곳에도 속하지 않으면서도 모든 곳에 속해요.' WHERE id = 'w_travel_C2_27';
UPDATE words SET example_en_2 = 'Xenophobia in border policy has real human costs.', example_ko_2 = '국경 정책에서의 외국인 혐오는 실질적인 인적 비용을 야기해요.', example_en_3 = 'Travel is one of the most effective antidotes to xenophobia.', example_ko_3 = '여행은 외국인 혐오에 대한 가장 효과적인 해독제 중 하나예요.', example_en_4 = 'Xenophobia can manifest in subtle forms of exclusion.', example_ko_4 = '외국인 혐오는 미묘한 배제의 형태로 나타날 수 있어요.', example_en_5 = 'She campaigned against xenophobia through storytelling and travel writing.', example_ko_5 = '그녀는 이야기 나누기와 여행 글쓰기를 통해 외국인 혐오에 맞서 캠페인을 벌였어요.' WHERE id = 'w_travel_C2_28';
UPDATE words SET example_en_2 = 'The epistemic shift triggered by travel is often underestimated.', example_ko_2 = '여행에 의해 촉발되는 인식론적 변화는 종종 과소평가돼요.', example_en_3 = 'Her epistemic humility made her a better anthropologist.', example_ko_3 = '그녀의 인식론적 겸손이 그녀를 더 나은 인류학자로 만들었어요.', example_en_4 = 'Crossing cultures raises deep epistemic questions about truth.', example_ko_4 = '문화를 넘나들면 진실에 대한 깊은 인식론적 질문이 생겨요.', example_en_5 = 'Each journey adds an epistemic layer to how we interpret the world.', example_ko_5 = '여행을 할 때마다 세계를 해석하는 방식에 인식론적 층위가 더해져요.' WHERE id = 'w_travel_C2_29';
UPDATE words SET example_en_2 = 'Long-haul travel can induce apophenia — seeing patterns everywhere.', example_ko_2 = '장거리 여행은 어디에서나 패턴을 보는 아포페니아를 유발할 수 있어요.', example_en_3 = 'Jet-lagged and disoriented, she experienced vivid apophenia.', example_ko_3 = '시차와 방향 감각 상실로 그녀는 생생한 아포페니아를 경험했어요.', example_en_4 = 'Apophenia can make a foreign city feel strangely familiar.', example_ko_4 = '아포페니아는 낯선 도시를 이상하게 친숙하게 느끼게 할 수 있어요.', example_en_5 = 'The traveller''s apophenia connected disparate symbols into a coherent story.', example_ko_5 = '여행자의 아포페니아가 서로 다른 상징들을 하나의 일관된 이야기로 연결했어요.' WHERE id = 'w_travel_C2_30';
UPDATE words SET example_en_2 = 'Sonder struck him as he watched the crowded ferry terminal.', example_ko_2 = '붐비는 페리 터미널을 바라보다 문득 존재의 무게가 느껴졌어요.', example_en_3 = 'Travel amplifies sonder — every stranger has a whole life.', example_ko_3 = '여행은 타인 실감을 증폭시켜요. 모든 낯선 사람에게는 온전한 삶이 있어요.', example_en_4 = 'A moment of sonder in a busy airport changed how she saw strangers.', example_ko_4 = '붐비는 공항에서 타인을 실감하는 순간이 낯선 사람들을 보는 방식을 바꿨어요.', example_en_5 = 'Sonder is one of those feelings that travel uniquely cultivates.', example_ko_5 = '타인 실감은 여행이 특별하게 키워주는 감정 중 하나예요.' WHERE id = 'w_travel_C2_31';
UPDATE words SET example_en_2 = 'The abandoned shrine had a numinous, otherworldly quality.', example_ko_2 = '그 버려진 성지는 신성하고 초월적인 분위기를 풍겼어요.', example_en_3 = 'She felt a numinous presence at the top of the mountain.', example_ko_3 = '산 정상에서 신성한 존재감을 느꼈어요.', example_en_4 = 'The numinous atmosphere of ancient ruins defies description.', example_ko_4 = '고대 유적의 신성한 분위기는 말로 표현하기 어려워요.', example_en_5 = 'Travel at its most profound touches the numinous.', example_ko_5 = '가장 심오한 여행은 신성함에 닿아요.' WHERE id = 'w_travel_C2_32';
UPDATE words SET example_en_2 = 'Discussions of indigeneity are central to debates about cultural tourism.', example_ko_2 = '토착성에 대한 논의는 문화 관광 논쟁의 중심에 있어요.', example_en_3 = 'The festival was an assertion of indigenous indigeneity.', example_ko_3 = '그 축제는 원주민 토착성의 주장이었어요.', example_en_4 = 'Indigeneity complicates simplistic narratives of national identity.', example_ko_4 = '토착성은 국가 정체성에 대한 단순한 서사를 복잡하게 만들어요.', example_en_5 = 'Tourism must reckon with questions of indigeneity and consent.', example_ko_5 = '관광은 토착성과 동의의 문제와 씨름해야 해요.' WHERE id = 'w_travel_C2_33';
UPDATE words SET example_en_2 = 'Her cartophilia was evident in the maps that covered every wall.', example_ko_2 = '모든 벽을 덮은 지도에서 그녀의 지도 사랑이 드러났어요.', example_en_3 = 'Cartophilia drives collectors to seek out rare antique maps.', example_ko_3 = '지도 사랑이 수집가들을 희귀한 골동품 지도를 찾아다니게 해요.', example_en_4 = 'His cartophilia began with a world map hung above his childhood bed.', example_ko_4 = '그의 지도 사랑은 어린 시절 침대 위에 걸린 세계 지도에서 시작됐어요.', example_en_5 = 'Cartophilia and wanderlust often go hand in hand.', example_ko_5 = '지도 사랑과 방랑벽은 종종 함께해요.' WHERE id = 'w_travel_C2_34';
UPDATE words SET example_en_2 = 'Her weltanschauung was shaped by twenty years of travel.', example_ko_2 = '그녀의 세계관은 20년간의 여행을 통해 형성됐어요.', example_en_3 = 'A travel-informed weltanschauung resists easy categorisation.', example_ko_3 = '여행을 통해 형성된 세계관은 쉽게 분류하기 어려워요.', example_en_4 = 'Each culture we encounter adds nuance to our weltanschauung.', example_ko_4 = '우리가 접하는 각 문화는 세계관에 뉘앙스를 더해줘요.', example_en_5 = 'He argued that travel is the most powerful force shaping weltanschauung.', example_ko_5 = '그는 여행이 세계관을 형성하는 가장 강력한 힘이라고 주장했어요.' WHERE id = 'w_travel_C2_35';
