UPDATE words SET example_en_2 = 'Depression affects millions of people around the world.', example_ko_2 = '우울증은 전 세계 수백만 명에게 영향을 미쳐요.', example_en_3 = 'He sought help after struggling with depression for months.', example_ko_3 = '그는 수개월간 우울증을 앓은 후 도움을 구했어요.', example_en_4 = 'Therapy and medication are both effective for depression.', example_ko_4 = '치료와 약물 치료 모두 우울증에 효과적이에요.', example_en_5 = 'It is important to talk to someone if you feel depressed.', example_ko_5 = '우울함을 느끼면 누군가에게 말하는 것이 중요해요.' WHERE id = 'w_health_B1_15';
