UPDATE words SET example_en_2 = 'The sequelae of the stroke included partial paralysis.', example_ko_2 = '뇌졸중의 후유증에는 부분 마비가 포함됐어요.', example_en_3 = 'Long-term sequelae can persist years after the initial illness.', example_ko_3 = '장기 후유증은 초기 질환 수년 후에도 지속될 수 있어요.', example_en_4 = 'Patients were monitored for sequelae following the infection.', example_ko_4 = '환자들은 감염 후 후유증 여부를 모니터링받았어요.', example_en_5 = 'Cognitive sequelae were reported in some recovered patients.', example_ko_5 = '일부 회복 환자에서 인지적 후유증이 보고됐어요.' WHERE id = 'w_health_C2_06';
UPDATE words SET example_en_2 = 'Iatrogenic harm from unnecessary procedures is well documented.', example_ko_2 = '불필요한 시술로 인한 의인성 해는 충분히 문서화돼 있어요.', example_en_3 = 'She suffered an iatrogenic infection following the catheter insertion.', example_ko_3 = '그녀는 카테터 삽입 후 의인성 감염을 겪었어요.', example_en_4 = 'Reducing iatrogenic complications is a key goal of patient safety.', example_ko_4 = '의인성 합병증을 줄이는 것이 환자 안전의 핵심 목표예요.', example_en_5 = 'The iatrogenic injury was caused by an incorrect dosage.', example_ko_5 = '의인성 손상은 잘못된 투여량으로 인해 발생했어요.' WHERE id = 'w_health_C2_07';
UPDATE words SET example_en_2 = 'Portal vein thrombosis is a rare but serious condition.', example_ko_2 = '문맥 혈전증은 드물지만 심각한 질환이에요.', example_en_3 = 'He was given anticoagulants to dissolve the thrombosis.', example_ko_3 = '그는 혈전증을 용해시키기 위해 항응고제를 투여받았어요.', example_en_4 = 'Thrombosis in the cerebral veins can cause stroke-like symptoms.', example_ko_4 = '대뇌 정맥의 혈전증은 뇌졸중과 유사한 증상을 유발할 수 있어요.', example_en_5 = 'Risk factors for thrombosis include immobility and dehydration.', example_ko_5 = '혈전증의 위험 요인에는 부동과 탈수가 포함돼요.' WHERE id = 'w_health_C2_08';
UPDATE words SET example_en_2 = 'Severe anaphylaxis can lead to circulatory collapse.', example_ko_2 = '심각한 아나필락시스는 순환계 붕괴로 이어질 수 있어요.', example_en_3 = 'The patient was revived after a near-fatal anaphylaxis episode.', example_ko_3 = '환자는 거의 치명적인 아나필락시스 발작 후 소생됐어요.', example_en_4 = 'Anaphylaxis to contrast dye is a known surgical risk.', example_ko_4 = '조영제에 대한 아나필락시스는 알려진 수술 위험이에요.', example_en_5 = 'The team drilled on anaphylaxis protocols monthly.', example_ko_5 = '팀은 매달 아나필락시스 프로토콜을 훈련했어요.' WHERE id = 'w_health_C2_09';
UPDATE words SET example_en_2 = 'Carcinogenesis involves the transformation of normal cells into cancer cells.', example_ko_2 = '발암 과정은 정상 세포가 암세포로 변형되는 것을 포함해요.', example_en_3 = 'UV radiation is a known trigger for carcinogenesis in skin cells.', example_ko_3 = '자외선은 피부 세포에서 발암 과정을 촉발하는 것으로 알려져 있어요.', example_en_4 = 'Researchers study carcinogenesis to develop better cancer prevention strategies.', example_ko_4 = '연구자들은 더 나은 암 예방 전략을 개발하기 위해 발암 과정을 연구해요.', example_en_5 = 'Understanding carcinogenesis at the molecular level is key to new treatments.', example_ko_5 = '분자 수준에서 발암 과정을 이해하는 것이 새로운 치료법의 핵심이에요.' WHERE id = 'w_health_C2_10';
UPDATE words SET example_en_2 = 'Xenotransplantation could address the shortage of human donor organs.', example_ko_2 = '이종 이식은 인간 기증 장기 부족 문제를 해결할 수 있어요.', example_en_3 = 'The first xenotransplantation of a pig kidney was a medical milestone.', example_ko_3 = '돼지 신장의 첫 번째 이종 이식은 의학적 이정표였어요.', example_en_4 = 'Xenotransplantation raises ethical concerns about animal use.', example_ko_4 = '이종 이식은 동물 사용에 관한 윤리적 우려를 제기해요.', example_en_5 = 'Immune rejection remains the main barrier in xenotransplantation.', example_ko_5 = '면역 거부 반응은 이종 이식의 주요 장벽으로 남아 있어요.' WHERE id = 'w_health_C2_11';
UPDATE words SET example_en_2 = 'Cytotoxic drugs destroy cancer cells but may harm healthy tissue.', example_ko_2 = '세포 독성 약물은 암세포를 파괴하지만 건강한 조직에 해를 줄 수 있어요.', example_en_3 = 'Healthcare workers handle cytotoxic medications with special precautions.', example_ko_3 = '의료 종사자들은 특별한 주의를 기울여 세포 독성 약물을 취급해요.', example_en_4 = 'Cytotoxic therapy caused significant side effects for the patient.', example_ko_4 = '세포 독성 요법은 환자에게 상당한 부작용을 초래했어요.', example_en_5 = 'The cytotoxic effect was confirmed in laboratory testing.', example_ko_5 = '세포 독성 효과는 실험실 검사에서 확인됐어요.' WHERE id = 'w_health_C2_12';
UPDATE words SET example_en_2 = 'Apoptosis is the process by which damaged cells self-destruct.', example_ko_2 = '세포 자멸사는 손상된 세포가 스스로 소멸하는 과정이에요.', example_en_3 = 'Cancer cells often evade apoptosis and continue to grow.', example_ko_3 = '암세포는 종종 세포 자멸사를 회피하고 계속 성장해요.', example_en_4 = 'Many drugs target apoptosis pathways to kill cancer cells.', example_ko_4 = '많은 약물이 암세포를 죽이기 위해 세포 자멸사 경로를 표적으로 해요.', example_en_5 = 'Disrupted apoptosis is a hallmark of tumor development.', example_ko_5 = '교란된 세포 자멸사는 종양 발달의 특징이에요.' WHERE id = 'w_health_C2_13';
UPDATE words SET example_en_2 = 'A vasopressor was administered to stabilize his blood pressure.', example_ko_2 = '그의 혈압을 안정시키기 위해 혈관 수축제를 투여했어요.', example_en_3 = 'Vasopressors are used in septic shock management.', example_ko_3 = '혈관 수축제는 패혈성 쇼크 관리에 사용돼요.', example_en_4 = 'The ICU team adjusted the vasopressor dose carefully.', example_ko_4 = '중환자실 팀이 혈관 수축제 용량을 신중하게 조정했어요.', example_en_5 = 'She responded quickly to vasopressor treatment.', example_ko_5 = '그녀는 혈관 수축제 치료에 빠르게 반응했어요.' WHERE id = 'w_health_C2_14';
UPDATE words SET example_en_2 = 'A bronchodilator opens the airways and makes breathing easier.', example_ko_2 = '기관지 확장제는 기도를 열어 호흡을 쉽게 해요.', example_en_3 = 'She was given a bronchodilator during the asthma attack.', example_ko_3 = '그녀는 천식 발작 중에 기관지 확장제를 투여받았어요.', example_en_4 = 'Bronchodilators come in both short- and long-acting forms.', example_ko_4 = '기관지 확장제는 단기형과 장기형 두 가지가 있어요.', example_en_5 = 'The bronchodilator reduced his symptoms within minutes.', example_ko_5 = '기관지 확장제가 몇 분 안에 그의 증상을 줄였어요.' WHERE id = 'w_health_C2_15';
UPDATE words SET example_en_2 = 'Glycosylation affects how proteins function in the body.', example_ko_2 = '당화는 단백질이 체내에서 기능하는 방식에 영향을 미쳐요.', example_en_3 = 'Abnormal glycosylation is linked to several diseases.', example_ko_3 = '비정상적인 당화는 여러 질환과 관련이 있어요.', example_en_4 = 'Researchers are studying glycosylation patterns in cancer cells.', example_ko_4 = '연구자들이 암세포의 당화 패턴을 연구하고 있어요.', example_en_5 = 'Glycosylation plays a key role in immune cell signaling.', example_ko_5 = '당화는 면역 세포 신호 전달에서 핵심적인 역할을 해요.' WHERE id = 'w_health_C2_16';
UPDATE words SET example_en_2 = 'Nociception is the neural process of encoding pain signals.', example_ko_2 = '침해 수용은 통증 신호를 인코딩하는 신경 과정이에요.', example_en_3 = 'Damage to nociception pathways can lead to chronic pain.', example_ko_3 = '침해 수용 경로의 손상은 만성 통증으로 이어질 수 있어요.', example_en_4 = 'Research into nociception may improve pain management therapies.', example_ko_4 = '침해 수용에 대한 연구는 통증 관리 요법을 개선할 수 있어요.', example_en_5 = 'Some anesthetics work by blocking nociception entirely.', example_ko_5 = '일부 마취제는 침해 수용을 완전히 차단해 작동해요.' WHERE id = 'w_health_C2_17';
UPDATE words SET example_en_2 = 'Immune dysregulation can lead to autoimmune conditions.', example_ko_2 = '면역 조절 이상은 자가 면역 질환으로 이어질 수 있어요.', example_en_3 = 'Dysregulation of the endocrine system causes hormonal imbalances.', example_ko_3 = '내분비계의 조절 이상은 호르몬 불균형을 유발해요.', example_en_4 = 'Researchers identified a pathway involved in gene dysregulation.', example_ko_4 = '연구자들이 유전자 조절 이상에 관여하는 경로를 발견했어요.', example_en_5 = 'Dysregulation of sleep cycles increases the risk of metabolic disease.', example_ko_5 = '수면 주기의 조절 이상은 대사 질환의 위험을 높여요.' WHERE id = 'w_health_C2_18';
UPDATE words SET example_en_2 = 'Hemodynamic instability requires urgent medical intervention.', example_ko_2 = '혈역학적 불안정은 긴급한 의료 개입이 필요해요.', example_en_3 = 'The team monitored hemodynamic parameters throughout the surgery.', example_ko_3 = '팀은 수술 내내 혈역학적 수치를 모니터링했어요.', example_en_4 = 'Hemodynamic changes were observed after administering the drug.', example_ko_4 = '약물 투여 후 혈역학적 변화가 관찰됐어요.', example_en_5 = 'She trained in hemodynamic monitoring as part of her ICU rotation.', example_ko_5 = '그녀는 중환자실 순환 실습의 일환으로 혈역학 모니터링을 훈련했어요.' WHERE id = 'w_health_C2_19';
UPDATE words SET example_en_2 = 'Hyponatremia can cause confusion and seizures if severe.', example_ko_2 = '저나트륨혈증이 심하면 혼란과 발작을 유발할 수 있어요.', example_en_3 = 'She developed hyponatremia after drinking excessive amounts of water.', example_ko_3 = '그녀는 과도한 물을 마신 후 저나트륨혈증이 생겼어요.', example_en_4 = 'Treatment of hyponatremia requires careful correction of sodium levels.', example_ko_4 = '저나트륨혈증 치료에는 나트륨 수치를 신중하게 교정하는 것이 필요해요.', example_en_5 = 'Hyponatremia is a common electrolyte disorder in hospitalized patients.', example_ko_5 = '저나트륨혈증은 입원 환자에서 흔한 전해질 장애예요.' WHERE id = 'w_health_C2_20';
UPDATE words SET example_en_2 = 'Proteomics helps identify proteins involved in disease pathways.', example_ko_2 = '단백체학은 질환 경로에 관여하는 단백질을 규명하는 데 도움이 돼요.', example_en_3 = 'Advances in proteomics are transforming drug discovery.', example_ko_3 = '단백체학의 발전이 신약 개발을 변화시키고 있어요.', example_en_4 = 'She used proteomics to compare healthy and diseased tissue samples.', example_ko_4 = '그녀는 단백체학을 사용해 건강한 조직과 병든 조직 샘플을 비교했어요.', example_en_5 = 'Proteomics and genomics are often used together in research.', example_ko_5 = '단백체학과 유전체학은 연구에서 종종 함께 사용돼요.' WHERE id = 'w_health_C2_21';
UPDATE words SET example_en_2 = 'The compound was found to be mutagenic in cell culture tests.', example_ko_2 = '이 화합물은 세포 배양 실험에서 변이원성이 있는 것으로 밝혀졌어요.', example_en_3 = 'Mutagenic substances can alter DNA and increase cancer risk.', example_ko_3 = '변이원성 물질은 DNA를 변형시켜 암 위험을 높일 수 있어요.', example_en_4 = 'Regulatory agencies classify chemicals by their mutagenic potential.', example_ko_4 = '규제 기관은 화학 물질을 변이원성 가능성에 따라 분류해요.', example_en_5 = 'Avoiding mutagenic chemicals in the workplace protects long-term health.', example_ko_5 = '직장에서 변이원성 화학 물질을 피하면 장기적인 건강을 보호해요.' WHERE id = 'w_health_C2_22';
UPDATE words SET example_en_2 = 'Homeostasis is the body''s ability to maintain a stable internal environment.', example_ko_2 = '항상성은 신체가 안정적인 내부 환경을 유지하는 능력이에요.', example_en_3 = 'Disease disrupts the body''s normal homeostasis.', example_ko_3 = '질병은 신체의 정상적인 항상성을 방해해요.', example_en_4 = 'The kidneys play a crucial role in fluid homeostasis.', example_ko_4 = '신장은 체액 항상성에서 중요한 역할을 해요.', example_en_5 = 'Restoring homeostasis is the ultimate goal of many treatments.', example_ko_5 = '항상성을 회복하는 것이 많은 치료의 궁극적인 목표예요.' WHERE id = 'w_health_C2_23';
UPDATE words SET example_en_2 = 'The allograft was accepted without signs of rejection.', example_ko_2 = '동종 이식편은 거부 반응 없이 받아들여졌어요.', example_en_3 = 'An allograft uses tissue from a donor of the same species.', example_ko_3 = '동종 이식은 같은 종의 기증자로부터 조직을 사용해요.', example_en_4 = 'Allograft surgery requires long-term immunosuppressive therapy.', example_ko_4 = '동종 이식 수술은 장기적인 면역 억제 치료가 필요해요.', example_en_5 = 'The bone allograft was used to repair the damaged joint.', example_ko_5 = '손상된 관절을 복구하기 위해 골 동종 이식이 사용됐어요.' WHERE id = 'w_health_C2_24';
UPDATE words SET example_en_2 = 'Pleiotropic drugs have effects on multiple organ systems.', example_ko_2 = '다효성 약물은 여러 장기 시스템에 영향을 미쳐요.', example_en_3 = 'Statins are known for their pleiotropic cardiovascular benefits.', example_ko_3 = '스타틴은 다효성 심혈관 효과로 알려져 있어요.', example_en_4 = 'The pleiotropic nature of the gene made it difficult to study.', example_ko_4 = '유전자의 다효성 특성이 연구를 어렵게 만들었어요.', example_en_5 = 'Pleiotropic effects are common in complex signaling molecules.', example_ko_5 = '다효성 효과는 복잡한 신호 분자에서 흔해요.' WHERE id = 'w_health_C2_25';
UPDATE words SET example_en_2 = 'Ischemia can cause permanent tissue damage if prolonged.', example_ko_2 = '허혈이 지속되면 영구적인 조직 손상을 유발할 수 있어요.', example_en_3 = 'Myocardial ischemia is a warning sign of a potential heart attack.', example_ko_3 = '심근 허혈은 잠재적 심장마비의 경고 신호예요.', example_en_4 = 'Early treatment of ischemia can prevent irreversible damage.', example_ko_4 = '허혈의 조기 치료는 비가역적 손상을 예방할 수 있어요.', example_en_5 = 'Cerebral ischemia leads to stroke when blood flow is blocked.', example_ko_5 = '뇌 허혈은 혈류가 차단될 때 뇌졸중으로 이어져요.' WHERE id = 'w_health_C2_26';
UPDATE words SET example_en_2 = 'An exacerbation of asthma sent her to hospital overnight.', example_ko_2 = '천식 악화로 그녀는 하룻밤 입원했어요.', example_en_3 = 'Cold air can trigger an exacerbation of COPD.', example_ko_3 = '차가운 공기는 만성 폐쇄성 폐질환의 악화를 유발할 수 있어요.', example_en_4 = 'He was prescribed steroids to manage the exacerbation.', example_ko_4 = '그는 악화를 관리하기 위해 스테로이드를 처방받았어요.', example_en_5 = 'Preventing exacerbation requires strict adherence to treatment.', example_ko_5 = '악화를 예방하려면 치료에 엄격히 따라야 해요.' WHERE id = 'w_health_C2_27';
UPDATE words SET example_en_2 = 'Xenobiotics include drugs, pollutants, and food additives.', example_ko_2 = '이종 생체 물질에는 약물, 오염 물질, 식품 첨가물이 포함돼요.', example_en_3 = 'The liver metabolizes many xenobiotics before excretion.', example_ko_3 = '간은 배출 전에 많은 이종 생체 물질을 대사해요.', example_en_4 = 'Exposure to xenobiotics can disrupt hormonal balance.', example_ko_4 = '이종 생체 물질에 노출되면 호르몬 균형이 무너질 수 있어요.', example_en_5 = 'Researchers study how xenobiotics interact with cellular receptors.', example_ko_5 = '연구자들이 이종 생체 물질이 세포 수용체와 어떻게 상호 작용하는지 연구해요.' WHERE id = 'w_health_C2_28';
UPDATE words SET example_en_2 = 'Erythropoietin stimulates the production of red blood cells.', example_ko_2 = '에리트로포이에틴은 적혈구 생산을 촉진해요.', example_en_3 = 'Recombinant erythropoietin is used to treat anemia in dialysis patients.', example_ko_3 = '재조합 에리트로포이에틴은 투석 환자의 빈혈 치료에 사용돼요.', example_en_4 = 'The kidneys produce erythropoietin in response to low oxygen levels.', example_ko_4 = '신장은 낮은 산소 수치에 반응해 에리트로포이에틴을 생산해요.', example_en_5 = 'Erythropoietin levels were measured as part of the anemia workup.', example_ko_5 = '빈혈 검사의 일환으로 에리트로포이에틴 수치를 측정했어요.' WHERE id = 'w_health_C2_29';
UPDATE words SET example_en_2 = 'Osmolality is measured to assess the concentration of body fluids.', example_ko_2 = '삼투압은 체액 농도를 평가하기 위해 측정해요.', example_en_3 = 'Abnormal serum osmolality can indicate kidney dysfunction.', example_ko_3 = '비정상적인 혈청 삼투압은 신장 기능 이상을 나타낼 수 있어요.', example_en_4 = 'The osmolality of the IV fluid was carefully matched to the patient''s needs.', example_ko_4 = '정맥 주사 수액의 삼투압은 환자의 필요에 맞게 신중하게 조정됐어요.', example_en_5 = 'Urine osmolality helps determine the cause of dehydration.', example_ko_5 = '소변 삼투압은 탈수의 원인을 파악하는 데 도움이 돼요.' WHERE id = 'w_health_C2_30';
UPDATE words SET example_en_2 = 'Phagocytosis is how immune cells engulf and destroy pathogens.', example_ko_2 = '식균 작용은 면역 세포가 병원체를 집어삼켜 파괴하는 방법이에요.', example_en_3 = 'Macrophages perform phagocytosis to clear cellular debris.', example_ko_3 = '대식 세포는 세포 잔해를 제거하기 위해 식균 작용을 수행해요.', example_en_4 = 'Impaired phagocytosis leads to increased susceptibility to infections.', example_ko_4 = '손상된 식균 작용은 감염에 대한 취약성을 높여요.', example_en_5 = 'The process of phagocytosis is essential for wound healing.', example_ko_5 = '식균 작용 과정은 상처 치유에 필수적이에요.' WHERE id = 'w_health_C2_31';
UPDATE words SET example_en_2 = 'A neoplasm can be either benign or malignant.', example_ko_2 = '신생물은 양성이거나 악성일 수 있어요.', example_en_3 = 'The neoplasm was removed surgically and sent for biopsy.', example_ko_3 = '신생물을 수술로 제거하고 생검을 위해 보냈어요.', example_en_4 = 'Imaging revealed a neoplasm in the left lung.', example_ko_4 = '영상 검사에서 왼쪽 폐에 신생물이 발견됐어요.', example_en_5 = 'Malignant neoplasms require urgent and aggressive treatment.', example_ko_5 = '악성 신생물은 긴급하고 적극적인 치료가 필요해요.' WHERE id = 'w_health_C2_32';
UPDATE words SET example_en_2 = 'Coagulopathy increases the risk of uncontrolled bleeding.', example_ko_2 = '응고 장애는 통제되지 않는 출혈의 위험을 높여요.', example_en_3 = 'She developed coagulopathy as a complication of liver failure.', example_ko_3 = '그녀는 간부전의 합병증으로 응고 장애가 생겼어요.', example_en_4 = 'Disseminated intravascular coagulopathy is a life-threatening condition.', example_ko_4 = '파종성 혈관 내 응고 장애는 생명을 위협하는 질환이에요.', example_en_5 = 'Coagulopathy is managed with plasma and clotting factor transfusions.', example_ko_5 = '응고 장애는 혈장과 응고 인자 수혈로 관리해요.' WHERE id = 'w_health_C2_33';
UPDATE words SET example_en_2 = 'Aortic stenosis restricts blood flow out of the heart.', example_ko_2 = '대동맥 협착증은 심장에서 혈류를 제한해요.', example_en_3 = 'She had surgery to repair the stenosis in her carotid artery.', example_ko_3 = '그녀는 경동맥의 협착을 수술로 복구했어요.', example_en_4 = 'Stenosis of the coronary arteries is a major cause of angina.', example_ko_4 = '관상 동맥 협착은 협심증의 주요 원인이에요.', example_en_5 = 'The degree of stenosis was measured by ultrasound.', example_ko_5 = '협착의 정도는 초음파로 측정됐어요.' WHERE id = 'w_health_C2_34';
UPDATE words SET example_en_2 = 'Encephalopathy can result from liver failure or infection.', example_ko_2 = '뇌증은 간부전이나 감염으로 인해 발생할 수 있어요.', example_en_3 = 'He developed hepatic encephalopathy following the liver disease progression.', example_ko_3 = '그는 간 질환이 진행되면서 간성 뇌증이 생겼어요.', example_en_4 = 'Encephalopathy symptoms include confusion, memory loss, and personality changes.', example_ko_4 = '뇌증 증상에는 혼란, 기억 상실, 성격 변화가 포함돼요.', example_en_5 = 'Early treatment of the underlying cause can reverse encephalopathy.', example_ko_5 = '근본 원인을 조기에 치료하면 뇌증을 회복시킬 수 있어요.' WHERE id = 'w_health_C2_35';
