UPDATE words SET example_en_2 = 'The school opens at eight in the morning.', example_ko_2 = '학교는 아침 8시에 문을 열어요.', example_en_3 = 'There are five hundred students in this school.', example_ko_3 = '이 학교에는 학생이 500명 있어요.', example_en_4 = 'My school has a big sports field.', example_ko_4 = '우리 학교에는 큰 운동장이 있어요.', example_en_5 = 'She walks to school every day.', example_ko_5 = '그녀는 매일 걸어서 학교에 가요.' WHERE id = 'w_education_A1_01';
