-- C2
-- ────────────────────────────────────────────────────────────
UPDATE words SET example_en_2 = 'Heuristics can introduce systematic biases into expert judgement.', example_ko_2 = '발견적 방법은 전문가 판단에 체계적 편향을 도입할 수 있어요.', example_en_3 = 'Kahneman distinguishes fast heuristics from slow deliberate reasoning.', example_ko_3 = '카너먼은 빠른 발견적 방법과 느린 숙고적 추론을 구별해요.', example_en_4 = 'Educational heuristics guide teachers when rules alone are insufficient.', example_ko_4 = '교육적 발견적 방법은 규칙만으로는 부족할 때 교사를 안내해요.', example_en_5 = 'The study examined how novice researchers adopt discipline-specific heuristics.', example_ko_5 = '그 연구는 초보 연구자들이 분야별 발견적 방법을 어떻게 습득하는지를 살펴봤어요.' WHERE id = 'w_education_C2_01';
UPDATE words SET example_en_2 = 'Phenomenology brackets prior assumptions to attend to lived experience.', example_ko_2 = '현상학은 살아있는 경험에 집중하기 위해 사전 전제를 괄호 안에 넣어요.', example_en_3 = 'Husserl''s phenomenology sought to describe the structures of consciousness.', example_ko_3 = '후설의 현상학은 의식의 구조를 기술하고자 했어요.', example_en_4 = 'Interpretative phenomenological analysis is widely used in health research.', example_ko_4 = '해석적 현상학적 분석은 건강 연구에서 널리 사용돼요.', example_en_5 = 'Phenomenology foregrounds the subjective dimension that positivism neglects.', example_ko_5 = '현상학은 실증주의가 외면하는 주관적 차원을 부각시켜요.' WHERE id = 'w_education_C2_02';
UPDATE words SET example_en_2 = 'Reductionism risks oversimplifying complex social phenomena.', example_ko_2 = '환원주의는 복잡한 사회 현상을 지나치게 단순화할 위험이 있어요.', example_en_3 = 'Biological reductionism cannot adequately explain cultural learning.', example_ko_3 = '생물학적 환원주의는 문화적 학습을 충분히 설명할 수 없어요.', example_en_4 = 'The critique of reductionism calls for holistic, systemic approaches.', example_ko_4 = '환원주의에 대한 비판은 전체론적이고 체계적인 접근법을 요청해요.', example_en_5 = 'Methodological reductionism has been challenged by complexity theorists.', example_ko_5 = '방법론적 환원주의는 복잡성 이론가들에 의해 도전받아왔어요.' WHERE id = 'w_education_C2_03';
UPDATE words SET example_en_2 = 'Popper''s falsifiability criterion distinguishes science from pseudo-science.', example_ko_2 = '포퍼의 반증 가능성 기준은 과학과 유사 과학을 구분해줘요.', example_en_3 = 'A hypothesis lacking falsifiability cannot be evaluated scientifically.', example_ko_3 = '반증 가능성이 없는 가설은 과학적으로 평가될 수 없어요.', example_en_4 = 'Falsifiability remains central to the philosophy of natural science.', example_ko_4 = '반증 가능성은 자연과학 철학의 핵심으로 남아 있어요.', example_en_5 = 'Critics question whether falsifiability applies equally to social science.', example_ko_5 = '비평가들은 반증 가능성이 사회과학에도 동등하게 적용되는지 의문을 제기해요.' WHERE id = 'w_education_C2_04';
UPDATE words SET example_en_2 = 'Her epistemological commitments shaped her choice of interpretive methodology.', example_ko_2 = '그녀의 인식론적 헌신은 해석적 방법론 선택을 형성했어요.', example_en_3 = 'The paper maps the epistemological terrain between realism and constructivism.', example_ko_3 = '그 논문은 실재론과 구성주의 사이의 인식론적 지형을 지도화해요.', example_en_4 = 'Epistemological humility demands acknowledging the limits of one''s own knowledge.', example_ko_4 = '인식론적 겸손은 자신의 지식 한계를 인정할 것을 요구해요.', example_en_5 = 'The researchers disclosed their epistemological assumptions in the methods section.', example_ko_5 = '연구자들은 방법 섹션에서 자신들의 인식론적 전제를 공개했어요.' WHERE id = 'w_education_C2_05';
UPDATE words SET example_en_2 = 'Praxis, for Freire, is the unity of reflection and action upon the world.', example_ko_2 = '프레이리에게 프락시스는 세계에 대한 성찰과 행동의 통일이에요.', example_en_3 = 'The doctoral programme aimed to cultivate a praxis-oriented research disposition.', example_ko_3 = '박사 프로그램은 프락시스 지향적 연구 성향을 함양하고자 했어요.', example_en_4 = 'Praxis collapses the dichotomy between knowing and doing.', example_ko_4 = '프락시스는 앎과 행함 사이의 이분법을 허물어요.', example_en_5 = 'Without a commitment to praxis, critical scholarship risks becoming self-referential.', example_ko_5 = '프락시스에 대한 헌신 없이는 비판적 학문이 자기 참조적이 될 위험이 있어요.' WHERE id = 'w_education_C2_06';
UPDATE words SET example_en_2 = 'Deconstruction exposes the internal contradictions within seemingly stable texts.', example_ko_2 = '해체는 겉으로 안정된 텍스트 내부의 모순을 드러내요.', example_en_3 = 'Derrida''s deconstruction unsettles the binary oppositions of Western philosophy.', example_ko_3 = '데리다의 해체는 서양 철학의 이항 대립을 불안정하게 만들어요.', example_en_4 = 'Deconstruction as a reading strategy resists singular interpretations.', example_ko_4 = '읽기 전략으로서의 해체는 단일한 해석에 저항해요.', example_en_5 = 'Her paper applied deconstruction to reveal ideological tensions in curriculum policy.', example_ko_5 = '그녀의 논문은 해체를 적용하여 교육과정 정책의 이데올로기적 긴장을 드러냈어요.' WHERE id = 'w_education_C2_07';
UPDATE words SET example_en_2 = 'Semiotic analysis reveals how signs construct meaning in educational texts.', example_ko_2 = '기호론적 분석은 교육 텍스트에서 기호가 어떻게 의미를 구성하는지 드러내요.', example_en_3 = 'A semiotic framework can be applied to visual as well as verbal discourse.', example_ko_3 = '기호론적 틀은 언어 담화뿐만 아니라 시각 담화에도 적용될 수 있어요.', example_en_4 = 'Peirce''s semiotic theory distinguishes icon, index, and symbol.', example_ko_4 = '퍼스의 기호론 이론은 아이콘, 인덱스, 상징을 구분해요.', example_en_5 = 'The multimodal semiotic approach proved productive for analysing classroom interaction.', example_ko_5 = '다중 양식적 기호론 접근법은 교실 상호작용 분석에 효과적이었어요.' WHERE id = 'w_education_C2_08';
UPDATE words SET example_en_2 = 'Poststructuralism questions the stability of meaning and the unity of the subject.', example_ko_2 = '후기 구조주의는 의미의 안정성과 주체의 통일성에 의문을 제기해요.', example_en_3 = 'Her research is informed by poststructuralism and feminist theory.', example_ko_3 = '그녀의 연구는 후기 구조주의와 페미니즘 이론을 기반으로 해요.', example_en_4 = 'Poststructuralism has profoundly reshaped educational philosophy since the 1980s.', example_ko_4 = '후기 구조주의는 1980년대 이후 교육 철학을 깊이 재편해왔어요.', example_en_5 = 'The poststructuralist critique of the subject challenges humanist pedagogical assumptions.', example_ko_5 = '주체에 대한 후기 구조주의적 비판은 인본주의적 교육학 전제에 도전해요.' WHERE id = 'w_education_C2_09';
UPDATE words SET example_en_2 = 'Scholasticism sought to reconcile faith and reason through systematic logic.', example_ko_2 = '스콜라 철학은 체계적 논리를 통해 신앙과 이성을 조화시키고자 했어요.', example_en_3 = 'Aquinas remains the most celebrated figure of medieval scholasticism.', example_ko_3 = '아퀴나스는 중세 스콜라 철학의 가장 유명한 인물로 남아 있어요.', example_en_4 = 'Critics of contemporary academia accuse it of neo-scholasticism divorced from practice.', example_ko_4 = '현대 학계 비평가들은 그것이 실천과 괴리된 신스콜라 철학이라고 비판해요.', example_en_5 = 'The lecture traced the decline of scholasticism and the emergence of Enlightenment thought.', example_ko_5 = '그 강의는 스콜라 철학의 쇠퇴와 계몽주의 사상의 등장을 추적했어요.' WHERE id = 'w_education_C2_10';
UPDATE words SET example_en_2 = 'An ontological commitment to social constructivism shapes qualitative inquiry.', example_ko_2 = '사회적 구성주의에 대한 존재론적 헌신은 질적 탐구의 형태를 결정해요.', example_en_3 = 'The ontological question of what counts as real pervades educational research.', example_ko_3 = '무엇이 실재로 간주되는지에 관한 존재론적 질문은 교육 연구 전반에 걸쳐 있어요.', example_en_4 = 'She defended a realist ontological position against idealist critiques.', example_ko_4 = '그녀는 관념론적 비판에 맞서 실재론적 존재론 입장을 옹호했어요.', example_en_5 = 'Ontological claims must be made explicit to ensure methodological coherence.', example_ko_5 = '방법론적 일관성을 보장하려면 존재론적 주장을 명시적으로 밝혀야 해요.' WHERE id = 'w_education_C2_11';
UPDATE words SET example_en_2 = 'Intersubjectivity emerges through shared engagement with a common object of study.', example_ko_2 = '상호주관성은 공통된 연구 대상에 대한 공유된 참여를 통해 나타나요.', example_en_3 = 'The concept of intersubjectivity underpins collaborative knowledge construction.', example_ko_3 = '상호주관성 개념은 협력적 지식 구성의 기초를 이뤄요.', example_en_4 = 'Phenomenologists see intersubjectivity as foundational to social reality.', example_ko_4 = '현상학자들은 상호주관성을 사회적 현실의 토대로 봐요.', example_en_5 = 'The analysis explored how intersubjectivity is achieved in online learning environments.', example_ko_5 = '분석에서는 온라인 학습 환경에서 상호주관성이 어떻게 달성되는지를 탐구했어요.' WHERE id = 'w_education_C2_12';
UPDATE words SET example_en_2 = 'Logocentrism privileges the spoken word as the origin of authentic meaning.', example_ko_2 = '로고중심주의는 말하기를 진정한 의미의 원천으로 특권화해요.', example_en_3 = 'Derrida''s critique of logocentrism opens space for alternative epistemologies.', example_ko_3 = '데리다의 로고중심주의 비판은 대안적 인식론을 위한 공간을 열어요.', example_en_4 = 'The paper argued that logocentrism pervades Western educational discourse.', example_ko_4 = '그 논문은 로고중심주의가 서양 교육 담론 전반에 퍼져 있다고 주장했어요.', example_en_5 = 'Challenging logocentrism requires attending to the margins and silences of texts.', example_ko_5 = '로고중심주의에 도전하려면 텍스트의 주변부와 침묵에 주목해야 해요.' WHERE id = 'w_education_C2_13';
UPDATE words SET example_en_2 = 'Kant distinguished the noumenon from the phenomenon as knowable appearance.', example_ko_2 = '칸트는 물자체를 알 수 있는 현상으로서의 현상과 구분했어요.', example_en_3 = 'The noumenon is, by definition, beyond the reach of sensory experience.', example_ko_3 = '물자체는 정의상 감각 경험의 범위를 벗어나 있어요.', example_en_4 = 'Educational philosophy rarely ventures into the territory of the noumenon.', example_ko_4 = '교육 철학은 물자체의 영역에 좀처럼 발을 들이지 않아요.', example_en_5 = 'The notion of the noumenon raises irreducible questions about the limits of knowledge.', example_ko_5 = '물자체 개념은 지식의 한계에 관한 환원 불가능한 질문을 제기해요.' WHERE id = 'w_education_C2_14';
UPDATE words SET example_en_2 = 'Teleology interprets educational processes in terms of their ultimate ends.', example_ko_2 = '목적론은 교육 과정을 그 궁극적 목적의 측면에서 해석해요.', example_en_3 = 'Aristotle''s teleology shaped medieval conceptions of learning and virtue.', example_ko_3 = '아리스토텔레스의 목적론은 중세의 학습과 덕성 개념을 형성했어요.', example_en_4 = 'Critics argue that teleological narratives of progress mask historical contingency.', example_ko_4 = '비평가들은 진보에 관한 목적론적 서사가 역사적 우연성을 가린다고 주장해요.', example_en_5 = 'A teleological approach to curriculum design asks what the educated person should become.', example_ko_5 = '교육과정 설계에 대한 목적론적 접근법은 교육받은 사람이 어떻게 되어야 하는지를 묻는 거예요.' WHERE id = 'w_education_C2_15';
UPDATE words SET example_en_2 = 'Intertextuality shows that every text is a mosaic of earlier voices.', example_ko_2 = '상호텍스트성은 모든 텍스트가 이전 목소리들의 모자이크임을 보여줘요.', example_en_3 = 'Kristeva coined the term intertextuality to describe the web of textual relations.', example_ko_3 = '크리스테바는 텍스트 관계의 그물망을 묘사하기 위해 상호텍스트성이라는 용어를 만들었어요.', example_en_4 = 'The analysis traced intertextuality between policy documents and academic discourse.', example_ko_4 = '분석은 정책 문서와 학술 담론 사이의 상호텍스트성을 추적했어요.', example_en_5 = 'Intertextuality complicates the notion of authorial originality in academic writing.', example_ko_5 = '상호텍스트성은 학술 글쓰기에서 저자의 독창성 개념을 복잡하게 만들어요.' WHERE id = 'w_education_C2_16';
UPDATE words SET example_en_2 = 'Moral relativism denies that any ethical standard is universally valid.', example_ko_2 = '도덕적 상대주의는 어떤 윤리적 기준도 보편적으로 타당하지 않다고 부정해요.', example_en_3 = 'Her critique argued that cultural relativism risks excusing harm.', example_ko_3 = '그녀의 비판은 문화적 상대주의가 해악을 용인할 위험이 있다고 주장했어요.', example_en_4 = 'Cognitive relativism holds that truth is always relative to a conceptual scheme.', example_ko_4 = '인지적 상대주의는 진리가 항상 개념적 틀에 상대적이라고 주장해요.', example_en_5 = 'The debate between relativism and universalism pervades philosophy of education.', example_ko_5 = '상대주의와 보편주의 사이의 논쟁은 교육 철학 전반에 걸쳐 있어요.' WHERE id = 'w_education_C2_17';
UPDATE words SET example_en_2 = 'Dialectical materialism analyses social change through the lens of material conditions.', example_ko_2 = '변증법적 유물론은 물질적 조건의 렌즈를 통해 사회 변화를 분석해요.', example_en_3 = 'Marx and Engels developed dialectical materialism as a critique of Hegelian idealism.', example_ko_3 = '마르크스와 엥겔스는 헤겔의 관념론을 비판하며 변증법적 유물론을 발전시켰어요.', example_en_4 = 'Dialectical materialism informed critical approaches to curriculum theory in the 1970s.', example_ko_4 = '변증법적 유물론은 1970년대 교육과정 이론의 비판적 접근법에 영향을 미쳤어요.', example_en_5 = 'The study drew on dialectical materialism to examine power relations in schooling.', example_ko_5 = '그 연구는 학교 교육에서의 권력 관계를 살펴보기 위해 변증법적 유물론을 활용했어요.' WHERE id = 'w_education_C2_18';
UPDATE words SET example_en_2 = 'Derrida exploits aporia to reveal the unresolvable tensions within texts.', example_ko_2 = '데리다는 아포리아를 활용하여 텍스트 내의 해결 불가능한 긴장을 드러내요.', example_en_3 = 'The concept of aporia foregrounds the limits of rational argument.', example_ko_3 = '아포리아 개념은 합리적 논증의 한계를 부각시켜요.', example_en_4 = 'The seminar ended in productive aporia — more questions than answers.', example_ko_4 = '그 세미나는 생산적인 아포리아로 끝났어요 — 답보다 질문이 더 많았죠.', example_en_5 = 'Aporia signals the point at which conventional interpretive frameworks break down.', example_ko_5 = '아포리아는 기존의 해석 틀이 무너지는 지점을 나타내요.' WHERE id = 'w_education_C2_19';
UPDATE words SET example_en_2 = 'Bakhtin''s concept of heteroglossia describes the coexistence of multiple voices in discourse.', example_ko_2 = '바흐틴의 이성적 복수성 개념은 담론에서 여러 목소리의 공존을 묘사해요.', example_en_3 = 'Heteroglossia challenges the assumption that academic discourse should be monological.', example_ko_3 = '이성적 복수성은 학술 담론이 단일 목소리여야 한다는 전제에 도전해요.', example_en_4 = 'The novel''s heteroglossia mirrors the ideological diversity of its social context.', example_ko_4 = '그 소설의 이성적 복수성은 그 사회적 맥락의 이데올로기적 다양성을 반영해요.', example_en_5 = 'Recognising heteroglossia in the classroom validates learners'' diverse linguistic repertoires.', example_ko_5 = '교실에서 이성적 복수성을 인식하는 것은 학습자의 다양한 언어 레퍼토리를 인정해요.' WHERE id = 'w_education_C2_20';
UPDATE words SET example_en_2 = 'Abduction involves inferring the best explanation from incomplete evidence.', example_ko_2 = '가추론은 불완전한 증거로부터 최선의 설명을 추론하는 것이에요.', example_en_3 = 'Peirce characterised abduction as the first step in scientific inquiry.', example_ko_3 = '퍼스는 가추론을 과학적 탐구의 첫 번째 단계로 특징지었어요.', example_en_4 = 'In qualitative research, abduction moves flexibly between theory and data.', example_ko_4 = '질적 연구에서 가추론은 이론과 데이터 사이를 유연하게 오가요.', example_en_5 = 'Abduction enables researchers to propose novel theoretical explanations.', example_ko_5 = '가추론은 연구자들이 새로운 이론적 설명을 제안할 수 있게 해줘요.' WHERE id = 'w_education_C2_21';
UPDATE words SET example_en_2 = 'Phronesis guides professional judgement in contexts where rules are insufficient.', example_ko_2 = '실천적 지혜는 규칙이 충분하지 않은 맥락에서 전문적 판단을 안내해요.', example_en_3 = 'Aristotle''s phronesis cannot be reduced to technical knowledge or procedures.', example_ko_3 = '아리스토텔레스의 실천적 지혜는 기술적 지식이나 절차로 환원될 수 없어요.', example_en_4 = 'Teacher education should cultivate phronesis alongside subject knowledge.', example_ko_4 = '교사 교육은 교과 지식과 함께 실천적 지혜를 함양해야 해요.', example_en_5 = 'Phronesis involves perceiving the ethically salient features of particular situations.', example_ko_5 = '실천적 지혜는 특정 상황에서 윤리적으로 중요한 특성을 인식하는 것을 포함해요.' WHERE id = 'w_education_C2_22';
UPDATE words SET example_en_2 = 'Liminality describes the threshold state between two stages of identity or knowledge.', example_ko_2 = '경계성은 정체성이나 지식의 두 단계 사이의 문턱 상태를 묘사해요.', example_en_3 = 'Students experience liminality when encountering threshold concepts in a discipline.', example_ko_3 = '학생들은 학문에서 문턱 개념을 접할 때 경계성을 경험해요.', example_en_4 = 'The researcher inhabited a liminal position between insider and outsider.', example_ko_4 = '연구자는 내부인과 외부인 사이의 경계적 위치에 있었어요.', example_en_5 = 'Liminality can be a productive, if uncomfortable, space for intellectual transformation.', example_ko_5 = '경계성은 불편하지만 지적 변화를 위한 생산적인 공간이 될 수 있어요.' WHERE id = 'w_education_C2_23';
UPDATE words SET example_en_2 = 'Hegemony operates through consent as much as through coercion.', example_ko_2 = '헤게모니는 강제만큼이나 동의를 통해 작동해요.', example_en_3 = 'Gramsci''s hegemony illuminates how dominant groups maintain cultural power.', example_ko_3 = '그람시의 헤게모니는 지배 집단이 어떻게 문화적 권력을 유지하는지를 보여줘요.', example_en_4 = 'Curriculum theory examines how hegemony shapes what counts as valid knowledge.', example_ko_4 = '교육과정 이론은 헤게모니가 어떻게 유효한 지식을 형성하는지를 탐구해요.', example_en_5 = 'Counter-hegemonic pedagogy seeks to challenge taken-for-granted assumptions.', example_ko_5 = '반헤게모니적 교육학은 당연하게 여겨지는 전제에 도전하고자 해요.' WHERE id = 'w_education_C2_24';
UPDATE words SET example_en_2 = 'The skilled interlocutor adapts their register to the needs of the discussion.', example_ko_2 = '숙련된 대화 상대방은 논의의 필요에 맞게 언어 사용역을 조절해요.', example_en_3 = 'Socratic dialogue requires a responsive and questioning interlocutor.', example_ko_3 = '소크라테스식 대화는 반응적이고 질문하는 대화 상대방을 필요로 해요.', example_en_4 = 'The interviewer functions as a sympathetic interlocutor, not a neutral observer.', example_ko_4 = '면접관은 중립적인 관찰자가 아니라 공감적인 대화 상대방으로 기능해요.', example_en_5 = 'Her role as interlocutor shaped the direction and depth of the discourse.', example_ko_5 = '대화 상대방으로서 그녀의 역할은 담론의 방향과 깊이를 형성했어요.' WHERE id = 'w_education_C2_25';
UPDATE words SET example_en_2 = 'Verisimilitude in academic writing creates the appearance of authoritative truth.', example_ko_2 = '학술 글쓰기에서 진실성은 권위 있는 진리의 외관을 만들어요.', example_en_3 = 'Popper used verisimilitude to describe a theory''s closeness to the truth.', example_ko_3 = '포퍼는 이론이 진리에 얼마나 가까운지를 묘사하기 위해 진실성이라는 용어를 사용했어요.', example_en_4 = 'The narrative''s verisimilitude lends credibility to its pedagogical claims.', example_ko_4 = '서사의 진실성은 교육학적 주장에 신뢰성을 부여해요.', example_en_5 = 'She questioned the verisimilitude of the case studies used to support the argument.', example_ko_5 = '그녀는 주장을 뒷받침하는 사례 연구의 진실성에 의문을 제기했어요.' WHERE id = 'w_education_C2_26';
UPDATE words SET example_en_2 = 'Foucault''s episteme refers to the underlying conditions that make knowledge possible.', example_ko_2 = '푸코의 에피스테메는 지식을 가능하게 하는 근본적 조건을 가리켜요.', example_en_3 = 'Each historical epoch, for Foucault, is characterised by a distinct episteme.', example_ko_3 = '푸코에게 각 역사적 시대는 고유한 에피스테메로 특징지어져요.', example_en_4 = 'The shift from one episteme to another is rarely gradual or smooth.', example_ko_4 = '하나의 에피스테메에서 다른 것으로의 전환은 좀처럼 점진적이거나 순조롭지 않아요.', example_en_5 = 'Analysing the episteme helps researchers situate knowledge claims historically.', example_ko_5 = '에피스테메를 분석하면 연구자가 지식 주장을 역사적으로 위치 지을 수 있어요.' WHERE id = 'w_education_C2_27';
UPDATE words SET example_en_2 = 'Bricolage draws on whatever theoretical tools are available to address a problem.', example_ko_2 = '브리콜라주는 문제를 해결하기 위해 사용 가능한 어떤 이론적 도구든 활용해요.', example_en_3 = 'Her methodology was a bricolage of ethnographic and discourse-analytic methods.', example_ko_3 = '그녀의 방법론은 민족지학과 담화 분석 방법의 브리콜라주였어요.', example_en_4 = 'Bricolage in research resists methodological purism in favour of pragmatic flexibility.', example_ko_4 = '연구에서의 브리콜라주는 실용적 유연성을 위해 방법론적 순수주의에 저항해요.', example_en_5 = 'Kincheloe advocated bricolage as a means to address the complexity of educational phenomena.', example_ko_5 = '킨첼로에는 교육 현상의 복잡성을 다루는 수단으로 브리콜라주를 옹호했어요.' WHERE id = 'w_education_C2_28';
UPDATE words SET example_en_2 = 'Sedimentation describes how past experiences solidify into taken-for-granted habits.', example_ko_2 = '침전은 과거 경험이 당연하게 여겨지는 습관으로 굳어지는 방식을 묘사해요.', example_en_3 = 'Bourdieu''s notion of habitus is related to the sedimentation of social practice.', example_ko_3 = '부르디외의 아비투스 개념은 사회적 실천의 침전과 관련이 있어요.', example_en_4 = 'Critical pedagogy aims to disrupt the sedimentation of oppressive ideologies.', example_ko_4 = '비판 교육학은 억압적 이데올로기의 침전을 방해하는 것을 목표로 해요.', example_en_5 = 'The sedimentation of institutional norms makes them difficult to challenge or reform.', example_ko_5 = '제도적 규범의 침전은 그것들을 도전하거나 개혁하기 어렵게 만들어요.' WHERE id = 'w_education_C2_29';
UPDATE words SET example_en_2 = 'Deleuze and Guattari''s rhizome challenges linear models of knowledge growth.', example_ko_2 = '들뢰즈와 가타리의 리좀은 지식 성장의 선형적 모델에 도전해요.', example_en_3 = 'A rhizome has no centre or fixed origin — it spreads in all directions.', example_ko_3 = '리좀은 중심이나 고정된 기원이 없으며 모든 방향으로 퍼져나가요.', example_en_4 = 'Rhizomatic curriculum theory resists the arborescent logic of objectives and outcomes.', example_ko_4 = '리좀적 교육과정 이론은 목표와 성과에 관한 수목형 논리에 저항해요.', example_en_5 = 'The rhizome serves as a productive metaphor for open, networked learning.', example_ko_5 = '리좀은 열린 네트워크 학습을 위한 생산적인 은유로 기능해요.' WHERE id = 'w_education_C2_30';
UPDATE words SET example_en_2 = 'Logomachy in academic debate often substitutes terminological dispute for substantive argument.', example_ko_2 = '학술 논쟁에서의 언어 싸움은 종종 실질적 논증을 용어 논쟁으로 대체해요.', example_en_3 = 'The committee meeting devolved into logomachy without resolving the core issue.', example_ko_3 = '위원회 회의는 핵심 문제를 해결하지 못한 채 언어 싸움으로 전락했어요.', example_en_4 = 'He warned that interdisciplinary dialogue risks descending into logomachy.', example_ko_4 = '그는 학제간 대화가 언어 싸움으로 전락할 위험이 있다고 경고했어요.', example_en_5 = 'Careful concept clarification can prevent productive debate from becoming logomachy.', example_ko_5 = '신중한 개념 명확화는 생산적인 논쟁이 언어 싸움이 되는 것을 막을 수 있어요.' WHERE id = 'w_education_C2_31';
UPDATE words SET example_en_2 = 'A propaedeutic course in logic prepares students for advanced philosophical study.', example_ko_2 = '논리학 예비 교육 과정은 학생들이 고급 철학 연구를 준비할 수 있게 해줘요.', example_en_3 = 'The text functions as a propaedeutic to the author''s more ambitious later work.', example_ko_3 = '그 텍스트는 저자의 더 야심찬 후기 작업을 위한 예비 교육으로 기능해요.', example_en_4 = 'She described the foundation year as propaedeutic rather than merely remedial.', example_ko_4 = '그녀는 기초 과정을 단순한 보충이 아니라 예비 교육으로 묘사했어요.', example_en_5 = 'Research methods training serves as a propaedeutic to doctoral inquiry.', example_ko_5 = '연구 방법 훈련은 박사 연구를 위한 예비 교육으로 기능해요.' WHERE id = 'w_education_C2_32';
UPDATE words SET example_en_2 = 'Aristotle conceived catharsis as the emotional purgation effected by tragedy.', example_ko_2 = '아리스토텔레스는 카타르시스를 비극이 일으키는 감정적 정화로 구상했어요.', example_en_3 = 'Drama-based pedagogy can produce a catharsis that facilitates personal insight.', example_ko_3 = '드라마 기반 교육학은 개인적 통찰을 촉진하는 카타르시스를 이끌어낼 수 있어요.', example_en_4 = 'She described the thesis defence as a catharsis that marked the end of her doctoral journey.', example_ko_4 = '그녀는 논문 심사를 박사 과정의 끝을 알리는 카타르시스로 묘사했어요.', example_en_5 = 'The concept of catharsis has been repurposed within therapeutic education models.', example_ko_5 = '카타르시스 개념은 치료적 교육 모델 내에서 재활용됐어요.' WHERE id = 'w_education_C2_33';
UPDATE words SET example_en_2 = 'Descartes'' cogito establishes subjective certainty as the foundation of knowledge.', example_ko_2 = '데카르트의 코기토는 주관적 확실성을 지식의 기초로 확립해요.', example_en_3 = 'The cogito has been both celebrated and contested throughout modern philosophy.', example_ko_3 = '코기토는 현대 철학 전반에서 찬사와 논쟁을 동시에 받아왔어요.', example_en_4 = 'Feminist philosophers have questioned whether the cogito assumes a disembodied self.', example_ko_4 = '페미니스트 철학자들은 코기토가 몸 없는 자아를 가정하는지 의문을 제기해왔어요.', example_en_5 = 'The cogito anchors Cartesian epistemology in the first-person standpoint.', example_ko_5 = '코기토는 데카르트 인식론을 1인칭 관점에 고정해요.' WHERE id = 'w_education_C2_34';
UPDATE words SET example_en_2 = 'Plato''s anamnesis holds that learning is the recollection of pre-existent knowledge.', example_ko_2 = '플라톤의 상기론은 학습이 선재하는 지식의 회상이라고 주장해요.', example_en_3 = 'The Meno dialogue illustrates anamnesis through Socrates'' questioning of a slave boy.', example_ko_3 = '메논 대화는 소크라테스가 노예 소년을 질문하는 방식으로 상기론을 예시해요.', example_en_4 = 'Anamnesis implies that education is facilitation of remembering rather than transmission.', example_ko_4 = '상기론은 교육이 전달이 아닌 기억의 촉진임을 시사해요.', example_en_5 = 'Contemporary neuroscience has revisited anamnesis through the lens of implicit memory.', example_ko_5 = '현대 신경과학은 암묵적 기억의 렌즈를 통해 상기론을 재검토했어요.' WHERE id = 'w_education_C2_35';
-- EngCat · Environment topic · words example sentences (examples 2-5)
-- A1 words

UPDATE words SET example_en_2 = 'The old tree in our garden gives us shade in summer.', example_ko_2 = '정원에 있는 오래된 나무가 여름에 그늘을 만들어 줘요.', example_en_3 = 'We planted a tree to celebrate Earth Day.', example_ko_3 = '지구의 날을 기념하여 나무 한 그루를 심었어요.', example_en_4 = 'Some trees can live for hundreds of years.', example_ko_4 = '어떤 나무들은 수백 년 동안 살 수 있어요.', example_en_5 = 'The tree provides a home for many birds and insects.', example_ko_5 = '그 나무는 많은 새와 곤충들에게 집이 되어 줘요.' WHERE id = 'w_environment_A1_01';
UPDATE words SET example_en_2 = 'Please don''t waste water when you brush your teeth.', example_ko_2 = '양치질할 때 물을 낭비하지 마세요.', example_en_3 = 'The water in this river is very clear and clean.', example_ko_3 = '이 강의 물은 매우 맑고 깨끗해요.', example_en_4 = 'We use water for drinking, cooking, and washing.', example_ko_4 = '우리는 마시고, 요리하고, 씻는 데 물을 사용해요.', example_en_5 = 'Turn off the tap so we don''t waste water.', example_ko_5 = '물을 낭비하지 않도록 수도꼭지를 잠가 주세요.' WHERE id = 'w_environment_A1_02';
UPDATE words SET example_en_2 = 'The air in the mountains feels so fresh and clean.', example_ko_2 = '산속의 공기는 정말 상쾌하고 깨끗하게 느껴져요.', example_en_3 = 'We need clean air to stay healthy.', example_ko_3 = '건강을 유지하려면 깨끗한 공기가 필요해요.', example_en_4 = 'Cars and factories can pollute the air around us.', example_ko_4 = '자동차와 공장은 주변 공기를 오염시킬 수 있어요.', example_en_5 = 'Open the window to let fresh air into the room.', example_ko_5 = '창문을 열어 방 안에 신선한 공기가 들어오게 해 주세요.' WHERE id = 'w_environment_A1_03';
UPDATE words SET example_en_2 = 'We should keep our parks clean for everyone to enjoy.', example_ko_2 = '모두가 즐길 수 있도록 공원을 깨끗하게 유지해야 해요.', example_en_3 = 'The volunteers helped to clean up the beach last weekend.', example_ko_3 = '지난 주말에 봉사자들이 해변을 청소하는 것을 도왔어요.', example_en_4 = 'It feels good to have a clean and tidy home.', example_ko_4 = '깨끗하고 정돈된 집을 갖는 것은 기분 좋은 일이에요.', example_en_5 = 'Drinking clean water is very important for your health.', example_ko_5 = '깨끗한 물을 마시는 것은 건강에 매우 중요해요.' WHERE id = 'w_environment_A1_04';
UPDATE words SET example_en_2 = 'Spending time in nature can help reduce stress.', example_ko_2 = '자연 속에서 시간을 보내면 스트레스를 줄이는 데 도움이 돼요.', example_en_3 = 'Many people visit national parks to enjoy nature.', example_ko_3 = '많은 사람들이 자연을 즐기기 위해 국립공원을 방문해요.', example_en_4 = 'We must protect nature for future generations.', example_ko_4 = '미래 세대를 위해 자연을 보호해야 해요.', example_en_5 = 'The documentary showed the beauty of nature around the world.', example_ko_5 = '그 다큐멘터리는 전 세계 자연의 아름다움을 보여 주었어요.' WHERE id = 'w_environment_A1_05';
UPDATE words SET example_en_2 = 'The sun rises in the east and sets in the west.', example_ko_2 = '태양은 동쪽에서 떠서 서쪽으로 져요.', example_en_3 = 'Too much sun can burn your skin, so wear sunscreen.', example_ko_3 = '햇빛을 너무 많이 쬐면 피부가 탈 수 있으니 자외선 차단제를 바르세요.', example_en_4 = 'Solar panels use energy from the sun to make electricity.', example_ko_4 = '태양 전지판은 태양의 에너지를 이용해 전기를 만들어요.', example_en_5 = 'The sunlight came through the window and warmed the room.', example_ko_5 = '햇빛이 창문을 통해 들어와 방을 따뜻하게 해 주었어요.' WHERE id = 'w_environment_A1_06';
UPDATE words SET example_en_2 = 'The earth is the only planet we know that has life.', example_ko_2 = '지구는 우리가 아는 유일하게 생명체가 있는 행성이에요.', example_en_3 = 'We must take care of the earth for future generations.', example_ko_3 = '미래 세대를 위해 지구를 돌봐야 해요.', example_en_4 = 'The earth orbits around the sun once a year.', example_ko_4 = '지구는 일 년에 한 번 태양 주위를 공전해요.', example_en_5 = 'Astronauts can see the whole earth from space.', example_ko_5 = '우주비행사들은 우주에서 지구 전체를 볼 수 있어요.' WHERE id = 'w_environment_A1_07';
UPDATE words SET example_en_2 = 'Eating more green vegetables is good for your health.', example_ko_2 = '녹색 채소를 더 많이 먹는 것은 건강에 좋아요.', example_en_3 = 'The hills were covered in green grass after the rain.', example_ko_3 = '비가 온 후 언덕은 녹색 풀로 덮였어요.', example_en_4 = 'She painted the garden wall green to match the plants.', example_ko_4 = '그녀는 식물과 어울리도록 정원 담장을 녹색으로 칠했어요.', example_en_5 = 'Going green means making choices that help the environment.', example_ko_5 = '친환경적으로 산다는 것은 환경에 도움이 되는 선택을 한다는 뜻이에요.' WHERE id = 'w_environment_A1_08';
UPDATE words SET example_en_2 = 'I water my plant every two days so it stays healthy.', example_ko_2 = '식물이 건강하게 자라도록 이틀에 한 번씩 물을 줘요.', example_en_3 = 'This plant needs a lot of sunlight to grow well.', example_ko_3 = '이 식물은 잘 자라려면 햇빛이 많이 필요해요.', example_en_4 = 'A plant makes its own food from sunlight and water.', example_ko_4 = '식물은 햇빛과 물로 스스로 먹이를 만들어요.', example_en_5 = 'Even a small plant can brighten up a room.', example_ko_5 = '작은 식물 하나도 방을 밝게 해줄 수 있어요.' WHERE id = 'w_environment_A1_09';
UPDATE words SET example_en_2 = 'My favourite animal is the dolphin because it is so clever.', example_ko_2 = '제가 가장 좋아하는 동물은 돌고래인데, 정말 영리하기 때문이에요.', example_en_3 = 'Every animal needs food, water, and shelter to survive.', example_ko_3 = '모든 동물은 살아남기 위해 먹이, 물, 그리고 피신처가 필요해요.', example_en_4 = 'We must not disturb wild animals in their natural habitat.', example_ko_4 = '야생 동물들의 자연 서식지에서 그들을 방해해서는 안 돼요.', example_en_5 = 'The zoo helps to protect endangered animals from extinction.', example_ko_5 = '동물원은 멸종 위기에 처한 동물들을 보호하는 데 도움을 줘요.' WHERE id = 'w_environment_A1_10';
UPDATE words SET example_en_2 = 'She picked a flower from the garden for her mother.', example_ko_2 = '그녀는 어머니를 위해 정원에서 꽃을 한 송이 꺾었어요.', example_en_3 = 'Bees collect nectar from flowers to make honey.', example_ko_3 = '벌들은 꿀을 만들기 위해 꽃에서 꿀을 모아요.', example_en_4 = 'These flowers only bloom in spring.', example_ko_4 = '이 꽃들은 봄에만 피어요.', example_en_5 = 'The park is full of colourful flowers in the summer.', example_ko_5 = '여름이 되면 공원은 알록달록한 꽃으로 가득 차요.' WHERE id = 'w_environment_A1_11';
UPDATE words SET example_en_2 = 'The sky turned orange and pink at sunset.', example_ko_2 = '일몰 때 하늘이 주황색과 분홍색으로 물들었어요.', example_en_3 = 'There was not a single cloud in the sky this morning.', example_ko_3 = '오늘 아침에는 하늘에 구름 한 점도 없었어요.', example_en_4 = 'Birds fly high in the sky searching for food.', example_ko_4 = '새들은 먹이를 찾아 하늘 높이 날아요.', example_en_5 = 'You can see millions of stars in the sky on a clear night.', example_ko_5 = '맑은 밤에는 하늘에서 수백만 개의 별을 볼 수 있어요.' WHERE id = 'w_environment_A1_12';
UPDATE words SET example_en_2 = 'The rain made the garden smell fresh and earthy.', example_ko_2 = '비가 내린 후 정원에서 신선하고 흙냄새가 났어요.', example_en_3 = 'Don''t forget to take an umbrella; it might rain today.', example_ko_3 = '오늘 비가 올 수도 있으니 우산을 가져가는 것을 잊지 마세요.', example_en_4 = 'Heavy rain flooded the streets in the city centre.', example_ko_4 = '폭우로 도심 거리가 침수되었어요.', example_en_5 = 'Rain is essential for plants and crops to grow.', example_ko_5 = '비는 식물과 농작물이 자라는 데 꼭 필요해요.' WHERE id = 'w_environment_A1_13';
UPDATE words SET example_en_2 = 'The snow covered the mountains in a white blanket.', example_ko_2 = '눈이 산을 하얀 이불처럼 덮었어요.', example_en_3 = 'Children love to play in the snow during winter.', example_ko_3 = '아이들은 겨울에 눈 속에서 노는 것을 좋아해요.', example_en_4 = 'The snow melted quickly when the temperature rose.', example_ko_4 = '기온이 오르자 눈이 빠르게 녹았어요.', example_en_5 = 'Too much snow can make driving very dangerous.', example_ko_5 = '눈이 너무 많이 오면 운전이 매우 위험해질 수 있어요.' WHERE id = 'w_environment_A1_14';
UPDATE words SET example_en_2 = 'The children sat on a big rock beside the river.', example_ko_2 = '아이들은 강가의 큰 바위 위에 앉았어요.', example_en_3 = 'The rock was covered in green moss from the damp air.', example_ko_3 = '그 바위는 습한 공기 때문에 녹색 이끼로 덮여 있었어요.', example_en_4 = 'Scientists study layers of rock to learn about Earth''s history.', example_ko_4 = '과학자들은 지구의 역사를 알아내기 위해 암석층을 연구해요.', example_en_5 = 'We skipped rocks across the surface of the lake.', example_ko_5 = '우리는 호수 표면에 돌멩이를 던지며 물수제비를 뜨었어요.' WHERE id = 'w_environment_A1_15';
UPDATE words SET example_en_2 = 'The sea is home to thousands of different species of fish.', example_ko_2 = '바다는 수천 종의 다양한 물고기가 사는 곳이에요.', example_en_3 = 'Rising temperatures are causing serious damage to the sea.', example_ko_3 = '기온 상승으로 바다가 심각한 피해를 입고 있어요.', example_en_4 = 'The sea looked calm and beautiful in the early morning light.', example_ko_4 = '이른 아침 햇빛 아래 바다는 잔잔하고 아름다웠어요.', example_en_5 = 'Plastic waste is one of the biggest threats to the sea.', example_ko_5 = '플라스틱 폐기물은 바다에 대한 가장 큰 위협 중 하나예요.' WHERE id = 'w_environment_A1_16';
UPDATE words SET example_en_2 = 'We watched the fish swim in the clear water of the stream.', example_ko_2 = '우리는 맑은 개울물 속을 헤엄치는 물고기를 바라보았어요.', example_en_3 = 'Salmon swim upstream to lay their eggs every year.', example_ko_3 = '연어는 매년 알을 낳기 위해 강 상류로 거슬러 올라가요.', example_en_4 = 'Overfishing is a serious problem in many parts of the ocean.', example_ko_4 = '남획은 바다 많은 지역에서 심각한 문제예요.', example_en_5 = 'The fish in this lake have been affected by water pollution.', example_ko_5 = '이 호수의 물고기들은 수질 오염의 영향을 받았어요.' WHERE id = 'w_environment_A1_17';
UPDATE words SET example_en_2 = 'The bird sang a beautiful song from the top of the tree.', example_ko_2 = '새가 나무 꼭대기에서 아름다운 노래를 불렀어요.', example_en_3 = 'Many birds migrate south for the winter every year.', example_ko_3 = '많은 새들이 매년 겨울을 나기 위해 남쪽으로 이동해요.', example_en_4 = 'The loss of trees reduces the habitat available for birds.', example_ko_4 = '나무가 줄어들면 새들이 살 수 있는 서식지도 줄어들어요.', example_en_5 = 'We put up a bird feeder in our garden to help local wildlife.', example_ko_5 = '우리는 지역 야생동물을 돕기 위해 정원에 새 모이통을 설치했어요.' WHERE id = 'w_environment_A1_18';
UPDATE words SET example_en_2 = 'A single leaf fell from the tree and landed in the pond.', example_ko_2 = '나뭇잎 한 장이 나무에서 떨어져 연못에 내려앉았어요.', example_en_3 = 'The leaves of the trees turn red and orange in autumn.', example_ko_3 = '가을이 되면 나무의 잎들이 빨간색과 주황색으로 변해요.', example_en_4 = 'Fallen leaves can be composted to make natural fertiliser.', example_ko_4 = '낙엽을 퇴비로 만들어 천연 비료로 사용할 수 있어요.', example_en_5 = 'The leaf was so delicate that I could see through it.', example_ko_5 = '그 잎사귀는 너무 얇아서 비쳐 보일 정도였어요.' WHERE id = 'w_environment_A1_19';
UPDATE words SET example_en_2 = 'The sheep grazed on the green grass in the field.', example_ko_2 = '양들이 들판의 푸른 풀을 뜯어 먹었어요.', example_en_3 = 'Walking barefoot on the grass feels wonderful.', example_ko_3 = '잔디 위를 맨발로 걷는 것은 정말 기분 좋아요.', example_en_4 = 'The gardener cut the grass short before the summer party.', example_ko_4 = '정원사는 여름 파티 전에 잔디를 짧게 깎았어요.', example_en_5 = 'Grass and other plants release oxygen into the air.', example_ko_5 = '잔디와 다른 식물들은 공기 중으로 산소를 방출해요.' WHERE id = 'w_environment_A1_20';
UPDATE words SET example_en_2 = 'The wind carried the seeds of the dandelion far away.', example_ko_2 = '바람이 민들레 씨앗을 멀리 날려 보냈어요.', example_en_3 = 'A strong wind blew the leaves off the trees in the park.', example_ko_3 = '강한 바람이 공원의 나무에서 잎들을 날려 보냈어요.', example_en_4 = 'Wind turbines convert the energy of the wind into electricity.', example_ko_4 = '풍력 터빈은 바람의 에너지를 전기로 변환해요.', example_en_5 = 'The wind felt cool and refreshing on such a hot day.', example_ko_5 = '이렇게 더운 날에는 바람이 시원하고 상쾌하게 느껴져요.' WHERE id = 'w_environment_A1_21';
UPDATE words SET example_en_2 = 'Fire requires oxygen, fuel, and heat to keep burning.', example_ko_2 = '불이 계속 타려면 산소, 연료, 열이 필요해요.', example_en_3 = 'Wildfires can destroy thousands of hectares of forest in days.', example_ko_3 = '산불은 며칠 만에 수천 헥타르의 숲을 태워 버릴 수 있어요.', example_en_4 = 'Never leave a fire unattended when you are camping outdoors.', example_ko_4 = '야외에서 캠핑할 때 불을 절대 방치하지 마세요.', example_en_5 = 'The campfire gave us warmth and light on the cold night.', example_ko_5 = '모닥불은 추운 밤에 우리에게 온기와 불빛을 주었어요.' WHERE id = 'w_environment_A1_22';
UPDATE words SET example_en_2 = 'Fine sand feels soft and warm under your feet at the beach.', example_ko_2 = '해변에서 고운 모래는 발아래서 부드럽고 따뜻하게 느껴져요.', example_en_3 = 'The desert is mostly made of sand and rocks.', example_ko_3 = '사막은 대부분 모래와 바위로 이루어져 있어요.', example_en_4 = 'The children built sandcastles on the beach all afternoon.', example_ko_4 = '아이들은 오후 내내 해변에서 모래성을 쌓았어요.', example_en_5 = 'Sand dunes are formed when wind blows sand into piles.', example_ko_5 = '모래 언덕은 바람이 모래를 쌓아 올릴 때 형성돼요.' WHERE id = 'w_environment_A1_23';
UPDATE words SET example_en_2 = 'The lake was perfectly still and reflected the mountains.', example_ko_2 = '호수는 완전히 잔잔하여 산을 그대로 비추고 있었어요.', example_en_3 = 'We went rowing on the lake on Sunday afternoon.', example_ko_3 = '우리는 일요일 오후에 호수에서 노를 저었어요.', example_en_4 = 'Pollution from farms can make lake water unsafe to drink.', example_ko_4 = '농장에서 나오는 오염물질이 호수 물을 마시기에 안전하지 않게 만들 수 있어요.', example_en_5 = 'The lake freezes over in winter and children skate on it.', example_ko_5 = '호수는 겨울에 얼고 아이들은 그 위에서 스케이트를 타요.' WHERE id = 'w_environment_A1_24';
UPDATE words SET example_en_2 = 'Climbing the mountain took us about four hours each way.', example_ko_2 = '산을 오르는 데 왕복 각각 약 네 시간이 걸렸어요.', example_en_3 = 'Many rare plants and animals live on the mountain.', example_ko_3 = '많은 희귀 식물과 동물들이 산에 살고 있어요.', example_en_4 = 'The mountain peak was covered in snow all year round.', example_ko_4 = '산 정상은 일 년 내내 눈으로 덮여 있었어요.', example_en_5 = 'The view from the top of the mountain was absolutely breathtaking.', example_ko_5 = '산 정상에서 바라본 경치는 정말 숨이 막힐 정도로 아름다웠어요.' WHERE id = 'w_environment_A1_25';
UPDATE words SET example_en_2 = 'Dark clouds gathered in the sky before the storm.', example_ko_2 = '폭풍이 오기 전에 하늘에 먹구름이 모였어요.', example_en_3 = 'The clouds blocked out the sun and made the day cooler.', example_ko_3 = '구름이 태양을 가려 날씨가 서늘해졌어요.', example_en_4 = 'I love watching clouds change shape as they move across the sky.', example_ko_4 = '구름이 하늘을 가로질러 이동하며 모양이 바뀌는 것을 바라보는 것을 좋아해요.', example_en_5 = 'High clouds often mean that rain is on the way.', example_ko_5 = '높은 구름이 끼면 곧 비가 올 것이라는 신호인 경우가 많아요.' WHERE id = 'w_environment_A1_26';
UPDATE words SET example_en_2 = 'Sunlight gives us warmth and light energy every day.', example_ko_2 = '햇빛은 우리에게 매일 온기와 빛 에너지를 주어요.', example_en_3 = 'The light from the lamp was not bright enough to read by.', example_ko_3 = '램프의 빛이 책을 읽기에 충분히 밝지 않았어요.', example_en_4 = 'Turn off the lights when you leave a room to save energy.', example_ko_4 = '에너지를 절약하기 위해 방에서 나올 때 불을 끄세요.', example_en_5 = 'LED lights use much less energy than traditional bulbs.', example_ko_5 = 'LED 조명은 기존 전구보다 훨씬 적은 에너지를 사용해요.' WHERE id = 'w_environment_A1_27';
UPDATE words SET example_en_2 = 'The forest was dark and mysterious at night.', example_ko_2 = '밤에 숲은 어둡고 신비로웠어요.', example_en_3 = 'It gets dark very early in winter in northern countries.', example_ko_3 = '북쪽 나라들은 겨울에 매우 일찍 어두워져요.', example_en_4 = 'Switch on the light so we can see in the dark room.', example_ko_4 = '어두운 방에서 볼 수 있도록 불을 켜 주세요.', example_en_5 = 'Pollution from city lights makes the sky too dark to see stars.', example_ko_5 = '도시의 빛 공해로 하늘이 너무 밝아 별을 보기 어려워요.' WHERE id = 'w_environment_A1_28';
UPDATE words SET example_en_2 = 'It was so hot that we stayed in the shade all afternoon.', example_ko_2 = '너무 더워서 우리는 오후 내내 그늘에 있었어요.', example_en_3 = 'Hot weather can be dangerous for elderly people and children.', example_ko_3 = '더운 날씨는 노인과 어린이에게 위험할 수 있어요.', example_en_4 = 'The desert is extremely hot during the day and cold at night.', example_ko_4 = '사막은 낮에는 매우 덥고 밤에는 추워요.', example_en_5 = 'Climate change is making heatwaves more frequent and intense.', example_ko_5 = '기후 변화로 폭염이 더 자주, 더 강하게 발생하고 있어요.' WHERE id = 'w_environment_A1_29';
UPDATE words SET example_en_2 = 'The cold wind came down from the mountains in the evening.', example_ko_2 = '저녁에 산에서 차가운 바람이 불어 내려왔어요.', example_en_3 = 'Cold weather causes rivers and lakes to freeze over.', example_ko_3 = '추운 날씨로 강과 호수가 얼어붙어요.', example_en_4 = 'Polar bears are adapted to survive in cold environments.', example_ko_4 = '북극곰은 추운 환경에서 생존할 수 있도록 적응되어 있어요.', example_en_5 = 'Drinking cold water is refreshing on a very hot day.', example_ko_5 = '매우 더운 날에 차가운 물을 마시면 기분이 상쾌해져요.' WHERE id = 'w_environment_A1_30';
UPDATE words SET example_en_2 = 'Seeds need good soil and sunlight to grow out of the ground.', example_ko_2 = '씨앗이 땅 위로 자라려면 좋은 흙과 햇빛이 필요해요.', example_en_3 = 'The earthquake shook the ground and caused buildings to crack.', example_ko_3 = '지진이 땅을 흔들어 건물에 균열이 생겼어요.', example_en_4 = 'Fallen leaves decompose and return nutrients to the ground.', example_ko_4 = '낙엽은 분해되어 영양분을 땅으로 되돌려 보내요.', example_en_5 = 'The ground was frozen solid during the long winter months.', example_ko_5 = '긴 겨울 동안 땅이 꽁꽁 얼어 있었어요.' WHERE id = 'w_environment_A1_31';
UPDATE words SET example_en_2 = 'The river flows from the mountains down to the sea.', example_ko_2 = '강은 산에서 바다로 흘러 내려가요.', example_en_3 = 'Many towns were built near rivers for easy access to water.', example_ko_3 = '많은 마을이 물을 쉽게 구하기 위해 강 근처에 세워졌어요.', example_en_4 = 'Industrial waste has polluted the river and harmed wildlife.', example_ko_4 = '산업 폐기물이 강을 오염시키고 야생동물에게 해를 끼쳤어요.', example_en_5 = 'We spent the afternoon fishing by the river with our family.', example_ko_5 = '우리는 가족과 함께 강가에서 오후 내내 낚시를 했어요.' WHERE id = 'w_environment_A1_32';
UPDATE words SET example_en_2 = 'The forest is home to deer, foxes, and many kinds of birds.', example_ko_2 = '숲에는 사슴, 여우, 그리고 다양한 종류의 새들이 살아요.', example_en_3 = 'Deforestation is destroying large areas of the world''s forests.', example_ko_3 = '삼림 벌채로 전 세계 숲의 넓은 지역이 파괴되고 있어요.', example_en_4 = 'Walking through the forest in the morning is very peaceful.', example_ko_4 = '아침에 숲속을 걷는 것은 매우 평화로워요.', example_en_5 = 'Forests help to regulate the climate by absorbing carbon dioxide.', example_ko_5 = '숲은 이산화탄소를 흡수해 기후 조절을 도와요.' WHERE id = 'w_environment_A1_33';
UPDATE words SET example_en_2 = 'Rich soil contains many nutrients that help plants to grow.', example_ko_2 = '비옥한 흙에는 식물이 자라는 데 도움이 되는 영양분이 많이 들어 있어요.', example_en_3 = 'Using too many chemicals can damage the soil over time.', example_ko_3 = '화학물질을 너무 많이 사용하면 시간이 지나면서 토양이 손상될 수 있어요.', example_en_4 = 'Composting kitchen waste helps to improve the quality of soil.', example_ko_4 = '음식물 쓰레기를 퇴비로 만들면 토양의 질을 개선하는 데 도움이 돼요.', example_en_5 = 'Healthy soil is essential for growing the food we eat.', example_ko_5 = '건강한 토양은 우리가 먹는 식물을 재배하는 데 꼭 필요해요.' WHERE id = 'w_environment_A1_34';
UPDATE words SET example_en_2 = 'The ground became wet and muddy after the heavy rain.', example_ko_2 = '폭우 후 땅이 젖어 진흙탕이 되었어요.', example_en_3 = 'My shoes got wet because I walked through a puddle.', example_ko_3 = '웅덩이를 걸어 지나가는 바람에 신발이 젖었어요.', example_en_4 = 'Wet weather is good for the garden but makes commuting difficult.', example_ko_4 = '젖은 날씨는 정원에는 좋지만 출퇴근을 어렵게 만들어요.', example_en_5 = 'The wet forest floor was covered in fallen leaves and mushrooms.', example_ko_5 = '젖은 숲 바닥은 낙엽과 버섯으로 뒤덮여 있었어요.' WHERE id = 'w_environment_A1_35';

