UPDATE words SET example_en_2 = 'She consistently outperforms expectations at major tournaments.', example_ko_2 = '그녀는 주요 토너먼트에서 기대를 지속적으로 뛰어넘어요.', example_en_3 = 'He outperformed every rival in the speed trials.', example_ko_3 = '그는 속도 시험에서 모든 라이벌을 능가했어요.', example_en_4 = 'Smaller teams can outperform bigger rivals with the right tactics.', example_ko_4 = '작은 팀이 올바른 전술로 더 큰 라이벌을 능가할 수 있어요.', example_en_5 = 'She outperformed herself in every race this season.', example_ko_5 = '그녀는 이번 시즌 모든 경주에서 자신의 기록을 뛰어넘었어요.' WHERE id = 'w_sports_B1_32';
