UPDATE words SET example_en_2 = 'The server was down for two hours this morning.', example_ko_2 = '오늘 아침 두 시간 동안 서버가 다운됐어요.', example_en_3 = 'All your data is stored on a secure server.', example_ko_3 = '모든 데이터는 안전한 서버에 저장되어 있어요.', example_en_4 = 'The company runs its own server instead of using the cloud.', example_ko_4 = '회사는 클라우드 대신 자체 서버를 운영해요.', example_en_5 = 'A dedicated server improves performance for high-traffic websites.', example_ko_5 = '전용 서버는 트래픽이 많은 웹사이트의 성능을 향상시켜요.' WHERE id = 'w_technology_B1_04';
