UPDATE words SET example_en_2 = 'Artificial intelligence is being used to improve medical diagnosis.', example_ko_2 = '인공지능이 의료 진단 향상에 활용되고 있어요.', example_en_3 = 'The company invested heavily in artificial intelligence research.', example_ko_3 = '회사는 인공지능 연구에 많은 투자를 했어요.', example_en_4 = 'Artificial intelligence can process vast amounts of data in seconds.', example_ko_4 = '인공지능은 수초 안에 방대한 양의 데이터를 처리할 수 있어요.', example_en_5 = 'There are serious ethical concerns about the use of artificial intelligence in hiring.', example_ko_5 = '채용 과정에서의 인공지능 활용에 대한 심각한 윤리적 우려가 있어요.' WHERE id = 'w_technology_B2_01';
