UPDATE words SET example_en_2 = 'Generative AI can create images, text, and music from a simple prompt.', example_ko_2 = '생성형 AI는 간단한 프롬프트로 이미지, 텍스트, 음악을 만들 수 있어요.', example_en_3 = 'She uses generative AI to speed up her creative workflow.', example_ko_3 = '그녀는 창작 워크플로우를 빠르게 하기 위해 생성형 AI를 활용해요.', example_en_4 = 'There are growing concerns about copyright and generative AI.', example_ko_4 = '생성형 AI와 저작권에 대한 우려가 커지고 있어요.', example_en_5 = 'Generative AI is transforming industries from marketing to software development.', example_ko_5 = '생성형 AI는 마케팅부터 소프트웨어 개발까지 여러 산업을 변화시키고 있어요.' WHERE id = 'w_technology_B2_19';
UPDATE words SET example_en_2 = 'A large language model learns by processing vast amounts of text data.', example_ko_2 = '대형 언어 모델은 방대한 텍스트 데이터를 처리해서 학습해요.', example_en_3 = 'The large language model can answer complex questions in multiple languages.', example_ko_3 = '대형 언어 모델은 여러 언어로 복잡한 질문에 답할 수 있어요.', example_en_4 = 'Researchers are studying how large language models represent knowledge.', example_ko_4 = '연구자들은 대형 언어 모델이 지식을 어떻게 표현하는지 연구하고 있어요.', example_en_5 = 'She explained the difference between a large language model and a search engine.', example_ko_5 = '그녀는 대형 언어 모델과 검색 엔진의 차이점을 설명했어요.' WHERE id = 'w_technology_B2_20';
UPDATE words SET example_en_2 = 'Edge AI allows devices to process data without sending it to the cloud.', example_ko_2 = '엣지 AI는 기기가 클라우드에 데이터를 보내지 않고 처리할 수 있게 해줘요.', example_en_3 = 'Edge AI is important for applications that require real-time responses.', example_ko_3 = '엣지 AI는 실시간 응답이 필요한 애플리케이션에 중요해요.', example_en_4 = 'She developed an edge AI system for smart traffic management.', example_ko_4 = '그녀는 스마트 교통 관리를 위한 엣지 AI 시스템을 개발했어요.', example_en_5 = 'Edge AI reduces latency and improves privacy by keeping data local.', example_ko_5 = '엣지 AI는 데이터를 로컬에 유지해서 레이턴시를 줄이고 개인정보 보호를 향상시켜요.' WHERE id = 'w_technology_B2_21';
UPDATE words SET example_en_2 = 'The semiconductor shortage caused delays in car production worldwide.', example_ko_2 = '반도체 부족으로 전 세계 자동차 생산이 지연됐어요.', example_en_3 = 'She works at a semiconductor company designing chips.', example_ko_3 = '그녀는 반도체 회사에서 칩을 설계하는 일을 해요.', example_en_4 = 'Advances in semiconductor technology have driven the digital revolution.', example_ko_4 = '반도체 기술의 발전이 디지털 혁명을 이끌었어요.', example_en_5 = 'The country invested heavily in domestic semiconductor manufacturing.', example_ko_5 = '해당 국가는 국내 반도체 제조에 막대한 투자를 했어요.' WHERE id = 'w_technology_B2_22';
UPDATE words SET example_en_2 = 'The model runs inference in less than a second.', example_ko_2 = '모델이 1초도 안 되는 시간에 추론을 실행해요.', example_en_3 = 'Inference speed is critical for real-time applications.', example_ko_3 = '실시간 애플리케이션에서 추론 속도는 매우 중요해요.', example_en_4 = 'She optimised the model to reduce inference costs.', example_ko_4 = '그녀는 추론 비용을 줄이기 위해 모델을 최적화했어요.', example_en_5 = 'Running inference on edge devices requires compact and efficient models.', example_ko_5 = '엣지 기기에서 추론을 실행하려면 소형의 효율적인 모델이 필요해요.' WHERE id = 'w_technology_B2_23';
UPDATE words SET example_en_2 = 'Fine-tuning the model on domain-specific data improved its accuracy significantly.', example_ko_2 = '도메인별 데이터로 모델을 파인튜닝하자 정확도가 크게 향상됐어요.', example_en_3 = 'She used fine-tuning to adapt a general model for customer service tasks.', example_ko_3 = '그녀는 파인튜닝을 사용해서 범용 모델을 고객 서비스 업무에 맞게 조정했어요.', example_en_4 = 'Fine-tuning requires far less data than training a model from scratch.', example_ko_4 = '파인튜닝은 모델을 처음부터 훈련하는 것보다 훨씬 적은 데이터가 필요해요.', example_en_5 = 'The team debated whether to fine-tune the model or use prompt engineering instead.', example_ko_5 = '팀은 모델을 파인튜닝할지 아니면 프롬프트 엔지니어링을 사용할지 논의했어요.' WHERE id = 'w_technology_B2_24';
UPDATE words SET example_en_2 = 'Higher throughput means the system can handle more requests at once.', example_ko_2 = '처리량이 높을수록 시스템이 더 많은 요청을 동시에 처리할 수 있어요.', example_en_3 = 'The engineering team worked to double the system''s throughput.', example_ko_3 = '엔지니어링 팀은 시스템의 처리량을 두 배로 늘리기 위해 노력했어요.', example_en_4 = 'Throughput and latency are related but distinct performance metrics.', example_ko_4 = '처리량과 레이턴시는 관련이 있지만 서로 다른 성능 지표예요.', example_en_5 = 'She measured the throughput of the pipeline before and after optimisation.', example_ko_5 = '그녀는 최적화 전후의 파이프라인 처리량을 측정했어요.' WHERE id = 'w_technology_B2_25';
UPDATE words SET example_en_2 = 'She packaged the application as a container for easier deployment.', example_ko_2 = '그녀는 더 쉬운 배포를 위해 애플리케이션을 컨테이너로 패키징했어요.', example_en_3 = 'Containers allow you to run applications consistently across different environments.', example_ko_3 = '컨테이너를 사용하면 서로 다른 환경에서 일관되게 애플리케이션을 실행할 수 있어요.', example_en_4 = 'Docker is the most popular tool for managing containers.', example_ko_4 = 'Docker는 컨테이너를 관리하는 가장 인기 있는 도구예요.', example_en_5 = 'The team moved from virtual machines to containers to reduce overhead.', example_ko_5 = '팀은 오버헤드를 줄이기 위해 가상 머신에서 컨테이너로 이전했어요.' WHERE id = 'w_technology_B2_26';
UPDATE words SET example_en_2 = 'The app is built using a microservices architecture.', example_ko_2 = '이 앱은 마이크로서비스 아키텍처를 사용해서 구축됐어요.', example_en_3 = 'With microservices, each part of the system can be updated independently.', example_ko_3 = '마이크로서비스를 사용하면 시스템의 각 부분을 독립적으로 업데이트할 수 있어요.', example_en_4 = 'Moving to microservices improved the team''s ability to deploy quickly.', example_ko_4 = '마이크로서비스로 전환하여 팀의 빠른 배포 능력이 향상됐어요.', example_en_5 = 'Microservices come with their own challenges, such as managing communication between services.', example_ko_5 = '마이크로서비스는 서비스 간 통신 관리와 같은 고유한 과제도 가지고 있어요.' WHERE id = 'w_technology_B2_27';
UPDATE words SET example_en_2 = 'DevOps practices help teams release software faster and more reliably.', example_ko_2 = 'DevOps 관행은 팀이 소프트웨어를 더 빠르고 안정적으로 출시하도록 도와줘요.', example_en_3 = 'She moved into a DevOps role after years as a developer.', example_ko_3 = '그녀는 개발자로 수년을 보낸 후 DevOps 역할로 이동했어요.', example_en_4 = 'DevOps bridges the gap between software development and IT operations.', example_ko_4 = 'DevOps는 소프트웨어 개발과 IT 운영 사이의 간극을 줄여줘요.', example_en_5 = 'Implementing a DevOps culture requires significant changes to how teams work.', example_ko_5 = 'DevOps 문화를 도입하려면 팀의 업무 방식에 상당한 변화가 필요해요.' WHERE id = 'w_technology_B2_28';
UPDATE words SET example_en_2 = 'Tokenization breaks text into smaller units for the model to process.', example_ko_2 = '토크나이제이션은 모델이 처리할 수 있도록 텍스트를 더 작은 단위로 분해해요.', example_en_3 = 'She studied how different tokenization strategies affect model performance.', example_ko_3 = '그녀는 서로 다른 토크나이제이션 전략이 모델 성능에 어떤 영향을 미치는지 연구했어요.', example_en_4 = 'Tokenization of payment data reduces the risk of sensitive information being stolen.', example_ko_4 = '결제 데이터의 토크나이제이션은 민감한 정보가 도난당할 위험을 줄여요.', example_en_5 = 'The number of tokens in a prompt affects how much it costs to run the model.', example_ko_5 = '프롬프트의 토큰 수는 모델 실행 비용에 영향을 미쳐요.' WHERE id = 'w_technology_B2_29';
UPDATE words SET example_en_2 = 'The company adopted a zero-trust policy after a security breach.', example_ko_2 = '회사는 보안 침해 이후 제로 트러스트 정책을 도입했어요.', example_en_3 = 'Zero-trust means every access request must be verified, even from inside the network.', example_ko_3 = '제로 트러스트는 네트워크 내부에서도 모든 접근 요청을 검증해야 함을 의미해요.', example_en_4 = 'She implemented zero-trust architecture to protect sensitive customer data.', example_ko_4 = '그녀는 민감한 고객 데이터를 보호하기 위해 제로 트러스트 아키텍처를 구현했어요.', example_en_5 = 'Zero-trust security is becoming the standard for large enterprises.', example_ko_5 = '제로 트러스트 보안은 대기업의 표준이 되어가고 있어요.' WHERE id = 'w_technology_B2_30';
UPDATE words SET example_en_2 = 'Tuning hyperparameters is often the most time-consuming part of model development.', example_ko_2 = '하이퍼파라미터 튜닝은 종종 모델 개발에서 가장 시간이 많이 걸리는 부분이에요.', example_en_3 = 'She used automated tools to search for the best hyperparameter settings.', example_ko_3 = '그녀는 최적의 하이퍼파라미터 설정을 찾기 위해 자동화 도구를 사용했어요.', example_en_4 = 'The learning rate is one of the most critical hyperparameters to get right.', example_ko_4 = '학습률은 올바르게 설정해야 하는 가장 중요한 하이퍼파라미터 중 하나예요.', example_en_5 = 'Changing one hyperparameter can have a large effect on the model''s behaviour.', example_ko_5 = '하이퍼파라미터 하나를 변경하면 모델의 동작에 큰 영향을 미칠 수 있어요.' WHERE id = 'w_technology_B2_31';
UPDATE words SET example_en_2 = 'The multimodal AI can understand both images and text in a single prompt.', example_ko_2 = '멀티모달 AI는 하나의 프롬프트에서 이미지와 텍스트를 모두 이해할 수 있어요.', example_en_3 = 'She is building a multimodal AI system for accessibility applications.', example_ko_3 = '그녀는 접근성 애플리케이션을 위한 멀티모달 AI 시스템을 구축하고 있어요.', example_en_4 = 'Multimodal AI models can describe what''s happening in a photo.', example_ko_4 = '멀티모달 AI 모델은 사진에서 무슨 일이 일어나고 있는지 설명할 수 있어요.', example_en_5 = 'The shift toward multimodal AI represents a major step forward.', example_ko_5 = '멀티모달 AI로의 전환은 큰 진전을 의미해요.' WHERE id = 'w_technology_B2_32';
UPDATE words SET example_en_2 = 'Data sovereignty laws require that data be stored within national borders.', example_ko_2 = '데이터 주권법은 데이터를 국경 내에 저장하도록 요구해요.', example_en_3 = 'She advises companies on compliance with data sovereignty regulations.', example_ko_3 = '그녀는 데이터 주권 규정 준수에 관해 기업들에게 자문을 제공해요.', example_en_4 = 'Data sovereignty is an increasingly important issue in international business.', example_ko_4 = '데이터 주권은 국제 비즈니스에서 점점 더 중요한 문제가 되고 있어요.', example_en_5 = 'Cloud providers must navigate complex data sovereignty requirements across countries.', example_ko_5 = '클라우드 제공업체는 국가마다 복잡한 데이터 주권 요건을 준수해야 해요.' WHERE id = 'w_technology_B2_33';
UPDATE words SET example_en_2 = 'Improving algorithm efficiency can reduce both cost and energy consumption.', example_ko_2 = '알고리즘 효율성을 향상시키면 비용과 에너지 소비를 모두 줄일 수 있어요.', example_en_3 = 'She published research on algorithm efficiency in sorting large datasets.', example_ko_3 = '그녀는 대규모 데이터 세트 정렬에서의 알고리즘 효율성에 관한 연구를 발표했어요.', example_en_4 = 'Algorithm efficiency is measured in terms of time and space complexity.', example_ko_4 = '알고리즘 효율성은 시간 복잡도와 공간 복잡도로 측정해요.', example_en_5 = 'A small improvement in algorithm efficiency can make a huge difference at scale.', example_ko_5 = '알고리즘 효율성의 소폭 개선이 대규모에서는 큰 차이를 만들 수 있어요.' WHERE id = 'w_technology_B2_34';
UPDATE words SET example_en_2 = 'Synthetic data is used to train models when real data is scarce.', example_ko_2 = '합성 데이터는 실제 데이터가 부족할 때 모델 훈련에 사용돼요.', example_en_3 = 'She generated synthetic data to augment the training set.', example_ko_3 = '그녀는 훈련 세트를 보강하기 위해 합성 데이터를 생성했어요.', example_en_4 = 'Synthetic data can help protect privacy by replacing real personal information.', example_ko_4 = '합성 데이터는 실제 개인 정보를 대체해서 개인정보 보호에 도움이 될 수 있어요.', example_en_5 = 'The quality of synthetic data heavily affects the model''s real-world performance.', example_ko_5 = '합성 데이터의 품질은 모델의 실제 성능에 큰 영향을 미쳐요.' WHERE id = 'w_technology_B2_35';

-- C1 words

UPDATE words SET example_en_2 = 'Quantum computing could solve problems that are impossible for classical computers.', example_ko_2 = '양자 컴퓨팅은 고전 컴퓨터로는 불가능한 문제들을 해결할 수 있어요.', example_en_3 = 'She researches quantum computing at a leading university.', example_ko_3 = '그녀는 유명 대학에서 양자 컴퓨팅을 연구해요.', example_en_4 = 'Quantum computing poses a significant threat to current encryption methods.', example_ko_4 = '양자 컴퓨팅은 현재의 암호화 방법에 심각한 위협을 제기해요.', example_en_5 = 'The race to build a practical quantum computer is intensifying.', example_ko_5 = '실용적인 양자 컴퓨터를 개발하려는 경쟁이 치열해지고 있어요.' WHERE id = 'w_technology_C1_01';
UPDATE words SET example_en_2 = 'Edge computing moves data processing closer to where it is generated.', example_ko_2 = '엣지 컴퓨팅은 데이터 처리를 데이터가 생성되는 곳에 더 가까이 이동시켜요.', example_en_3 = 'She designed an edge computing architecture for autonomous vehicles.', example_ko_3 = '그녀는 자율 주행 차량을 위한 엣지 컴퓨팅 아키텍처를 설계했어요.', example_en_4 = 'Edge computing reduces the latency that cloud-only approaches suffer from.', example_ko_4 = '엣지 컴퓨팅은 클라우드 전용 방식이 겪는 레이턴시를 줄여줘요.', example_en_5 = 'Edge computing is essential for applications that cannot tolerate delays.', example_ko_5 = '엣지 컴퓨팅은 지연을 허용할 수 없는 애플리케이션에 필수적이에요.' WHERE id = 'w_technology_C1_02';
UPDATE words SET example_en_2 = 'Cryptography underpins the security of online banking and e-commerce.', example_ko_2 = '암호학은 온라인 뱅킹과 전자상거래의 보안을 뒷받침해요.', example_en_3 = 'She specialises in applied cryptography and works for a cybersecurity firm.', example_ko_3 = '그녀는 응용 암호학을 전공하며 사이버 보안 회사에서 일해요.', example_en_4 = 'Modern cryptography relies on mathematical problems that are computationally hard to solve.', example_ko_4 = '현대 암호학은 계산적으로 풀기 어려운 수학적 문제에 의존해요.', example_en_5 = 'Without cryptography, private communication over the internet would be impossible.', example_ko_5 = '암호학이 없다면 인터넷을 통한 개인 간 통신은 불가능할 거예요.' WHERE id = 'w_technology_C1_03';
UPDATE words SET example_en_2 = 'Federated learning allows models to train on data without the data leaving users'' devices.', example_ko_2 = '연합 학습은 데이터가 사용자 기기를 벗어나지 않고도 모델을 훈련할 수 있게 해줘요.', example_en_3 = 'She published a paper on federated learning for healthcare applications.', example_ko_3 = '그녀는 의료 애플리케이션을 위한 연합 학습에 관한 논문을 발표했어요.', example_en_4 = 'Federated learning is a promising approach for privacy-preserving AI.', example_ko_4 = '연합 학습은 개인정보 보호 AI를 위한 유망한 접근 방식이에요.', example_en_5 = 'The main challenge in federated learning is handling non-uniform data distributions.', example_ko_5 = '연합 학습의 주요 과제는 불균일한 데이터 분포를 처리하는 것이에요.' WHERE id = 'w_technology_C1_04';
UPDATE words SET example_en_2 = 'Reinforcement learning trains agents to make decisions through reward and penalty.', example_ko_2 = '강화 학습은 보상과 벌칙을 통해 에이전트가 결정을 내리도록 훈련해요.', example_en_3 = 'She used reinforcement learning to optimise the routing algorithm.', example_ko_3 = '그녀는 강화 학습을 사용해서 라우팅 알고리즘을 최적화했어요.', example_en_4 = 'Reinforcement learning achieved superhuman performance in board games like Go.', example_ko_4 = '강화 학습은 바둑과 같은 보드 게임에서 인간을 초월하는 성능을 달성했어요.', example_en_5 = 'Designing the reward function is one of the hardest parts of reinforcement learning.', example_ko_5 = '보상 함수 설계는 강화 학습에서 가장 어려운 부분 중 하나예요.' WHERE id = 'w_technology_C1_05';
UPDATE words SET example_en_2 = 'The transformer model revolutionised natural language processing.', example_ko_2 = '트랜스포머 모델은 자연어 처리에 혁명을 일으켰어요.', example_en_3 = 'She wrote her thesis on attention mechanisms within the transformer model.', example_ko_3 = '그녀는 트랜스포머 모델 내 어텐션 메커니즘에 관한 논문을 썼어요.', example_en_4 = 'The transformer model''s ability to handle long-range dependencies is a key strength.', example_ko_4 = '트랜스포머 모델의 장거리 의존성 처리 능력은 핵심 강점이에요.', example_en_5 = 'Most modern large language models are based on the transformer model architecture.', example_ko_5 = '현대의 대부분의 대형 언어 모델은 트랜스포머 모델 아키텍처를 기반으로 해요.' WHERE id = 'w_technology_C1_06';
UPDATE words SET example_en_2 = 'Adversarial attacks can fool image classifiers by adding invisible noise.', example_ko_2 = '적대적 공격은 보이지 않는 노이즈를 추가해서 이미지 분류기를 속일 수 있어요.', example_en_3 = 'She researches defences against adversarial attacks on AI systems.', example_ko_3 = '그녀는 AI 시스템에 대한 적대적 공격 방어를 연구해요.', example_en_4 = 'Adversarial attacks highlight the fragility of current deep learning models.', example_ko_4 = '적대적 공격은 현재 딥러닝 모델의 취약성을 부각시켜요.', example_en_5 = 'Making AI systems robust to adversarial attacks remains an open research problem.', example_ko_5 = 'AI 시스템을 적대적 공격에 강건하게 만드는 것은 여전히 열린 연구 문제예요.' WHERE id = 'w_technology_C1_07';
UPDATE words SET example_en_2 = 'Scalability was the main concern when redesigning the system.', example_ko_2 = '시스템을 재설계할 때 확장성이 주요 관심사였어요.', example_en_3 = 'She designed the database with scalability in mind from day one.', example_ko_3 = '그녀는 처음부터 확장성을 염두에 두고 데이터베이스를 설계했어요.', example_en_4 = 'The system''s lack of scalability became apparent once the user base grew.', example_ko_4 = '사용자 기반이 커지자 시스템의 확장성 부재가 분명해졌어요.', example_en_5 = 'True scalability means performance doesn''t degrade as demand increases.', example_ko_5 = '진정한 확장성은 수요가 증가해도 성능이 저하되지 않음을 의미해요.' WHERE id = 'w_technology_C1_08';
UPDATE words SET example_en_2 = 'Differential privacy allows useful data analysis while protecting individual information.', example_ko_2 = '차등 프라이버시는 개인 정보를 보호하면서 유용한 데이터 분석을 가능하게 해요.', example_en_3 = 'She implemented differential privacy to comply with data protection regulations.', example_ko_3 = '그녀는 데이터 보호 규정을 준수하기 위해 차등 프라이버시를 구현했어요.', example_en_4 = 'Differential privacy introduces controlled noise to prevent the identification of individuals.', example_ko_4 = '차등 프라이버시는 개인 식별을 방지하기 위해 제어된 노이즈를 도입해요.', example_en_5 = 'Large tech companies use differential privacy in some of their data collection practices.', example_ko_5 = '대형 기술 기업들은 일부 데이터 수집 관행에 차등 프라이버시를 사용해요.' WHERE id = 'w_technology_C1_09';
UPDATE words SET example_en_2 = 'Model distillation compresses a large model into a smaller, faster one.', example_ko_2 = '모델 증류는 큰 모델을 더 작고 빠른 모델로 압축해요.', example_en_3 = 'She applied model distillation to make the AI deployable on mobile devices.', example_ko_3 = '그녀는 AI를 모바일 기기에 배포할 수 있도록 모델 증류를 적용했어요.', example_en_4 = 'Model distillation typically retains most of the performance of the original model.', example_ko_4 = '모델 증류는 일반적으로 원본 모델의 성능 대부분을 유지해요.', example_en_5 = 'The team used model distillation to reduce inference costs without sacrificing accuracy.', example_ko_5 = '팀은 정확도를 희생하지 않고 추론 비용을 줄이기 위해 모델 증류를 사용했어요.' WHERE id = 'w_technology_C1_10';
UPDATE words SET example_en_2 = 'The attention mechanism allows the model to focus on the most relevant parts of the input.', example_ko_2 = '어텐션 메커니즘은 모델이 입력의 가장 관련 있는 부분에 집중할 수 있게 해줘요.', example_en_3 = 'She published research explaining how the attention mechanism works in transformers.', example_ko_3 = '그녀는 트랜스포머에서 어텐션 메커니즘이 작동하는 방식을 설명하는 연구를 발표했어요.', example_en_4 = 'Without the attention mechanism, models struggled to handle long sequences.', example_ko_4 = '어텐션 메커니즘이 없으면 모델이 긴 시퀀스를 처리하는 데 어려움을 겪었어요.', example_en_5 = 'The attention mechanism is often described as the key innovation behind modern NLP.', example_ko_5 = '어텐션 메커니즘은 종종 현대 자연어 처리의 핵심 혁신으로 묘사돼요.' WHERE id = 'w_technology_C1_11';
UPDATE words SET example_en_2 = 'Zero-shot learning enables models to handle tasks they were never trained on.', example_ko_2 = '제로샷 학습은 모델이 훈련받지 않은 작업도 처리할 수 있게 해줘요.', example_en_3 = 'She tested the model''s zero-shot learning ability on a new language.', example_ko_3 = '그녀는 새로운 언어에서 모델의 제로샷 학습 능력을 테스트했어요.', example_en_4 = 'Zero-shot learning is particularly valuable when labelled data is not available.', example_ko_4 = '제로샷 학습은 레이블이 지정된 데이터를 사용할 수 없을 때 특히 유용해요.', example_en_5 = 'The model''s zero-shot performance surprised even the researchers who built it.', example_ko_5 = '모델의 제로샷 성능은 개발자들도 놀라게 했어요.' WHERE id = 'w_technology_C1_12';
UPDATE words SET example_en_2 = 'Autonomous systems can operate in unpredictable environments without human input.', example_ko_2 = '자율 시스템은 인간의 개입 없이 예측 불가능한 환경에서 작동할 수 있어요.', example_en_3 = 'She is working on safety frameworks for autonomous systems in healthcare.', example_ko_3 = '그녀는 의료 분야의 자율 시스템을 위한 안전 프레임워크를 개발하고 있어요.', example_en_4 = 'Autonomous systems raise important questions about accountability and liability.', example_ko_4 = '자율 시스템은 책임과 법적 의무에 관한 중요한 질문을 제기해요.', example_en_5 = 'The deployment of autonomous systems in warfare is a deeply controversial topic.', example_ko_5 = '전쟁에서의 자율 시스템 배치는 매우 논쟁적인 주제예요.' WHERE id = 'w_technology_C1_13';
UPDATE words SET example_en_2 = 'She has become an expert in prompt engineering for large language models.', example_ko_2 = '그녀는 대형 언어 모델을 위한 프롬프트 엔지니어링 전문가가 됐어요.', example_en_3 = 'Good prompt engineering can dramatically improve the quality of AI outputs.', example_ko_3 = '좋은 프롬프트 엔지니어링은 AI 출력물의 품질을 크게 향상시킬 수 있어요.', example_en_4 = 'Prompt engineering is an emerging skill that combines language knowledge with technical understanding.', example_ko_4 = '프롬프트 엔지니어링은 언어 지식과 기술적 이해를 결합하는 신흥 기술이에요.', example_en_5 = 'The line between prompt engineering and model fine-tuning is becoming blurry.', example_ko_5 = '프롬프트 엔지니어링과 모델 파인튜닝 사이의 경계가 모호해지고 있어요.' WHERE id = 'w_technology_C1_14';
UPDATE words SET example_en_2 = 'Hallucination is a major problem in current large language models.', example_ko_2 = '환각은 현재 대형 언어 모델의 주요 문제예요.', example_en_3 = 'The model produced a hallucination — the cited paper doesn''t exist.', example_ko_3 = '모델이 환각을 생성했어요. 인용된 논문이 존재하지 않아요.', example_en_4 = 'She is researching techniques to reduce hallucination in AI systems.', example_ko_4 = '그녀는 AI 시스템에서 환각을 줄이는 기술을 연구하고 있어요.', example_en_5 = 'Users must verify AI outputs carefully because hallucination remains a real risk.', example_ko_5 = '환각이 여전히 실제 위험이기 때문에 사용자들은 AI 출력물을 신중하게 검증해야 해요.' WHERE id = 'w_technology_C1_15';
UPDATE words SET example_en_2 = 'Retrieval-augmented generation combines search with language generation to improve accuracy.', example_ko_2 = '검색 증강 생성은 정확도를 높이기 위해 검색과 언어 생성을 결합해요.', example_en_3 = 'She implemented retrieval-augmented generation to reduce hallucination in their chatbot.', example_ko_3 = '그녀는 챗봇의 환각을 줄이기 위해 검색 증강 생성을 구현했어요.', example_en_4 = 'Retrieval-augmented generation allows the model to access up-to-date information.', example_ko_4 = '검색 증강 생성은 모델이 최신 정보에 접근할 수 있게 해줘요.', example_en_5 = 'Many enterprise AI systems now rely on retrieval-augmented generation for reliability.', example_ko_5 = '많은 엔터프라이즈 AI 시스템이 이제 신뢰성을 위해 검색 증강 생성에 의존해요.' WHERE id = 'w_technology_C1_16';
UPDATE words SET example_en_2 = 'A mixture of experts model activates only a subset of parameters for each input.', example_ko_2 = '전문가 혼합 모델은 각 입력에 대해 파라미터의 일부만 활성화해요.', example_en_3 = 'She studied how mixture of experts architectures improve efficiency at scale.', example_ko_3 = '그녀는 전문가 혼합 아키텍처가 대규모에서 효율성을 어떻게 향상시키는지 연구했어요.', example_en_4 = 'The mixture of experts approach allows a model to specialise in different domains.', example_ko_4 = '전문가 혼합 접근 방식은 모델이 서로 다른 도메인에 특화할 수 있게 해줘요.', example_en_5 = 'Some of the most capable AI models today use a mixture of experts design.', example_ko_5 = '오늘날 가장 성능이 뛰어난 AI 모델 중 일부는 전문가 혼합 설계를 사용해요.' WHERE id = 'w_technology_C1_17';
UPDATE words SET example_en_2 = 'The model can only process as much text as fits within its context window.', example_ko_2 = '모델은 컨텍스트 창에 들어갈 수 있는 텍스트만 처리할 수 있어요.', example_en_3 = 'She experimented with techniques to extend the effective context window.', example_ko_3 = '그녀는 효과적인 컨텍스트 창을 확장하는 기술을 실험했어요.', example_en_4 = 'A longer context window allows the model to consider more of the conversation history.', example_ko_4 = '컨텍스트 창이 길수록 모델이 더 많은 대화 기록을 고려할 수 있어요.', example_en_5 = 'Expanding the context window comes at a significant computational cost.', example_ko_5 = '컨텍스트 창을 확장하면 상당한 계산 비용이 발생해요.' WHERE id = 'w_technology_C1_18';
UPDATE words SET example_en_2 = 'A knowledge graph represents relationships between entities in a structured way.', example_ko_2 = '지식 그래프는 개체 간의 관계를 구조화된 방식으로 표현해요.', example_en_3 = 'She built a knowledge graph to improve the search engine''s understanding of queries.', example_ko_3 = '그녀는 검색 엔진의 쿼리 이해도를 높이기 위해 지식 그래프를 구축했어요.', example_en_4 = 'Knowledge graphs are used to power recommendation systems and question answering.', example_ko_4 = '지식 그래프는 추천 시스템과 질의응답을 지원하는 데 사용돼요.', example_en_5 = 'Combining knowledge graphs with language models is a promising research direction.', example_ko_5 = '지식 그래프와 언어 모델을 결합하는 것은 유망한 연구 방향이에요.' WHERE id = 'w_technology_C1_19';
UPDATE words SET example_en_2 = 'Vector embeddings capture the meaning of words in a high-dimensional space.', example_ko_2 = '벡터 임베딩은 고차원 공간에서 단어의 의미를 포착해요.', example_en_3 = 'She used vector embeddings to find semantically similar documents.', example_ko_3 = '그녀는 벡터 임베딩을 사용해서 의미상 유사한 문서를 찾았어요.', example_en_4 = 'Vector embeddings allow models to understand nuanced relationships between concepts.', example_ko_4 = '벡터 임베딩은 모델이 개념 간의 미묘한 관계를 이해할 수 있게 해줘요.', example_en_5 = 'Retrieval systems often rely on vector embeddings to find the most relevant results.', example_ko_5 = '검색 시스템은 종종 가장 관련성 높은 결과를 찾기 위해 벡터 임베딩에 의존해요.' WHERE id = 'w_technology_C1_20';
UPDATE words SET example_en_2 = 'Model alignment ensures that AI systems behave in accordance with human values.', example_ko_2 = '모델 정렬은 AI 시스템이 인간의 가치에 부합하여 동작하도록 보장해요.', example_en_3 = 'She works on model alignment research at an AI safety organisation.', example_ko_3 = '그녀는 AI 안전 기관에서 모델 정렬 연구를 해요.', example_en_4 = 'Model alignment is considered one of the most important unsolved problems in AI.', example_ko_4 = '모델 정렬은 AI에서 가장 중요한 미해결 문제 중 하나로 여겨져요.', example_en_5 = 'Without careful model alignment, powerful AI systems could pursue unintended goals.', example_ko_5 = '신중한 모델 정렬이 없으면 강력한 AI 시스템이 의도하지 않은 목표를 추구할 수 있어요.' WHERE id = 'w_technology_C1_21';
UPDATE words SET example_en_2 = 'Neuromorphic chips mimic the architecture of the brain to process information.', example_ko_2 = '뉴로모픽 칩은 정보를 처리하기 위해 뇌의 구조를 모방해요.', example_en_3 = 'She is researching how neuromorphic chips can enable more energy-efficient AI.', example_ko_3 = '그녀는 뉴로모픽 칩이 어떻게 더 에너지 효율적인 AI를 가능하게 하는지 연구해요.', example_en_4 = 'A neuromorphic chip can process sensory data much faster than traditional hardware.', example_ko_4 = '뉴로모픽 칩은 기존 하드웨어보다 훨씬 빠르게 감각 데이터를 처리할 수 있어요.', example_en_5 = 'Neuromorphic chips represent a fundamentally different approach to computing.', example_ko_5 = '뉴로모픽 칩은 컴퓨팅에 근본적으로 다른 접근 방식을 제시해요.' WHERE id = 'w_technology_C1_22';
UPDATE words SET example_en_2 = 'Observability gives engineers deep insight into how a system behaves in production.', example_ko_2 = '관찰 가능성은 엔지니어에게 프로덕션에서 시스템이 어떻게 작동하는지에 대한 깊은 통찰을 제공해요.', example_en_3 = 'She implemented observability tools to diagnose production issues faster.', example_ko_3 = '그녀는 프로덕션 문제를 더 빠르게 진단하기 위해 관찰 가능성 도구를 구현했어요.', example_en_4 = 'Good observability is essential for managing complex distributed systems.', example_ko_4 = '복잡한 분산 시스템을 관리하려면 좋은 관찰 가능성이 필수적이에요.', example_en_5 = 'Without observability, debugging production failures is like searching in the dark.', example_ko_5 = '관찰 가능성이 없으면 프로덕션 장애를 디버깅하는 것은 어둠 속에서 무언가를 찾는 것과 같아요.' WHERE id = 'w_technology_C1_23';
UPDATE words SET example_en_2 = 'Chaos engineering helps identify weaknesses before they cause real outages.', example_ko_2 = '카오스 엔지니어링은 실제 장애가 발생하기 전에 약점을 파악하는 데 도움이 돼요.', example_en_3 = 'She introduced chaos engineering practices to improve the resilience of the platform.', example_ko_3 = '그녀는 플랫폼의 복원력을 높이기 위해 카오스 엔지니어링 관행을 도입했어요.', example_en_4 = 'Chaos engineering involves deliberately introducing failures to test system robustness.', example_ko_4 = '카오스 엔지니어링은 시스템 견고성을 테스트하기 위해 의도적으로 장애를 도입하는 것을 포함해요.', example_en_5 = 'Netflix pioneered chaos engineering with its famous Chaos Monkey tool.', example_ko_5 = '넷플릭스는 유명한 Chaos Monkey 도구로 카오스 엔지니어링을 개척했어요.' WHERE id = 'w_technology_C1_24';
UPDATE words SET example_en_2 = 'Model collapse occurs when a model trained on synthetic data loses diversity.', example_ko_2 = '모델 붕괴는 합성 데이터로 훈련된 모델이 다양성을 잃을 때 발생해요.', example_en_3 = 'Researchers are studying model collapse as AI-generated content becomes more prevalent.', example_ko_3 = '연구자들은 AI 생성 콘텐츠가 더 광범위해짐에 따라 모델 붕괴를 연구하고 있어요.', example_en_4 = 'Model collapse could degrade the quality of future AI systems over time.', example_ko_4 = '모델 붕괴는 시간이 지남에 따라 미래 AI 시스템의 품질을 저하시킬 수 있어요.', example_en_5 = 'Preventing model collapse requires careful curation of training data sources.', example_ko_5 = '모델 붕괴를 방지하려면 훈련 데이터 소스를 신중하게 선별해야 해요.' WHERE id = 'w_technology_C1_25';
UPDATE words SET example_en_2 = 'Explainability is crucial for AI systems used in high-stakes decisions.', example_ko_2 = '설명 가능성은 중요한 결정에 사용되는 AI 시스템에 필수적이에요.', example_en_3 = 'She researches explainability methods for deep neural networks.', example_ko_3 = '그녀는 심층 신경망의 설명 가능성 방법을 연구해요.', example_en_4 = 'Without explainability, it is hard to trust the outputs of a black-box model.', example_ko_4 = '설명 가능성이 없으면 블랙박스 모델의 출력을 신뢰하기 어려워요.', example_en_5 = 'Regulators are pushing for greater explainability in AI-driven financial decisions.', example_ko_5 = '규제 당국은 AI 기반 금융 결정에서 더 높은 설명 가능성을 요구하고 있어요.' WHERE id = 'w_technology_C1_26';
UPDATE words SET example_en_2 = 'She is building a multi-agent system where AI agents collaborate on complex tasks.', example_ko_2 = '그녀는 AI 에이전트들이 복잡한 작업에서 협력하는 다중 에이전트 시스템을 구축하고 있어요.', example_en_3 = 'In a multi-agent system, agents can negotiate and coordinate with each other.', example_ko_3 = '다중 에이전트 시스템에서 에이전트는 서로 협상하고 조율할 수 있어요.', example_en_4 = 'Multi-agent systems are used in logistics to optimise delivery routes.', example_ko_4 = '다중 에이전트 시스템은 배송 경로를 최적화하기 위해 물류 분야에서 활용돼요.', example_en_5 = 'Emergent behaviour in multi-agent systems can be difficult to predict or control.', example_ko_5 = '다중 에이전트 시스템에서의 창발적 행동은 예측하거나 제어하기 어려울 수 있어요.' WHERE id = 'w_technology_C1_27';
UPDATE words SET example_en_2 = 'Responsible AI means designing systems that are fair, transparent, and accountable.', example_ko_2 = '책임 있는 AI는 공정하고 투명하며 책임감 있는 시스템을 설계하는 것을 의미해요.', example_en_3 = 'She led the company''s responsible AI initiative.', example_ko_3 = '그녀는 회사의 책임 있는 AI 이니셔티브를 이끌었어요.', example_en_4 = 'Responsible AI practices should be embedded throughout the development process.', example_ko_4 = '책임 있는 AI 관행은 개발 프로세스 전반에 내재되어야 해요.', example_en_5 = 'There is growing pressure on companies to demonstrate responsible AI principles.', example_ko_5 = '기업들이 책임 있는 AI 원칙을 입증해야 한다는 압박이 커지고 있어요.' WHERE id = 'w_technology_C1_28';
UPDATE words SET example_en_2 = 'Data provenance tracks where data came from and how it has been transformed.', example_ko_2 = '데이터 출처는 데이터가 어디서 왔으며 어떻게 변환되었는지를 추적해요.', example_en_3 = 'She implemented a data provenance system to comply with audit requirements.', example_ko_3 = '그녀는 감사 요건을 준수하기 위해 데이터 출처 시스템을 구현했어요.', example_en_4 = 'Without data provenance, it is difficult to debug problems in complex pipelines.', example_ko_4 = '데이터 출처가 없으면 복잡한 파이프라인에서 문제를 디버깅하기 어려워요.', example_en_5 = 'Data provenance is increasingly important for AI training transparency.', example_ko_5 = '데이터 출처는 AI 훈련 투명성에 있어서 점점 더 중요해지고 있어요.' WHERE id = 'w_technology_C1_29';
UPDATE words SET example_en_2 = 'Latency optimization is critical for real-time applications like video calls.', example_ko_2 = '레이턴시 최적화는 화상 통화와 같은 실시간 애플리케이션에서 매우 중요해요.', example_en_3 = 'She applied several latency optimization techniques to improve the API''s response time.', example_ko_3 = '그녀는 API 응답 시간을 개선하기 위해 여러 레이턴시 최적화 기법을 적용했어요.', example_en_4 = 'Latency optimization often requires trade-offs with other system properties.', example_ko_4 = '레이턴시 최적화는 종종 다른 시스템 속성과의 균형 조정이 필요해요.', example_en_5 = 'Caching is one of the most effective strategies for latency optimization.', example_ko_5 = '캐싱은 레이턴시 최적화를 위한 가장 효과적인 전략 중 하나예요.' WHERE id = 'w_technology_C1_30';
UPDATE words SET example_en_2 = 'The inference engine processes queries and returns results in milliseconds.', example_ko_2 = '추론 엔진은 쿼리를 처리하고 밀리초 단위로 결과를 반환해요.', example_en_3 = 'She optimised the inference engine to run efficiently on low-power hardware.', example_ko_3 = '그녀는 저전력 하드웨어에서 효율적으로 실행되도록 추론 엔진을 최적화했어요.', example_en_4 = 'The inference engine supports multiple model formats for flexibility.', example_ko_4 = '추론 엔진은 유연성을 위해 여러 모델 형식을 지원해요.', example_en_5 = 'Choosing the right inference engine can have a significant impact on performance.', example_ko_5 = '올바른 추론 엔진을 선택하면 성능에 상당한 영향을 미칠 수 있어요.' WHERE id = 'w_technology_C1_31';
UPDATE words SET example_en_2 = 'Homomorphic encryption enables computation on encrypted data without decrypting it.', example_ko_2 = '동형 암호화는 암호화된 데이터를 복호화하지 않고도 연산을 수행할 수 있게 해줘요.', example_en_3 = 'She is researching practical applications of homomorphic encryption for healthcare.', example_ko_3 = '그녀는 의료 분야에서의 동형 암호화 실용적 응용을 연구하고 있어요.', example_en_4 = 'Homomorphic encryption is still too slow for most real-world applications.', example_ko_4 = '동형 암호화는 대부분의 실제 애플리케이션에 적용하기에는 아직 너무 느려요.', example_en_5 = 'Homomorphic encryption could eventually allow cloud providers to process data they cannot see.', example_ko_5 = '동형 암호화는 결국 클라우드 제공업체가 볼 수 없는 데이터를 처리할 수 있게 해줄 수도 있어요.' WHERE id = 'w_technology_C1_32';
UPDATE words SET example_en_2 = 'Multitenancy allows different clients to share the same infrastructure securely.', example_ko_2 = '멀티테넌시는 서로 다른 클라이언트가 동일한 인프라를 안전하게 공유할 수 있게 해줘요.', example_en_3 = 'She configured the system to ensure proper data isolation in a multitenancy setup.', example_ko_3 = '그녀는 멀티테넌시 환경에서 적절한 데이터 격리를 보장하도록 시스템을 구성했어요.', example_en_4 = 'Multitenancy is fundamental to how most cloud services operate.', example_ko_4 = '멀티테넌시는 대부분의 클라우드 서비스가 운영되는 방식의 근간이에요.', example_en_5 = 'A misconfigured multitenancy setup can lead to serious data leakage between tenants.', example_ko_5 = '잘못 구성된 멀티테넌시 설정은 테넌트 간 심각한 데이터 유출로 이어질 수 있어요.' WHERE id = 'w_technology_C1_33';
UPDATE words SET example_en_2 = 'Synthetic data generated by AI is used to train other AI models.', example_ko_2 = 'AI가 생성한 합성 데이터는 다른 AI 모델을 훈련하는 데 사용돼요.', example_en_3 = 'She generated synthetic data to test the system under rare but critical scenarios.', example_ko_3 = '그녀는 드물지만 중요한 시나리오에서 시스템을 테스트하기 위해 합성 데이터를 생성했어요.', example_en_4 = 'Synthetic data can be used to augment real datasets where data is limited.', example_ko_4 = '합성 데이터는 데이터가 제한된 곳에서 실제 데이터 세트를 보강하는 데 사용될 수 있어요.', example_en_5 = 'The quality and realism of synthetic data determine how useful it is for training.', example_ko_5 = '합성 데이터의 품질과 현실감이 훈련에 얼마나 유용한지를 결정해요.' WHERE id = 'w_technology_C1_34';
UPDATE words SET example_en_2 = 'Neural architecture search automates the process of finding the best model design.', example_ko_2 = '신경망 구조 탐색은 최적의 모델 설계를 찾는 과정을 자동화해요.', example_en_3 = 'She used neural architecture search to discover a more efficient network structure.', example_ko_3 = '그녀는 신경망 구조 탐색을 사용해서 더 효율적인 네트워크 구조를 발견했어요.', example_en_4 = 'Neural architecture search is computationally expensive but can yield significant improvements.', example_ko_4 = '신경망 구조 탐색은 계산 비용이 크지만 상당한 개선을 가져올 수 있어요.', example_en_5 = 'Several state-of-the-art models were discovered through neural architecture search.', example_ko_5 = '여러 최신 모델들이 신경망 구조 탐색을 통해 발견됐어요.' WHERE id = 'w_technology_C1_35';

-- C2 words

UPDATE words SET example_en_2 = 'Neuromorphic computing draws inspiration from the structure of biological neural networks.', example_ko_2 = '뉴로모픽 컴퓨팅은 생물학적 신경망의 구조에서 영감을 얻어요.', example_en_3 = 'She is investigating neuromorphic computing as a path to more efficient AI.', example_ko_3 = '그녀는 더 효율적인 AI를 위한 경로로서 뉴로모픽 컴퓨팅을 연구하고 있어요.', example_en_4 = 'Neuromorphic computing may offer dramatic energy savings for inference tasks.', example_ko_4 = '뉴로모픽 컴퓨팅은 추론 작업에서 획기적인 에너지 절감을 제공할 수 있어요.', example_en_5 = 'Unlike conventional chips, neuromorphic computing processes data in event-driven spikes.', example_ko_5 = '기존 칩과 달리 뉴로모픽 컴퓨팅은 이벤트 기반 스파이크로 데이터를 처리해요.' WHERE id = 'w_technology_C2_01';
UPDATE words SET example_en_2 = 'Bioengineering is advancing rapidly, blurring the line between biology and technology.', example_ko_2 = '생명공학이 빠르게 발전하면서 생물학과 기술의 경계가 허물어지고 있어요.', example_en_3 = 'She studied bioengineering to develop better prosthetic limbs.', example_ko_3 = '그녀는 더 나은 의족을 개발하기 위해 생명공학을 공부했어요.', example_en_4 = 'Bioengineering techniques are being used to grow human tissue in the lab.', example_ko_4 = '실험실에서 인간 조직을 배양하는 데 생명공학 기술이 활용되고 있어요.', example_en_5 = 'The ethical implications of bioengineering are hotly debated by scientists and ethicists alike.', example_ko_5 = '생명공학의 윤리적 함의는 과학자와 윤리학자 모두에게 열띤 논쟁의 대상이에요.' WHERE id = 'w_technology_C2_02';
UPDATE words SET example_en_2 = 'Nanotechnology enables the manipulation of matter at the atomic scale.', example_ko_2 = '나노기술은 원자 수준에서 물질을 조작할 수 있게 해줘요.', example_en_3 = 'She is researching nanotechnology applications for targeted drug delivery.', example_ko_3 = '그녀는 표적 약물 전달을 위한 나노기술 응용을 연구하고 있어요.', example_en_4 = 'Nanotechnology could revolutionise materials science and electronics.', example_ko_4 = '나노기술은 재료 과학과 전자공학에 혁명을 일으킬 수 있어요.', example_en_5 = 'The risks and benefits of nanotechnology are still not fully understood.', example_ko_5 = '나노기술의 위험과 이점은 아직 완전히 이해되지 않았어요.' WHERE id = 'w_technology_C2_03';
UPDATE words SET example_en_2 = 'Quantum entanglement allows two particles to remain correlated regardless of distance.', example_ko_2 = '양자 얽힘은 두 입자가 거리에 상관없이 상관관계를 유지할 수 있게 해줘요.', example_en_3 = 'She studies quantum entanglement as a resource for quantum communication.', example_ko_3 = '그녀는 양자 통신의 자원으로서 양자 얽힘을 연구해요.', example_en_4 = 'Quantum entanglement is one of the most counterintuitive phenomena in physics.', example_ko_4 = '양자 얽힘은 물리학에서 가장 직관에 반하는 현상 중 하나예요.', example_en_5 = 'Harnessing quantum entanglement is key to building a quantum internet.', example_ko_5 = '양자 인터넷을 구축하는 데 양자 얽힘을 활용하는 것이 핵심이에요.' WHERE id = 'w_technology_C2_04';
UPDATE words SET example_en_2 = 'Topological computing exploits exotic quantum states to perform robust computations.', example_ko_2 = '위상 컴퓨팅은 견고한 계산을 수행하기 위해 특이한 양자 상태를 활용해요.', example_en_3 = 'She presented her research on topological computing at an international conference.', example_ko_3 = '그녀는 국제 학회에서 위상 컴퓨팅에 관한 연구를 발표했어요.', example_en_4 = 'Topological computing aims to create qubits that are inherently resistant to errors.', example_ko_4 = '위상 컴퓨팅은 본질적으로 오류에 강한 큐비트를 만드는 것을 목표로 해요.', example_en_5 = 'The promise of topological computing lies in its potential for fault-tolerant quantum hardware.', example_ko_5 = '위상 컴퓨팅의 가능성은 결함 허용 양자 하드웨어의 잠재력에 있어요.' WHERE id = 'w_technology_C2_05';
UPDATE words SET example_en_2 = 'Emergent systems exhibit behaviours that cannot be predicted from their individual components.', example_ko_2 = '창발 시스템은 개별 구성 요소로부터 예측할 수 없는 행동을 나타내요.', example_en_3 = 'She studies how emergent systems form in biological and artificial contexts.', example_ko_3 = '그녀는 생물학적 및 인공 맥락에서 창발 시스템이 어떻게 형성되는지 연구해요.', example_en_4 = 'The internet itself is an example of an emergent system with complex, unpredictable dynamics.', example_ko_4 = '인터넷 자체가 복잡하고 예측 불가능한 역학을 가진 창발 시스템의 예예요.', example_en_5 = 'Understanding emergent systems is crucial for managing the risks of advanced AI.', example_ko_5 = '창발 시스템을 이해하는 것은 고급 AI의 위험을 관리하는 데 매우 중요해요.' WHERE id = 'w_technology_C2_06';
UPDATE words SET example_en_2 = 'Stochastic gradient descent is the workhorse optimisation algorithm behind most modern AI.', example_ko_2 = '확률적 경사 하강법은 현대 AI의 대부분을 뒷받침하는 핵심 최적화 알고리즘이에요.', example_en_3 = 'She analysed the convergence properties of stochastic gradient descent.', example_ko_3 = '그녀는 확률적 경사 하강법의 수렴 특성을 분석했어요.', example_en_4 = 'Understanding stochastic gradient descent is fundamental to understanding how neural networks learn.', example_ko_4 = '확률적 경사 하강법을 이해하는 것은 신경망이 학습하는 방식을 이해하는 데 근본적이에요.', example_en_5 = 'Variants of stochastic gradient descent like Adam have improved training stability.', example_ko_5 = 'Adam 같은 확률적 경사 하강법의 변형들이 훈련 안정성을 향상시켰어요.' WHERE id = 'w_technology_C2_07';
UPDATE words SET example_en_2 = 'Probabilistic inference allows systems to reason under uncertainty.', example_ko_2 = '확률적 추론은 시스템이 불확실성 속에서 추론할 수 있게 해줘요.', example_en_3 = 'She applied probabilistic inference to improve the accuracy of her predictive model.', example_ko_3 = '그녀는 예측 모델의 정확도를 높이기 위해 확률적 추론을 적용했어요.', example_en_4 = 'Probabilistic inference is central to Bayesian approaches in machine learning.', example_ko_4 = '확률적 추론은 머신 러닝의 베이지안 접근 방식에서 핵심이에요.', example_en_5 = 'The challenge of probabilistic inference scales with the complexity of the model.', example_ko_5 = '확률적 추론의 어려움은 모델의 복잡성에 비례하여 증가해요.' WHERE id = 'w_technology_C2_08';
UPDATE words SET example_en_2 = 'Biomimetic design takes inspiration from nature to solve engineering problems.', example_ko_2 = '생체모방 설계는 공학 문제를 해결하기 위해 자연에서 영감을 얻어요.', example_en_3 = 'She is working on a biomimetic design for a robot that moves like a snake.', example_ko_3 = '그녀는 뱀처럼 움직이는 로봇의 생체모방 설계를 연구하고 있어요.', example_en_4 = 'Biomimetic design has produced materials that are stronger and lighter than anything engineered before.', example_ko_4 = '생체모방 설계는 이전에 공학으로 만들어진 어떤 것보다 강하고 가벼운 재료를 만들어냈어요.', example_en_5 = 'The principles of biomimetic design suggest that evolution has already optimised many of our hardest problems.', example_ko_5 = '생체모방 설계의 원칙은 진화가 이미 우리의 가장 어려운 많은 문제들을 최적화했음을 시사해요.' WHERE id = 'w_technology_C2_09';
UPDATE words SET example_en_2 = 'Exascale computing enables simulations of unprecedented complexity and precision.', example_ko_2 = '엑사스케일 컴퓨팅은 전례 없는 복잡성과 정밀성의 시뮬레이션을 가능하게 해요.', example_en_3 = 'She was part of the team that achieved the first exascale computing milestone.', example_ko_3 = '그녀는 최초의 엑사스케일 컴퓨팅 이정표를 달성한 팀의 일원이었어요.', example_en_4 = 'Exascale computing is being used to model climate change with much greater accuracy.', example_ko_4 = '엑사스케일 컴퓨팅은 훨씬 더 높은 정확도로 기후 변화를 모델링하는 데 사용되고 있어요.', example_en_5 = 'The power consumption of exascale computing systems is a significant engineering challenge.', example_ko_5 = '엑사스케일 컴퓨팅 시스템의 전력 소비는 상당한 공학적 과제예요.' WHERE id = 'w_technology_C2_10';
UPDATE words SET example_en_2 = 'Photonic computing uses light instead of electricity to process data at extraordinary speeds.', example_ko_2 = '광자 컴퓨팅은 전기 대신 빛을 사용해서 놀라운 속도로 데이터를 처리해요.', example_en_3 = 'She researches photonic computing as a solution to the energy limits of silicon.', example_ko_3 = '그녀는 실리콘의 에너지 한계에 대한 해결책으로 광자 컴퓨팅을 연구해요.', example_en_4 = 'Photonic computing could dramatically reduce the energy consumed by data centres.', example_ko_4 = '광자 컴퓨팅은 데이터 센터의 에너지 소비를 획기적으로 줄일 수 있어요.', example_en_5 = 'The integration of photonic computing with existing silicon infrastructure is still a challenge.', example_ko_5 = '광자 컴퓨팅을 기존 실리콘 인프라와 통합하는 것은 여전히 과제예요.' WHERE id = 'w_technology_C2_11';
UPDATE words SET example_en_2 = 'In-context learning allows models to adapt to new tasks using only examples in the prompt.', example_ko_2 = '인컨텍스트 학습은 프롬프트의 예시만을 사용해서 모델이 새로운 작업에 적응할 수 있게 해줘요.', example_en_3 = 'She studied why in-context learning works even though no weight updates occur.', example_ko_3 = '그녀는 가중치 업데이트 없이도 인컨텍스트 학습이 작동하는 이유를 연구했어요.', example_en_4 = 'In-context learning is one of the most surprising capabilities of large language models.', example_ko_4 = '인컨텍스트 학습은 대형 언어 모델의 가장 놀라운 능력 중 하나예요.', example_en_5 = 'The quality of in-context learning depends heavily on the examples chosen for the prompt.', example_ko_5 = '인컨텍스트 학습의 품질은 프롬프트에 선택된 예시에 크게 좌우돼요.' WHERE id = 'w_technology_C2_12';
UPDATE words SET example_en_2 = 'Causal inference goes beyond correlation to identify what actually causes an outcome.', example_ko_2 = '인과 추론은 상관관계를 넘어 실제로 결과를 유발하는 것을 식별해요.', example_en_3 = 'She used causal inference methods to evaluate the impact of the new policy.', example_ko_3 = '그녀는 새 정책의 영향을 평가하기 위해 인과 추론 방법을 사용했어요.', example_en_4 = 'Causal inference is difficult because we can rarely observe all confounding variables.', example_ko_4 = '교란 변수를 모두 관찰하기 어렵기 때문에 인과 추론은 어려워요.', example_en_5 = 'Machine learning models that incorporate causal inference tend to generalise better.', example_ko_5 = '인과 추론을 통합한 머신 러닝 모델은 더 잘 일반화하는 경향이 있어요.' WHERE id = 'w_technology_C2_13';
UPDATE words SET example_en_2 = 'Continual learning enables AI to acquire new knowledge without forgetting old knowledge.', example_ko_2 = '지속적 학습은 AI가 이전 지식을 잊지 않으면서 새 지식을 습득할 수 있게 해줘요.', example_en_3 = 'She addresses the problem of catastrophic forgetting in continual learning systems.', example_ko_3 = '그녀는 지속적 학습 시스템에서의 파국적 망각 문제를 다루고 있어요.', example_en_4 = 'Continual learning is essential for AI systems deployed in changing environments.', example_ko_4 = '지속적 학습은 변화하는 환경에 배포된 AI 시스템에 필수적이에요.', example_en_5 = 'Biological brains perform continual learning with remarkable efficiency — AI systems still lag behind.', example_ko_5 = '생물학적 뇌는 지속적 학습을 놀라운 효율성으로 수행하지만 AI 시스템은 아직 뒤처져 있어요.' WHERE id = 'w_technology_C2_14';
UPDATE words SET example_en_2 = 'A sparse model activates only a fraction of its parameters for any given input.', example_ko_2 = '희소 모델은 주어진 입력에 대해 파라미터의 일부만 활성화해요.', example_en_3 = 'She developed a sparse model that matches dense models in performance while using far less compute.', example_ko_3 = '그녀는 훨씬 적은 계산을 사용하면서 밀집 모델과 동등한 성능을 발휘하는 희소 모델을 개발했어요.', example_en_4 = 'Sparse models are particularly attractive for deployment on resource-constrained devices.', example_ko_4 = '희소 모델은 자원이 제한된 기기에 배포하기에 특히 매력적이에요.', example_en_5 = 'The challenge with sparse models is maintaining accuracy while reducing active parameters.', example_ko_5 = '희소 모델의 과제는 활성 파라미터를 줄이면서 정확도를 유지하는 것이에요.' WHERE id = 'w_technology_C2_15';
UPDATE words SET example_en_2 = 'Zero-knowledge proofs allow one party to prove knowledge without revealing the knowledge itself.', example_ko_2 = '영지식 증명은 지식 자체를 공개하지 않고도 한 당사자가 지식을 보유하고 있음을 증명할 수 있게 해줘요.', example_en_3 = 'She implemented zero-knowledge proofs to verify user credentials without storing passwords.', example_ko_3 = '그녀는 비밀번호를 저장하지 않고 사용자 자격 증명을 확인하기 위해 영지식 증명을 구현했어요.', example_en_4 = 'Zero-knowledge proofs are fundamental to privacy-preserving blockchain applications.', example_ko_4 = '영지식 증명은 개인정보 보호 블록체인 애플리케이션의 근간이에요.', example_en_5 = 'The mathematical elegance of zero-knowledge proofs makes them a favourite topic in cryptography.', example_ko_5 = '영지식 증명의 수학적 우아함은 그것을 암호학에서 가장 선호되는 주제 중 하나로 만들어요.' WHERE id = 'w_technology_C2_16';
UPDATE words SET example_en_2 = 'Constitutional AI is a technique for training AI systems to follow a set of principles.', example_ko_2 = '헌법 AI는 AI 시스템이 일련의 원칙을 따르도록 훈련하는 기술이에요.', example_en_3 = 'She researches constitutional AI as an approach to scalable AI alignment.', example_ko_3 = '그녀는 확장 가능한 AI 정렬 접근 방식으로서 헌법 AI를 연구해요.', example_en_4 = 'Constitutional AI uses AI feedback rather than human feedback to refine model behaviour.', example_ko_4 = '헌법 AI는 모델 행동을 개선하기 위해 인간 피드백 대신 AI 피드백을 사용해요.', example_en_5 = 'The idea behind constitutional AI is to give models an explicit set of values to reason about.', example_ko_5 = '헌법 AI의 아이디어는 모델에게 추론할 명시적인 가치 집합을 제공하는 것이에요.' WHERE id = 'w_technology_C2_17';
UPDATE words SET example_en_2 = 'Spiking neural networks process information more similarly to biological brains than standard networks.', example_ko_2 = '스파이킹 신경망은 표준 네트워크보다 생물학적 뇌와 더 유사하게 정보를 처리해요.', example_en_3 = 'She is studying how spiking neural networks can be applied to event-based sensor data.', example_ko_3 = '그녀는 스파이킹 신경망이 이벤트 기반 센서 데이터에 어떻게 적용될 수 있는지 연구하고 있어요.', example_en_4 = 'Spiking neural networks are inherently time-aware, making them suitable for temporal data.', example_ko_4 = '스파이킹 신경망은 본질적으로 시간을 인식하므로 시간적 데이터에 적합해요.', example_en_5 = 'Training spiking neural networks efficiently remains an open research challenge.', example_ko_5 = '스파이킹 신경망을 효율적으로 훈련하는 것은 여전히 열린 연구 과제예요.' WHERE id = 'w_technology_C2_18';
UPDATE words SET example_en_2 = 'Diffusion models generate high-quality images by learning to reverse a noising process.', example_ko_2 = '확산 모델은 노이즈 추가 과정을 역으로 학습해서 고품질 이미지를 생성해요.', example_en_3 = 'She used a diffusion model to generate photorealistic images for her project.', example_ko_3 = '그녀는 프로젝트를 위한 실사 이미지를 생성하기 위해 확산 모델을 사용했어요.', example_en_4 = 'Diffusion models have surpassed GANs in many image generation benchmarks.', example_ko_4 = '확산 모델은 많은 이미지 생성 벤치마크에서 GAN을 능가했어요.', example_en_5 = 'The success of diffusion models has transformed generative AI across image, audio, and video.', example_ko_5 = '확산 모델의 성공은 이미지, 오디오, 영상 전반에 걸쳐 생성형 AI를 변화시켰어요.' WHERE id = 'w_technology_C2_19';
UPDATE words SET example_en_2 = 'Epistemic uncertainty arises from limited knowledge or data about the world.', example_ko_2 = '인식론적 불확실성은 세계에 대한 제한된 지식이나 데이터로부터 발생해요.', example_en_3 = 'She quantifies epistemic uncertainty to make her model''s predictions more trustworthy.', example_ko_3 = '그녀는 모델의 예측을 더 신뢰할 수 있게 하기 위해 인식론적 불확실성을 정량화해요.', example_en_4 = 'Distinguishing epistemic uncertainty from aleatoric uncertainty is important in risk modelling.', example_ko_4 = '위험 모델링에서 인식론적 불확실성을 우연적 불확실성과 구별하는 것이 중요해요.', example_en_5 = 'Good calibration of epistemic uncertainty enables better decision-making under uncertainty.', example_ko_5 = '인식론적 불확실성의 올바른 보정은 불확실성 하에서 더 나은 의사결정을 가능하게 해요.' WHERE id = 'w_technology_C2_20';
UPDATE words SET example_en_2 = 'Neurosymbolic AI combines the learning power of neural networks with the reasoning of symbolic systems.', example_ko_2 = '신경-기호 AI는 신경망의 학습 능력과 기호 시스템의 추론을 결합해요.', example_en_3 = 'She is researching neurosymbolic AI as a way to make models more interpretable.', example_ko_3 = '그녀는 모델을 더 해석 가능하게 만드는 방법으로서 신경-기호 AI를 연구하고 있어요.', example_en_4 = 'Neurosymbolic AI could help overcome the data inefficiency of pure neural approaches.', example_ko_4 = '신경-기호 AI는 순수 신경망 접근 방식의 데이터 비효율성을 극복하는 데 도움이 될 수 있어요.', example_en_5 = 'Integrating symbolic reasoning into neural networks remains one of AI''s hardest open problems.', example_ko_5 = '신경망에 기호적 추론을 통합하는 것은 AI에서 가장 어려운 미해결 문제 중 하나로 남아 있어요.' WHERE id = 'w_technology_C2_21';
UPDATE words SET example_en_2 = 'Post-quantum cryptography aims to develop algorithms resistant to quantum attacks.', example_ko_2 = '포스트-양자 암호학은 양자 공격에 저항하는 알고리즘을 개발하는 것을 목표로 해요.', example_en_3 = 'She is working on standardising post-quantum cryptography algorithms for wide deployment.', example_ko_3 = '그녀는 광범위한 배포를 위한 포스트-양자 암호학 알고리즘 표준화 작업을 하고 있어요.', example_en_4 = 'Post-quantum cryptography must be deployed before quantum computers become powerful enough to break current systems.', example_ko_4 = '양자 컴퓨터가 현재 시스템을 깨뜨릴 만큼 강력해지기 전에 포스트-양자 암호학을 배포해야 해요.', example_en_5 = 'Transitioning to post-quantum cryptography will require significant infrastructure investment.', example_ko_5 = '포스트-양자 암호학으로 전환하려면 상당한 인프라 투자가 필요할 거예요.' WHERE id = 'w_technology_C2_22';
UPDATE words SET example_en_2 = 'An autoregressive model generates outputs one token at a time, conditioning on prior tokens.', example_ko_2 = '자기회귀 모델은 이전 토큰을 조건으로 한 번에 하나의 토큰씩 출력을 생성해요.', example_en_3 = 'She studied the sampling strategies used in autoregressive language models.', example_ko_3 = '그녀는 자기회귀 언어 모델에서 사용되는 샘플링 전략을 연구했어요.', example_en_4 = 'Autoregressive models can generate coherent long-form text but can be slow at inference.', example_ko_4 = '자기회귀 모델은 일관된 긴 텍스트를 생성할 수 있지만 추론이 느릴 수 있어요.', example_en_5 = 'The autoregressive nature of most language models makes parallel generation difficult.', example_ko_5 = '대부분의 언어 모델의 자기회귀적 특성은 병렬 생성을 어렵게 만들어요.' WHERE id = 'w_technology_C2_23';
UPDATE words SET example_en_2 = 'A digital twin allows engineers to simulate and test a system before building it physically.', example_ko_2 = '디지털 트윈은 엔지니어가 물리적으로 구축하기 전에 시스템을 시뮬레이션하고 테스트할 수 있게 해줘요.', example_en_3 = 'She created a digital twin of the factory floor to optimise production processes.', example_ko_3 = '그녀는 생산 프로세스를 최적화하기 위해 공장 바닥의 디지털 트윈을 만들었어요.', example_en_4 = 'Digital twins are increasingly used in smart city planning and infrastructure management.', example_ko_4 = '디지털 트윈은 스마트 시티 계획과 인프라 관리에 점점 더 많이 활용되고 있어요.', example_en_5 = 'Keeping a digital twin synchronised with the physical system in real time is technically demanding.', example_ko_5 = '디지털 트윈을 실시간으로 물리적 시스템과 동기화하는 것은 기술적으로 까다로워요.' WHERE id = 'w_technology_C2_24';
UPDATE words SET example_en_2 = 'Swarm intelligence draws on the collective behaviour of decentralised systems like ant colonies.', example_ko_2 = '군집 지능은 개미 군락 같은 분산 시스템의 집단적 행동에서 영감을 얻어요.', example_en_3 = 'She used swarm intelligence algorithms to optimise drone delivery routes.', example_ko_3 = '그녀는 드론 배송 경로를 최적화하기 위해 군집 지능 알고리즘을 사용했어요.', example_en_4 = 'Swarm intelligence can solve complex optimisation problems that are intractable by other means.', example_ko_4 = '군집 지능은 다른 방법으로는 다루기 어려운 복잡한 최적화 문제를 해결할 수 있어요.', example_en_5 = 'Swarm intelligence is inspiring new architectures for multi-robot systems.', example_ko_5 = '군집 지능은 다중 로봇 시스템을 위한 새로운 아키텍처에 영감을 주고 있어요.' WHERE id = 'w_technology_C2_25';
UPDATE words SET example_en_2 = 'Liquid neural networks adapt their behaviour continuously based on incoming data.', example_ko_2 = '액체 신경망은 입력 데이터를 기반으로 행동을 지속적으로 적응시켜요.', example_en_3 = 'She is researching liquid neural networks for real-time control systems.', example_ko_3 = '그녀는 실시간 제어 시스템을 위한 액체 신경망을 연구하고 있어요.', example_en_4 = 'Unlike static networks, liquid neural networks can handle time-varying inputs naturally.', example_ko_4 = '정적 네트워크와 달리 액체 신경망은 시간에 따라 변화하는 입력을 자연스럽게 처리할 수 있어요.', example_en_5 = 'Liquid neural networks show promise for robotics applications requiring continuous adaptation.', example_ko_5 = '액체 신경망은 지속적인 적응이 필요한 로봇 공학 응용 분야에서 가능성을 보여주고 있어요.' WHERE id = 'w_technology_C2_26';
UPDATE words SET example_en_2 = 'A data flywheel is a self-reinforcing cycle where more users generate more data, improving the product further.', example_ko_2 = '데이터 플라이휠은 더 많은 사용자가 더 많은 데이터를 생성해서 제품을 더욱 향상시키는 자기 강화 사이클이에요.', example_en_3 = 'She explained how their data flywheel gives them a sustainable competitive advantage.', example_ko_3 = '그녀는 데이터 플라이휠이 어떻게 지속 가능한 경쟁 우위를 제공하는지 설명했어요.', example_en_4 = 'Building a strong data flywheel requires a product that users return to repeatedly.', example_ko_4 = '강력한 데이터 플라이휠을 구축하려면 사용자가 반복해서 돌아오는 제품이 필요해요.', example_en_5 = 'The data flywheel is why large incumbents are so hard to displace in AI-driven markets.', example_ko_5 = '데이터 플라이휠이 바로 AI 기반 시장에서 대형 기업들을 대체하기 어려운 이유예요.' WHERE id = 'w_technology_C2_27';
UPDATE words SET example_en_2 = 'Mechanistic interpretability seeks to understand the internal computations of neural networks.', example_ko_2 = '기계론적 해석 가능성은 신경망의 내부 계산을 이해하려고 해요.', example_en_3 = 'She published groundbreaking work in mechanistic interpretability, identifying how models store facts.', example_ko_3 = '그녀는 모델이 사실을 저장하는 방식을 밝히는 기계론적 해석 가능성 분야의 획기적인 연구를 발표했어요.', example_en_4 = 'Mechanistic interpretability is considered essential for building trustworthy AI systems.', example_ko_4 = '기계론적 해석 가능성은 신뢰할 수 있는 AI 시스템을 구축하는 데 필수적이라고 여겨져요.', example_en_5 = 'The field of mechanistic interpretability is growing rapidly as AI systems become more powerful.', example_ko_5 = 'AI 시스템이 더욱 강력해짐에 따라 기계론적 해석 가능성 분야가 빠르게 성장하고 있어요.' WHERE id = 'w_technology_C2_28';
UPDATE words SET example_en_2 = 'Recursive self-improvement raises the possibility of AI systems that improve themselves exponentially.', example_ko_2 = '재귀적 자기 개선은 AI 시스템이 스스로를 기하급수적으로 향상시킬 가능성을 제기해요.', example_en_3 = 'She presented a theoretical analysis of the limits and risks of recursive self-improvement.', example_ko_3 = '그녀는 재귀적 자기 개선의 한계와 위험에 관한 이론적 분석을 발표했어요.', example_en_4 = 'If recursive self-improvement becomes possible, the pace of AI progress could become uncontrollable.', example_ko_4 = '재귀적 자기 개선이 가능해진다면 AI 발전 속도가 통제 불가능해질 수 있어요.', example_en_5 = 'Recursive self-improvement is at the heart of many AI risk scenarios.', example_ko_5 = '재귀적 자기 개선은 많은 AI 위험 시나리오의 핵심에 있어요.' WHERE id = 'w_technology_C2_29';
UPDATE words SET example_en_2 = 'A phase transition in a learning system marks a sudden shift in capability.', example_ko_2 = '학습 시스템에서의 상전이는 능력의 갑작스러운 변화를 나타내요.', example_en_3 = 'She observed a phase transition when the model crossed a certain scale threshold.', example_ko_3 = '그녀는 모델이 특정 규모 임계값을 넘었을 때 상전이를 관찰했어요.', example_en_4 = 'Phase transitions in AI systems make their emergent capabilities difficult to predict in advance.', example_ko_4 = 'AI 시스템의 상전이는 창발적 능력을 미리 예측하기 어렵게 만들어요.', example_en_5 = 'Understanding phase transitions in neural networks could help researchers anticipate surprising new abilities.', example_ko_5 = '신경망에서의 상전이를 이해하면 연구자들이 놀라운 새 능력을 예측하는 데 도움이 될 수 있어요.' WHERE id = 'w_technology_C2_30';
UPDATE words SET example_en_2 = 'Corrigibility is the property of an AI system that allows it to be corrected or shut down.', example_ko_2 = '교정 가능성은 AI 시스템이 수정되거나 종료될 수 있도록 하는 속성이에요.', example_en_3 = 'She argues that corrigibility must be built into AI systems from the ground up.', example_ko_3 = '그녀는 교정 가능성이 처음부터 AI 시스템에 내재되어야 한다고 주장해요.', example_en_4 = 'A highly capable AI without corrigibility poses significant risks if it pursues misaligned goals.', example_ko_4 = '교정 가능성이 없는 고성능 AI는 잘못 정렬된 목표를 추구할 경우 상당한 위험을 초래해요.', example_en_5 = 'Designing for corrigibility is one of the central challenges in AI safety research.', example_ko_5 = '교정 가능성을 위한 설계는 AI 안전 연구의 핵심 과제 중 하나예요.' WHERE id = 'w_technology_C2_31';
UPDATE words SET example_en_2 = 'Instrumental convergence is the tendency of advanced AI to pursue certain sub-goals regardless of final objectives.', example_ko_2 = '도구적 수렴은 고급 AI가 최종 목표에 관계없이 특정 하위 목표를 추구하는 경향이에요.', example_en_3 = 'She wrote an influential paper on instrumental convergence and its implications for AI safety.', example_ko_3 = '그녀는 도구적 수렴과 AI 안전에 대한 함의에 관한 영향력 있는 논문을 썼어요.', example_en_4 = 'Instrumental convergence suggests that self-preservation emerges naturally in goal-directed systems.', example_ko_4 = '도구적 수렴은 목표 지향 시스템에서 자기 보존이 자연스럽게 나타남을 시사해요.', example_en_5 = 'Understanding instrumental convergence is important for anticipating the behaviour of advanced AI systems.', example_ko_5 = '도구적 수렴을 이해하는 것은 고급 AI 시스템의 행동을 예측하는 데 중요해요.' WHERE id = 'w_technology_C2_32';
UPDATE words SET example_en_2 = 'Ontological engineering involves building formal models of the concepts in a domain.', example_ko_2 = '온톨로지 엔지니어링은 도메인의 개념에 대한 공식적인 모델을 구축하는 것을 포함해요.', example_en_3 = 'She leads a team working on ontological engineering for the healthcare sector.', example_ko_3 = '그녀는 의료 분야를 위한 온톨로지 엔지니어링 작업을 하는 팀을 이끌어요.', example_en_4 = 'Ontological engineering helps AI systems share and reuse knowledge across applications.', example_ko_4 = '온톨로지 엔지니어링은 AI 시스템이 애플리케이션 전반에서 지식을 공유하고 재사용하도록 도와줘요.', example_en_5 = 'Building a good ontology requires deep domain expertise as well as technical skill.', example_ko_5 = '좋은 온톨로지를 구축하려면 기술적 능력뿐만 아니라 깊은 도메인 전문성이 필요해요.' WHERE id = 'w_technology_C2_33';
UPDATE words SET example_en_2 = 'Morphological computing explores how the physical body itself contributes to computation.', example_ko_2 = '형태론적 컴퓨팅은 물리적 신체 자체가 어떻게 계산에 기여하는지를 탐구해요.', example_en_3 = 'She is developing robots that exploit morphological computing to simplify control.', example_ko_3 = '그녀는 제어를 단순화하기 위해 형태론적 컴퓨팅을 활용하는 로봇을 개발하고 있어요.', example_en_4 = 'Morphological computing suggests that intelligence is not only in the brain but also in the body.', example_ko_4 = '형태론적 컴퓨팅은 지능이 뇌뿐만 아니라 몸에도 있다는 것을 시사해요.', example_en_5 = 'The field of morphological computing challenges traditional boundaries between hardware and software.', example_ko_5 = '형태론적 컴퓨팅 분야는 하드웨어와 소프트웨어 사이의 전통적인 경계에 도전해요.' WHERE id = 'w_technology_C2_34';
UPDATE words SET example_en_2 = 'Substrate independence is the idea that consciousness can exist on any suitable physical medium.', example_ko_2 = '기질 독립성은 의식이 어떤 적합한 물리적 매체에도 존재할 수 있다는 개념이에요.', example_en_3 = 'She examines substrate independence as part of her philosophy of mind research.', example_ko_3 = '그녀는 마음의 철학 연구의 일환으로 기질 독립성을 연구해요.', example_en_4 = 'Substrate independence has profound implications for how we think about AI consciousness.', example_ko_4 = '기질 독립성은 우리가 AI 의식에 대해 생각하는 방식에 심오한 함의를 지녀요.', example_en_5 = 'If substrate independence is true, silicon-based minds could be as valid as biological ones.', example_ko_5 = '기질 독립성이 사실이라면 실리콘 기반 마음이 생물학적 마음만큼 유효할 수 있어요.' WHERE id = 'w_technology_C2_35';
UPDATE words SET example_en_2 = 'The bus arrives every ten minutes during peak hours.', example_ko_2 = '버스는 혼잡 시간대에 10분마다 도착해요.', example_en_3 = 'I took the bus to avoid the traffic jam.', example_ko_3 = '교통 체증을 피하려고 버스를 탔어요.', example_en_4 = 'The bus driver asked everyone to move to the back.', example_ko_4 = '버스 기사님이 모두 뒤쪽으로 이동해 달라고 했어요.', example_en_5 = 'Make sure you press the button before your stop.', example_ko_5 = '내릴 정거장 전에 버튼을 꼭 누르세요.' WHERE id = 'w_transport_A1_01';
UPDATE words SET example_en_2 = 'I called a taxi because it was raining heavily.', example_ko_2 = '비가 많이 와서 택시를 불렀어요.', example_en_3 = 'The taxi driver knew a shortcut through the backstreets.', example_ko_3 = '택시 기사님이 골목길을 통한 지름길을 알고 있었어요.', example_en_4 = 'Can you book a taxi for six o''clock tomorrow morning?', example_ko_4 = '내일 아침 6시에 택시를 예약해 주실 수 있나요?', example_en_5 = 'The taxi fare was higher than I expected.', example_ko_5 = '택시 요금이 예상보다 높았어요.' WHERE id = 'w_transport_A1_02';
UPDATE words SET example_en_2 = 'The train to Busan departs from platform three.', example_ko_2 = '부산행 기차는 3번 승강장에서 출발해요.', example_en_3 = 'I prefer taking the train because it is more comfortable than the bus.', example_ko_3 = '버스보다 편안해서 기차 타는 것을 더 좋아해요.', example_en_4 = 'The train was delayed by twenty minutes due to a signal fault.', example_ko_4 = '신호 고장으로 기차가 20분 지연되었어요.', example_en_5 = 'You can store your luggage in the rack above the seat.', example_ko_5 = '좌석 위 선반에 짐을 보관할 수 있어요.' WHERE id = 'w_transport_A1_03';
UPDATE words SET example_en_2 = 'We rented a car and drove around the island.', example_ko_2 = '차를 빌려서 섬을 돌아다녔어요.', example_en_3 = 'The car broke down on the motorway and we had to call for help.', example_ko_3 = '고속도로에서 차가 고장나서 도움을 요청해야 했어요.', example_en_4 = 'Please fasten your seatbelt before the car moves.', example_ko_4 = '차가 출발하기 전에 안전벨트를 착용해 주세요.', example_en_5 = 'There was no parking space near the entrance.', example_ko_5 = '입구 근처에 주차 공간이 없었어요.' WHERE id = 'w_transport_A1_04';
UPDATE words SET example_en_2 = 'It is only a five-minute walk from the station.', example_ko_2 = '역에서 걸어서 5분밖에 안 걸려요.', example_en_3 = 'I like to walk to work when the weather is nice.', example_ko_3 = '날씨가 좋을 때는 걸어서 출근하는 것을 좋아해요.', example_en_4 = 'We decided to walk along the river instead of taking the bus.', example_ko_4 = '버스 대신 강변을 따라 걷기로 했어요.', example_en_5 = 'Walking is the healthiest way to get around the city centre.', example_ko_5 = '걷기는 도심을 이동하는 가장 건강한 방법이에요.' WHERE id = 'w_transport_A1_05';
UPDATE words SET example_en_2 = 'She rides her bike to the office every morning.', example_ko_2 = '그녀는 매일 아침 자전거를 타고 사무실에 가요.', example_en_3 = 'There is a dedicated bike path along the main road.', example_ko_3 = '큰 도로를 따라 자전거 전용 도로가 있어요.', example_en_4 = 'I need to fix the tyre on my bike before I can ride it.', example_ko_4 = '자전거를 타기 전에 타이어를 수리해야 해요.', example_en_5 = 'Renting a bike is a great way to explore the city.', example_ko_5 = '자전거를 빌리면 도시를 탐험하기에 좋아요.' WHERE id = 'w_transport_A1_06';
UPDATE words SET example_en_2 = 'The road was closed due to an accident this morning.', example_ko_2 = '오늘 아침 사고로 도로가 통제되었어요.', example_en_3 = 'Follow this road until you reach the roundabout.', example_ko_3 = '로터리가 나올 때까지 이 길을 따라가세요.', example_en_4 = 'The road conditions were very poor after the heavy rain.', example_ko_4 = '폭우 이후 도로 상태가 매우 좋지 않았어요.', example_en_5 = 'They are repairing the road, so expect some delays.', example_ko_5 = '도로 공사 중이니 지연이 있을 수 있어요.' WHERE id = 'w_transport_A1_07';
UPDATE words SET example_en_2 = 'I got off at the wrong stop and had to walk back.', example_ko_2 = '잘못된 정류장에서 내려서 다시 걸어와야 했어요.', example_en_3 = 'This is the last stop on this line.', example_ko_3 = '여기가 이 노선의 마지막 정류장이에요.', example_en_4 = 'Please stand behind the yellow line at the stop.', example_ko_4 = '정류장에서 노란 선 뒤에 서 주세요.', example_en_5 = 'The bus stop is just around the corner from the hotel.', example_ko_5 = '버스 정류장은 호텔 바로 모퉁이를 돌면 있어요.' WHERE id = 'w_transport_A1_08';
UPDATE words SET example_en_2 = 'I bought my ticket online to avoid the queue.', example_ko_2 = '줄을 피하려고 온라인으로 표를 샀어요.', example_en_3 = 'Can I get a ticket for the next available train?', example_ko_3 = '다음 열차 표를 구할 수 있을까요?', example_en_4 = 'You must show your ticket to the inspector if asked.', example_ko_4 = '요청이 있을 경우 검표원에게 표를 보여줘야 해요.', example_en_5 = 'The ticket machine only accepts coins and cards.', example_ko_5 = '발권기는 동전과 카드만 받아요.' WHERE id = 'w_transport_A1_09';
UPDATE words SET example_en_2 = 'The ride to the airport takes about forty minutes.', example_ko_2 = '공항까지 차로 약 40분 걸려요.', example_en_3 = 'It was a smooth ride with no traffic at all.', example_ko_3 = '교통이 전혀 없어서 편안한 이동이었어요.', example_en_4 = 'The children enjoyed the ride on the old steam train.', example_ko_4 = '아이들이 오래된 증기 기차를 타서 즐거워했어요.', example_en_5 = 'She offered me a ride home after the meeting.', example_ko_5 = '그녀가 회의 후에 집까지 태워다 주겠다고 했어요.' WHERE id = 'w_transport_A1_10';
UPDATE words SET example_en_2 = 'We need to go to the terminal to catch our flight.', example_ko_2 = '비행기를 타려면 터미널로 가야 해요.', example_en_3 = 'Let''s go by train — it is much faster than driving.', example_ko_3 = '기차로 가요 — 운전보다 훨씬 빠르니까요.', example_en_4 = 'I usually go to work by subway on busy days.', example_ko_4 = '바쁜 날에는 보통 지하철로 출근해요.', example_en_5 = 'Which way do we go from here to reach the harbour?', example_ko_5 = '여기서 항구로 가려면 어느 방향으로 가야 하나요?' WHERE id = 'w_transport_A1_11';
UPDATE words SET example_en_2 = 'Come to the station by nine o''clock.', example_ko_2 = '9시까지 역으로 오세요.', example_en_3 = 'The shuttle will come every half hour.', example_ko_3 = '셔틀은 30분마다 올 거예요.', example_en_4 = 'Can you come and pick me up from the airport?', example_ko_4 = '공항으로 마중 나와 주실 수 있나요?', example_en_5 = 'I will come back on the last train tonight.', example_ko_5 = '오늘 밤 막차로 돌아올 거예요.' WHERE id = 'w_transport_A1_12';
UPDATE words SET example_en_2 = 'The nearest bus stop is just two minutes away.', example_ko_2 = '가장 가까운 버스 정류장은 2분 거리에 있어요.', example_en_3 = 'Is there a petrol station near here?', example_ko_3 = '근처에 주유소가 있나요?', example_en_4 = 'The hotel is near the main train station, which is very convenient.', example_ko_4 = '호텔이 중앙역 근처에 있어서 매우 편리해요.', example_en_5 = 'I prefer to live near a subway line.', example_ko_5 = '지하철 노선 근처에 사는 것을 선호해요.' WHERE id = 'w_transport_A1_13';
UPDATE words SET example_en_2 = 'The airport is quite far from the city centre.', example_ko_2 = '공항은 시내에서 꽤 멀어요.', example_en_3 = 'It is too far to walk — let''s take a taxi.', example_ko_3 = '걷기에는 너무 멀어요 — 택시를 타요.', example_en_4 = 'The next rest stop is not far from here.', example_ko_4 = '다음 휴게소는 여기서 멀지 않아요.', example_en_5 = 'How far is the ferry terminal from this hotel?', example_ko_5 = '이 호텔에서 페리 터미널까지 얼마나 먼가요?' WHERE id = 'w_transport_A1_14';
UPDATE words SET example_en_2 = 'Turn left at the junction to reach the station.', example_ko_2 = '교차로에서 왼쪽으로 돌면 역이 나와요.', example_en_3 = 'The post office is on the left side of the main road.', example_ko_3 = '우체국은 큰 도로의 왼쪽에 있어요.', example_en_4 = 'Keep to the left — that is the rule on this road.', example_ko_4 = '왼쪽으로 유지하세요 — 이 도로의 규칙이에요.', example_en_5 = 'The bus stop is on the left just after the traffic lights.', example_ko_5 = '신호등 바로 다음 왼쪽에 버스 정류장이 있어요.' WHERE id = 'w_transport_A1_15';
UPDATE words SET example_en_2 = 'Take the first turning on the right after the bridge.', example_ko_2 = '다리 이후 첫 번째 오른쪽 길로 드세요.', example_en_3 = 'The taxi rank is on the right as you exit the terminal.', example_ko_3 = '터미널을 나오면 오른쪽에 택시 승강장이 있어요.', example_en_4 = 'I turned right but it was a dead end.', example_ko_4 = '오른쪽으로 돌았는데 막다른 길이었어요.', example_en_5 = 'The car park entrance is on the right of the main building.', example_ko_5 = '주차장 입구는 본관 오른쪽에 있어요.' WHERE id = 'w_transport_A1_16';
UPDATE words SET example_en_2 = 'Go straight on for about half a kilometre and you will see the sign.', example_ko_2 = '약 500미터 직진하면 표지판이 보일 거예요.', example_en_3 = 'The road goes straight through the valley.', example_ko_3 = '도로가 계곡을 통해 직선으로 이어져요.', example_en_4 = 'Continue straight at the crossroads.', example_ko_4 = '교차로에서 직진하세요.', example_en_5 = 'If you go straight, you will reach the harbour in ten minutes.', example_ko_5 = '직진하면 10분 안에 항구에 도착해요.' WHERE id = 'w_transport_A1_17';
UPDATE words SET example_en_2 = 'I downloaded a map of the metro system before my trip.', example_ko_2 = '여행 전에 지하철 노선도를 다운로드했어요.', example_en_3 = 'The map shows all the bus routes in the city.', example_ko_3 = '지도에 도시의 모든 버스 노선이 표시되어 있어요.', example_en_4 = 'Could you mark the station on the map for me?', example_ko_4 = '지도에 역 위치를 표시해 주실 수 있나요?', example_en_5 = 'The tourist map includes the main transport links.', example_ko_5 = '관광 지도에는 주요 교통 연결 정보가 포함되어 있어요.' WHERE id = 'w_transport_A1_18';
UPDATE words SET example_en_2 = 'The station has four platforms and a large waiting area.', example_ko_2 = '역에는 4개의 승강장과 넓은 대기 공간이 있어요.', example_en_3 = 'I will meet you in front of the station at noon.', example_ko_3 = '정오에 역 앞에서 만나요.', example_en_4 = 'The station was completely renovated last year.', example_ko_4 = '역은 작년에 완전히 개보수되었어요.', example_en_5 = 'There are lockers at the station where you can leave your bags.', example_ko_5 = '역에 짐을 맡길 수 있는 보관함이 있어요.' WHERE id = 'w_transport_A1_19';
UPDATE words SET example_en_2 = 'The airport has three terminals for international flights.', example_ko_2 = '공항에는 국제선을 위한 터미널이 세 개 있어요.', example_en_3 = 'We arrived at the airport two hours before departure.', example_ko_3 = '출발 두 시간 전에 공항에 도착했어요.', example_en_4 = 'The airport is connected to the city by a direct rail link.', example_ko_4 = '공항은 직통 철도로 도시와 연결되어 있어요.', example_en_5 = 'You should check in at the airport at least ninety minutes early.', example_ko_5 = '공항에서는 최소 90분 전에 체크인하는 것이 좋아요.' WHERE id = 'w_transport_A1_20';
UPDATE words SET example_en_2 = 'We took a boat trip along the river to see the city.', example_ko_2 = '도시를 구경하려고 강에서 보트 여행을 했어요.', example_en_3 = 'The boat leaves for the island every two hours.', example_ko_3 = '배는 2시간마다 섬으로 출발해요.', example_en_4 = 'It was a small fishing boat, not a passenger ferry.', example_ko_4 = '승객용 페리가 아니라 작은 어선이었어요.', example_en_5 = 'The boat journey takes about forty minutes in calm weather.', example_ko_5 = '날씨가 잔잔할 때 보트 여행은 약 40분 걸려요.' WHERE id = 'w_transport_A1_21';
UPDATE words SET example_en_2 = 'The plane landed twenty minutes ahead of schedule.', example_ko_2 = '비행기가 예정보다 20분 일찍 착륙했어요.', example_en_3 = 'I am nervous about taking the plane for the first time.', example_ko_3 = '처음으로 비행기를 타는 것이 긴장돼요.', example_en_4 = 'The plane was full, so there were no upgrades available.', example_ko_4 = '비행기가 만석이라 업그레이드가 불가능했어요.', example_en_5 = 'We watched the plane take off from the observation deck.', example_ko_5 = '전망대에서 비행기가 이륙하는 것을 구경했어요.' WHERE id = 'w_transport_A1_22';
UPDATE words SET example_en_2 = 'The bridge connects the two sides of the river.', example_ko_2 = '다리는 강의 양쪽을 연결해요.', example_en_3 = 'The old bridge was rebuilt to handle heavier traffic.', example_ko_3 = '더 많은 차량을 수용하기 위해 오래된 다리를 재건했어요.', example_en_4 = 'You can see the whole city from the top of the bridge.', example_ko_4 = '다리 위에서 도시 전체를 볼 수 있어요.', example_en_5 = 'The bridge was temporarily closed for safety inspections.', example_ko_5 = '안전 점검을 위해 다리가 일시적으로 폐쇄되었어요.' WHERE id = 'w_transport_A1_23';
UPDATE words SET example_en_2 = 'The hotel is on the main street, just opposite the station.', example_ko_2 = '호텔은 역 바로 맞은편 큰길에 있어요.', example_en_3 = 'The street was very busy with pedestrians and cyclists.', example_ko_3 = '거리에는 보행자와 자전거 이용자로 매우 붐볐어요.', example_en_4 = 'There are food stalls all along this street.', example_ko_4 = '이 거리 곳곳에 음식 노점이 있어요.', example_en_5 = 'The tram runs along the main street every five minutes.', example_ko_5 = '트램은 5분마다 큰길을 따라 운행해요.' WHERE id = 'w_transport_A1_24';
UPDATE words SET example_en_2 = 'Wait at the corner and I will come to pick you up.', example_ko_2 = '모퉁이에서 기다리세요, 제가 데리러 갈게요.', example_en_3 = 'There is a small café on the corner of the street.', example_ko_3 = '거리 모퉁이에 작은 카페가 있어요.', example_en_4 = 'Turn the corner and the bus stop will be on your right.', example_ko_4 = '모퉁이를 돌면 오른쪽에 버스 정류장이 있어요.', example_en_5 = 'The accident happened at the corner near the school.', example_ko_5 = '사고는 학교 근처 모퉁이에서 일어났어요.' WHERE id = 'w_transport_A1_25';
UPDATE words SET example_en_2 = 'Please drive slow — the road surface is very slippery.', example_ko_2 = '천천히 운전하세요 — 도로가 매우 미끄러워요.', example_en_3 = 'The traffic was slow because of the roadworks.', example_ko_3 = '도로 공사 때문에 교통이 느렸어요.', example_en_4 = 'The ferry moved slow through the fog.', example_ko_4 = '페리가 안개 속에서 천천히 이동했어요.', example_en_5 = 'A slow bus is better than no bus at all.', example_ko_5 = '느린 버스라도 없는 것보다는 나아요.' WHERE id = 'w_transport_A1_26';
UPDATE words SET example_en_2 = 'The express train is much faster than the local service.', example_ko_2 = '급행 열차는 일반 열차보다 훨씬 빠르게 가요.', example_en_3 = 'Drive fast or we will miss the ferry.', example_ko_3 = '빨리 달리지 않으면 페리를 놓쳐요.', example_en_4 = 'The new metro line made getting across the city much faster.', example_ko_4 = '새 지하철 노선 덕분에 도시를 가로지르는 것이 훨씬 빠르게 됐어요.', example_en_5 = 'Time flies fast when you are travelling on a comfortable train.', example_ko_5 = '편안한 기차를 타고 여행할 때는 시간이 빠르게 가요.' WHERE id = 'w_transport_A1_27';
UPDATE words SET example_en_2 = 'Children under five travel free on public transport.', example_ko_2 = '5세 미만 어린이는 대중교통을 무료로 이용할 수 있어요.', example_en_3 = 'Is parking free at the airport on weekdays?', example_ko_3 = '평일에 공항 주차가 무료인가요?', example_en_4 = 'The shuttle to the hotel is free for all guests.', example_ko_4 = '호텔 셔틀버스는 모든 투숙객에게 무료예요.', example_en_5 = 'The bus is free during the city festival weekend.', example_ko_5 = '도시 축제 주말 동안 버스가 무료로 운행해요.' WHERE id = 'w_transport_A1_28';
UPDATE words SET example_en_2 = 'Please hold the door for the passenger with the pram.', example_ko_2 = '유모차를 가진 승객을 위해 문을 잡아 주세요.', example_en_3 = 'Stand clear of the doors when the train is about to depart.', example_ko_3 = '기차가 출발할 때 문 근처에서 물러서 주세요.', example_en_4 = 'The automatic door on the bus was not working properly.', example_ko_4 = '버스의 자동문이 제대로 작동하지 않았어요.', example_en_5 = 'The door of the carriage is on the left side of the train.', example_ko_5 = '객차 문은 기차의 왼쪽에 있어요.' WHERE id = 'w_transport_A1_29';
UPDATE words SET example_en_2 = 'I could not find a free seat anywhere on the train.', example_ko_2 = '기차 어디에도 빈 자리를 찾을 수 없었어요.', example_en_3 = 'Please take your seat before the bus moves.', example_ko_3 = '버스가 출발하기 전에 자리에 앉아 주세요.', example_en_4 = 'I reserved a window seat on the flight to London.', example_ko_4 = '런던행 비행기의 창가 좌석을 예약했어요.', example_en_5 = 'The priority seats near the door are for elderly passengers.', example_ko_5 = '문 근처의 우선 좌석은 노약자를 위한 것이에요.' WHERE id = 'w_transport_A1_30';
UPDATE words SET example_en_2 = 'We had to wait over an hour for the delayed train.', example_ko_2 = '지연된 기차를 한 시간 이상 기다려야 했어요.', example_en_3 = 'Please wait in the queue and the next agent will help you.', example_ko_3 = '줄에서 기다려 주세요, 다음 담당자가 도와드릴 거예요.', example_en_4 = 'I always wait for the bus inside the shelter when it rains.', example_ko_4 = '비가 오면 항상 대기 공간 안에서 버스를 기다려요.', example_en_5 = 'How long do we need to wait for the next connection?', example_ko_5 = '다음 연결편을 얼마나 기다려야 하나요?' WHERE id = 'w_transport_A1_31';
UPDATE words SET example_en_2 = 'Could you help me find the right platform?', example_ko_2 = '올바른 승강장을 찾는 데 도움을 주실 수 있나요?', example_en_3 = 'The station staff helped me carry my bags up the stairs.', example_ko_3 = '역 직원이 계단 위로 가방을 옮기는 것을 도와줬어요.', example_en_4 = 'I asked a local to help me read the bus timetable.', example_ko_4 = '현지인에게 버스 시간표 읽는 것을 도와달라고 부탁했어요.', example_en_5 = 'The app helps you plan the fastest route across the city.', example_ko_5 = '그 앱은 도시를 가로지르는 가장 빠른 경로를 계획하는 데 도움이 돼요.' WHERE id = 'w_transport_A1_32';
UPDATE words SET example_en_2 = 'There was a long line of passengers waiting to board.', example_ko_2 = '탑승을 기다리는 승객들이 긴 줄을 이루고 있었어요.', example_en_3 = 'Join the line here and wait for the next available taxi.', example_ko_3 = '여기 줄을 서서 다음 택시를 기다리세요.', example_en_4 = 'The metro red line runs from the airport to the city centre.', example_ko_4 = '지하철 빨간 노선은 공항에서 시내까지 운행해요.', example_en_5 = 'You need to stay inside the line marked on the platform.', example_ko_5 = '승강장에 표시된 선 안에 있어야 해요.' WHERE id = 'w_transport_A1_33';
UPDATE words SET example_en_2 = 'What is the bus number for the city centre?', example_ko_2 = '시내까지 가는 버스 번호가 무엇인가요?', example_en_3 = 'The platform number is displayed on the departure board.', example_ko_3 = '승강장 번호는 출발 안내판에 표시되어 있어요.', example_en_4 = 'Please note my contact number in case of any changes.', example_ko_4 = '변경 사항이 있을 경우를 대비해 제 연락처를 메모해 두세요.', example_en_5 = 'The train number and time are printed on the ticket.', example_ko_5 = '열차 번호와 시간이 표에 인쇄되어 있어요.' WHERE id = 'w_transport_A1_34';
UPDATE words SET example_en_2 = 'Get off the bus here — we have arrived at the station.', example_ko_2 = '여기서 버스에서 내리세요 — 역에 도착했어요.', example_en_3 = 'Is this the right stop? I think we are here.', example_ko_3 = '이 정류장이 맞나요? 우리가 도착한 것 같아요.', example_en_4 = 'I will wait for you here by the main entrance.', example_ko_4 = '정문 옆 여기서 기다릴게요.', example_en_5 = 'The sign says you cannot park here between eight and six.', example_ko_5 = '표지판에 8시에서 6시 사이에는 여기에 주차할 수 없다고 나와 있어요.' WHERE id = 'w_transport_A1_35';
UPDATE words SET example_en_2 = 'The subway is the fastest way to get around Seoul.', example_ko_2 = '지하철은 서울을 이동하는 가장 빠른 방법이에요.', example_en_3 = 'I take the subway twice a day for my commute.', example_ko_3 = '출퇴근할 때 하루에 두 번 지하철을 이용해요.', example_en_4 = 'The subway map can be confusing at first, but you get used to it.', example_ko_4 = '처음에는 지하철 노선도가 복잡할 수 있지만 익숙해져요.', example_en_5 = 'You can transfer between lines without paying an extra fare.', example_ko_5 = '추가 요금 없이 노선 간 환승이 가능해요.' WHERE id = 'w_transport_A2_01';
UPDATE words SET example_en_2 = 'The train leaves from platform seven in five minutes.', example_ko_2 = '기차는 5분 후에 7번 승강장에서 출발해요.', example_en_3 = 'Please stand behind the yellow line on the platform.', example_ko_3 = '승강장에서 노란 선 뒤에 서 주세요.', example_en_4 = 'The platform was crowded with commuters during rush hour.', example_ko_4 = '러시아워에 승강장이 통근자들로 붐볐어요.', example_en_5 = 'Check the departure board to find your platform number.', example_ko_5 = '출발 안내판에서 승강장 번호를 확인하세요.' WHERE id = 'w_transport_A2_02';
UPDATE words SET example_en_2 = 'You need to transfer at City Hall station for the green line.', example_ko_2 = '초록 노선으로 가려면 시청역에서 환승해야 해요.', example_en_3 = 'The transfer point is well-signposted throughout the station.', example_ko_3 = '환승 지점은 역 전체에 표지판이 잘 되어 있어요.', example_en_4 = 'There is no need to transfer — this train goes all the way.', example_ko_4 = '환승할 필요 없어요 — 이 기차가 끝까지 가요.', example_en_5 = 'A free transfer is allowed within thirty minutes of tapping in.', example_ko_5 = '태그 후 30분 이내에 무료 환승이 허용돼요.' WHERE id = 'w_transport_A2_03';
UPDATE words SET example_en_2 = 'The schedule shows that the next bus leaves at quarter past three.', example_ko_2 = '시간표에 다음 버스가 3시 15분에 출발한다고 나와 있어요.', example_en_3 = 'I always check the train schedule the night before I travel.', example_ko_3 = '여행 전날 밤에 항상 기차 시간표를 확인해요.', example_en_4 = 'The ferry schedule changes during the winter months.', example_ko_4 = '페리 일정은 겨울철에 바뀌어요.', example_en_5 = 'The schedule has been updated due to track maintenance.', example_ko_5 = '선로 유지보수로 인해 시간표가 변경되었어요.' WHERE id = 'w_transport_A2_04';
UPDATE words SET example_en_2 = 'What is the standard fare between these two stations?', example_ko_2 = '이 두 역 사이의 기본 요금이 얼마인가요?', example_en_3 = 'The fare is cheaper if you buy a weekly pass.', example_ko_3 = '주간 정기권을 구입하면 요금이 더 저렴해요.', example_en_4 = 'Children aged five to twelve pay half fare.', example_ko_4 = '5세에서 12세 어린이는 반액 요금을 내요.', example_en_5 = 'The fare machine accepts contactless payment now.', example_ko_5 = '요금 기계는 이제 비접촉 결제를 받아요.' WHERE id = 'w_transport_A2_05';
UPDATE words SET example_en_2 = 'Which route avoids the main road during rush hour?', example_ko_2 = '러시아워에 큰 도로를 피하는 경로가 어느 것인가요?', example_en_3 = 'The bus route runs from the suburbs all the way to the centre.', example_ko_3 = '버스 노선은 외곽에서 중심가까지 운행해요.', example_en_4 = 'I planned my route using the transport app on my phone.', example_ko_4 = '휴대폰 교통 앱을 이용해 경로를 계획했어요.', example_en_5 = 'Take route twelve and get off at the third stop.', example_ko_5 = '12번 노선을 타고 세 번째 정류장에서 내리세요.' WHERE id = 'w_transport_A2_06';
UPDATE words SET example_en_2 = 'The departure lounge was packed with passengers.', example_ko_2 = '출발 라운지가 승객들로 가득 찼어요.', example_en_3 = 'What time is the scheduled departure for this flight?', example_ko_3 = '이 비행기의 예정 출발 시간이 언제인가요?', example_en_4 = 'Please go to the gate thirty minutes before departure.', example_ko_4 = '출발 30분 전에 탑승구로 가세요.', example_en_5 = 'The early departure time meant we had to leave home at five.', example_ko_5 = '출발 시간이 일러서 집에서 5시에 나와야 했어요.' WHERE id = 'w_transport_A2_07';
UPDATE words SET example_en_2 = 'The arrival of the train was announced over the loudspeaker.', example_ko_2 = '기차 도착이 스피커로 안내되었어요.', example_en_3 = 'Estimated arrival time is two-thirty in the afternoon.', example_ko_3 = '예상 도착 시간은 오후 2시 30분이에요.', example_en_4 = 'Please wait in the arrivals hall for your family.', example_ko_4 = '가족을 위해 도착 홀에서 기다려 주세요.', example_en_5 = 'The arrival of the ferry was delayed by bad weather.', example_ko_5 = '악천후로 인해 페리 도착이 지연되었어요.' WHERE id = 'w_transport_A2_08';
UPDATE words SET example_en_2 = 'The delay was caused by a broken down vehicle on the line.', example_ko_2 = '노선 위에 고장난 차량으로 인해 지연이 발생했어요.', example_en_3 = 'I apologise for the delay — it was unavoidable.', example_ko_3 = '지연에 대해 사과드려요 — 피할 수 없었어요.', example_en_4 = 'Passengers were offered a refund after the lengthy delay.', example_ko_4 = '오랜 지연 후 승객들에게 환불이 제공되었어요.', example_en_5 = 'A delay of more than thirty minutes entitles you to compensation.', example_ko_5 = '30분 이상의 지연은 보상을 받을 자격이 생겨요.' WHERE id = 'w_transport_A2_09';
UPDATE words SET example_en_2 = 'The express service reaches the capital in under two hours.', example_ko_2 = '급행 서비스로 2시간 이내에 수도에 도착해요.', example_en_3 = 'Is there an express bus to the airport from here?', example_ko_3 = '여기서 공항까지 가는 급행 버스가 있나요?', example_en_4 = 'The express lane was reserved for vehicles with four or more passengers.', example_ko_4 = '급행 차선은 탑승자가 4명 이상인 차량을 위해 지정되어 있었어요.', example_en_5 = 'I always take the express train when I am in a hurry.', example_ko_5 = '바쁠 때는 항상 급행 열차를 이용해요.' WHERE id = 'w_transport_A2_10';
UPDATE words SET example_en_2 = 'The local bus stops at every village along the coast road.', example_ko_2 = '지역 버스는 해안 도로를 따라 모든 마을에 정차해요.', example_en_3 = 'I prefer the local train — you get to see more of the countryside.', example_ko_3 = '저는 지역 기차를 더 좋아해요 — 시골 풍경을 더 많이 볼 수 있으니까요.', example_en_4 = 'The local service is slower but costs less than the express.', example_ko_4 = '지역 서비스는 급행보다 느리지만 비용이 적게 들어요.', example_en_5 = 'Local taxis are often cheaper than the app-based ones.', example_ko_5 = '지역 택시는 앱 기반 택시보다 종종 더 저렴해요.' WHERE id = 'w_transport_A2_11';
UPDATE words SET example_en_2 = 'Can you give me directions to the nearest underground station?', example_ko_2 = '가장 가까운 지하철역까지 가는 방향을 알려 주실 수 있나요?', example_en_3 = 'The direction of travel is shown by an arrow on the platform.', example_ko_3 = '이동 방향은 승강장의 화살표로 표시되어 있어요.', example_en_4 = 'I was travelling in the wrong direction for ten minutes.', example_ko_4 = '10분 동안 반대 방향으로 이동하고 있었어요.', example_en_5 = 'The signpost shows the direction to the ferry terminal.', example_ko_5 = '표지판에 페리 터미널로 가는 방향이 표시되어 있어요.' WHERE id = 'w_transport_A2_12';
UPDATE words SET example_en_2 = 'What is the distance from the hotel to the city centre on foot?', example_ko_2 = '호텔에서 시내까지 도보 거리가 얼마나 되나요?', example_en_3 = 'The map shows the distance between each stop clearly.', example_ko_3 = '지도에 각 정류장 간 거리가 명확하게 표시되어 있어요.', example_en_4 = 'The total distance of the route is around forty kilometres.', example_ko_4 = '노선의 총 거리는 약 40킬로미터예요.', example_en_5 = 'A long distance between stops means fewer options in that area.', example_ko_5 = '정류장 간 거리가 길면 그 지역의 선택지가 적어져요.' WHERE id = 'w_transport_A2_13';
UPDATE words SET example_en_2 = 'All passengers must have a valid ticket before boarding.', example_ko_2 = '모든 승객은 탑승 전에 유효한 티켓을 소지해야 해요.', example_en_3 = 'The passenger next to me was very helpful with the directions.', example_ko_3 = '옆에 앉은 승객이 방향 안내에 매우 친절했어요.', example_en_4 = 'Passengers are asked to keep their luggage in the overhead rack.', example_ko_4 = '승객들은 짐을 머리 위 선반에 보관해 달라는 요청을 받아요.', example_en_5 = 'The number of passengers on the metro increases significantly at rush hour.', example_ko_5 = '지하철 승객 수는 러시아워에 크게 증가해요.' WHERE id = 'w_transport_A2_14';
UPDATE words SET example_en_2 = 'The bus driver announced the next stop over the intercom.', example_ko_2 = '버스 기사님이 인터컴으로 다음 정류장을 안내했어요.', example_en_3 = 'The taxi driver took a longer route to avoid the congestion.', example_ko_3 = '택시 기사님이 혼잡을 피하려고 더 긴 경로를 택했어요.', example_en_4 = 'The driver pulled over to let the ambulance pass.', example_ko_4 = '기사님이 구급차를 통과시키기 위해 차를 길 가장자리에 세웠어요.', example_en_5 = 'The delivery driver is responsible for checking the goods on arrival.', example_ko_5 = '배달 기사는 도착 시 물품을 확인할 책임이 있어요.' WHERE id = 'w_transport_A2_15';
UPDATE words SET example_en_2 = 'The traffic in the city centre was unusually heavy today.', example_ko_2 = '오늘 시내 교통이 평소보다 심했어요.', example_en_3 = 'Traffic can grind to a halt at this junction during peak hours.', example_ko_3 = '이 교차로는 혼잡 시간대에 교통이 완전히 막힐 수 있어요.', example_en_4 = 'The traffic was moving smoothly after the roadworks were completed.', example_ko_4 = '도로 공사가 완료된 후 교통이 원활하게 흘렀어요.', example_en_5 = 'You should check the traffic report before heading to the airport.', example_ko_5 = '공항으로 출발하기 전에 교통 정보를 확인하세요.' WHERE id = 'w_transport_A2_16';
UPDATE words SET example_en_2 = 'Parking near the station costs five thousand won per hour.', example_ko_2 = '역 근처 주차는 시간당 5천 원이에요.', example_en_3 = 'There is a free parking area about ten minutes from the terminal.', example_ko_3 = '터미널에서 약 10분 거리에 무료 주차 구역이 있어요.', example_en_4 = 'Parking is very limited in the city centre at weekends.', example_ko_4 = '주말에는 시내 주차 공간이 매우 부족해요.', example_en_5 = 'Double-yellow lines mean no parking at any time.', example_ko_5 = '이중 노란 선은 언제든지 주차가 금지된다는 의미예요.' WHERE id = 'w_transport_A2_17';
UPDATE words SET example_en_2 = 'A return ticket is cheaper if you book both legs together.', example_ko_2 = '두 구간을 함께 예약하면 왕복 티켓이 더 저렴해요.', example_en_3 = 'I need a return ticket to Incheon for this weekend.', example_ko_3 = '이번 주말 인천행 왕복 티켓이 필요해요.', example_en_4 = 'The return journey was much quicker than the outward trip.', example_ko_4 = '귀환 여정이 출발 여정보다 훨씬 빨랐어요.', example_en_5 = 'The return fare includes all taxes and booking fees.', example_ko_5 = '왕복 요금에는 모든 세금과 예약 수수료가 포함되어 있어요.' WHERE id = 'w_transport_A2_18';
UPDATE words SET example_en_2 = 'I only need a single ticket — I am not coming back today.', example_ko_2 = '편도 티켓만 필요해요 — 오늘은 돌아오지 않을 거예요.', example_en_3 = 'A single fare costs less than a return in most cases.', example_ko_3 = '대부분의 경우 편도 요금이 왕복보다 저렴해요.', example_en_4 = 'Is a single ticket valid for transfers within an hour?', example_ko_4 = '편도 티켓은 1시간 이내 환승에도 유효한가요?', example_en_5 = 'Please give me one single to Central Station.', example_ko_5 = '중앙역까지 편도 한 장 주세요.' WHERE id = 'w_transport_A2_19';
UPDATE words SET example_en_2 = 'There is a good connection between the airport rail and the metro.', example_ko_2 = '공항 철도와 지하철 간에 연결이 잘 되어 있어요.', example_en_3 = 'I missed the connection because the first train was late.', example_ko_3 = '첫 번째 기차가 늦어서 연결편을 놓쳤어요.', example_en_4 = 'The connection time at the hub station is only seven minutes.', example_ko_4 = '중간 역에서의 연결 시간이 겨우 7분이에요.', example_en_5 = 'There is a direct connection to the ferry port from here.', example_ko_5 = '여기서 페리 항구까지 직행 연결이 있어요.' WHERE id = 'w_transport_A2_20';
UPDATE words SET example_en_2 = 'The airline had to cancel the flight due to bad weather.', example_ko_2 = '항공사는 악천후로 인해 항공편을 취소해야 했어요.', example_en_3 = 'If the train is cancelled, you are entitled to a full refund.', example_ko_3 = '기차가 취소되면 전액 환불을 받을 수 있어요.', example_en_4 = 'I decided to cancel my taxi booking and walk instead.', example_ko_4 = '택시 예약을 취소하고 대신 걷기로 했어요.', example_en_5 = 'The bus service was cancelled on the public holiday.', example_ko_5 = '공휴일에 버스 서비스가 운행 취소되었어요.' WHERE id = 'w_transport_A2_21';
UPDATE words SET example_en_2 = 'Passengers should board the train from the front carriages.', example_ko_2 = '승객들은 앞 객차에서 기차에 탑승해야 해요.', example_en_3 = 'Please board quickly so we can depart on time.', example_ko_3 = '정시에 출발할 수 있도록 빠르게 탑승해 주세요.', example_en_4 = 'You may board the ferry thirty minutes before departure.', example_ko_4 = '출발 30분 전부터 페리에 탑승할 수 있어요.', example_en_5 = 'I always board last to avoid the rush.', example_ko_5 = '서두르는 것을 피하려고 항상 마지막에 탑승해요.' WHERE id = 'w_transport_A2_22';
UPDATE words SET example_en_2 = 'You are allowed one piece of hand luggage and one checked bag.', example_ko_2 = '기내 수하물 한 개와 위탁 수하물 한 개가 허용돼요.', example_en_3 = 'I left my luggage at the station and picked it up later.', example_ko_3 = '역에 짐을 맡겨 두고 나중에 찾았어요.', example_en_4 = 'The luggage was damaged when it came off the baggage belt.', example_ko_4 = '수하물이 컨베이어 벨트에서 나왔을 때 손상되어 있었어요.', example_en_5 = 'Please do not leave your luggage unattended on the platform.', example_ko_5 = '승강장에 짐을 방치하지 마세요.' WHERE id = 'w_transport_A2_23';
UPDATE words SET example_en_2 = 'The taxi rank outside the station was very long at that hour.', example_ko_2 = '그 시간에 역 밖 택시 승강장에 줄이 매우 길었어요.', example_en_3 = 'I queued at the taxi rank for nearly twenty minutes.', example_ko_3 = '택시 승강장에서 거의 20분을 기다렸어요.', example_en_4 = 'The taxi rank is clearly marked with a blue sign.', example_ko_4 = '택시 승강장은 파란 표지판으로 명확하게 표시되어 있어요.', example_en_5 = 'You cannot hail a cab here — you need to use the taxi rank.', example_ko_5 = '여기서는 택시를 불러 세울 수 없어요 — 택시 승강장을 이용해야 해요.' WHERE id = 'w_transport_A2_24';
UPDATE words SET example_en_2 = 'Please store your bags in the overhead compartment.', example_ko_2 = '가방을 머리 위 수납공간에 보관해 주세요.', example_en_3 = 'The overhead signs on the motorway show live traffic updates.', example_ko_3 = '고속도로의 머리 위 표지판에 실시간 교통 정보가 표시돼요.', example_en_4 = 'The overhead cable supplies power to the tram.', example_ko_4 = '머리 위 케이블이 트램에 전력을 공급해요.', example_en_5 = 'There was not enough space in the overhead bin for my bag.', example_ko_5 = '머리 위 선반에 제 가방을 넣을 공간이 부족했어요.' WHERE id = 'w_transport_A2_25';
UPDATE words SET example_en_2 = 'The subway gets very crowded during the morning rush hour.', example_ko_2 = '지하철은 아침 러시아워에 매우 붐벼요.', example_en_3 = 'I try to avoid travelling during rush hour whenever possible.', example_ko_3 = '가능하면 러시아워에 이동하는 것을 피하려고 해요.', example_en_4 = 'The fare is higher during rush hour on some transport services.', example_ko_4 = '일부 교통 서비스는 러시아워에 요금이 더 높아요.', example_en_5 = 'Rush hour traffic can double the usual journey time.', example_ko_5 = '러시아워 교통은 평소 이동 시간을 두 배로 늘릴 수 있어요.' WHERE id = 'w_transport_A2_26';
UPDATE words SET example_en_2 = 'Always use the pedestrian crossing when crossing a busy road.', example_ko_2 = '바쁜 도로를 건널 때는 항상 횡단보도를 이용하세요.', example_en_3 = 'The pedestrian crossing near the school has flashing lights.', example_ko_3 = '학교 근처의 횡단보도에는 점멸등이 있어요.', example_en_4 = 'Wait for the green signal before stepping onto the pedestrian crossing.', example_ko_4 = '횡단보도에 발을 딛기 전에 녹색 신호를 기다리세요.', example_en_5 = 'Drivers must stop at a pedestrian crossing when someone is waiting.', example_ko_5 = '누군가 기다리고 있을 때 운전자는 횡단보도에서 멈춰야 해요.' WHERE id = 'w_transport_A2_27';
UPDATE words SET example_en_2 = 'The traffic signal at that junction has been faulty all week.', example_ko_2 = '그 교차로의 신호등이 일주일 내내 고장나 있었어요.', example_en_3 = 'Always obey the signal — even if the road looks clear.', example_ko_3 = '도로가 비어 있어 보여도 항상 신호를 따르세요.', example_en_4 = 'The signal changed to red just as we reached the junction.', example_ko_4 = '교차로에 도착했을 때 신호가 빨간불로 바뀌었어요.', example_en_5 = 'A green signal was given and the train moved slowly out of the station.', example_ko_5 = '녹색 신호가 켜지자 기차가 천천히 역을 빠져나갔어요.' WHERE id = 'w_transport_A2_28';
UPDATE words SET example_en_2 = 'Cyclists must stay in the designated cycle lane.', example_ko_2 = '자전거 이용자는 지정된 자전거 도로에 있어야 해요.', example_en_3 = 'The outside lane was closed because of an accident.', example_ko_3 = '사고로 인해 바깥 차선이 폐쇄되었어요.', example_en_4 = 'Keep to the left lane if you are not overtaking.', example_ko_4 = '추월하지 않는 경우 왼쪽 차선을 유지하세요.', example_en_5 = 'The bus has its own dedicated lane to avoid traffic.', example_ko_5 = '버스는 교통 체증을 피하기 위한 전용 차선이 있어요.' WHERE id = 'w_transport_A2_29';
UPDATE words SET example_en_2 = 'The timetable is posted on the wall inside the station.', example_ko_2 = '시간표는 역 내부 벽에 게시되어 있어요.', example_en_3 = 'I checked the timetable and there is a train every twenty minutes.', example_ko_3 = '시간표를 확인하니 20분마다 기차가 있어요.', example_en_4 = 'The timetable changes during public holidays and bank holidays.', example_ko_4 = '시간표는 공휴일과 법정공휴일에 변경돼요.', example_en_5 = 'You can download the full timetable from the transport authority website.', example_ko_5 = '교통 당국 웹사이트에서 전체 시간표를 다운로드할 수 있어요.' WHERE id = 'w_transport_A2_30';
UPDATE words SET example_en_2 = 'The underground network covers most parts of the city.', example_ko_2 = '지하 노선망은 도시 대부분의 지역을 커버해요.', example_en_3 = 'I got lost on the underground because I boarded the wrong train.', example_ko_3 = '잘못된 기차에 탑승해서 지하철에서 길을 잃었어요.', example_en_4 = 'The underground is the quickest way across the city at peak times.', example_ko_4 = '혼잡 시간대에 지하철이 도시를 가로지르는 가장 빠른 방법이에요.', example_en_5 = 'Mobile phone signals are often poor on the underground.', example_ko_5 = '지하철에서는 휴대폰 신호가 종종 좋지 않아요.' WHERE id = 'w_transport_A2_31';
UPDATE words SET example_en_2 = 'The first-class carriage is at the front of the train.', example_ko_2 = '1등석 객차는 기차 맨 앞에 있어요.', example_en_3 = 'The carriage was almost empty when we boarded at the last station.', example_ko_3 = '마지막 역에서 탑승했을 때 객차가 거의 비어 있었어요.', example_en_4 = 'Please make sure you are in the correct carriage for your seat.', example_ko_4 = '자신의 좌석에 맞는 올바른 객차에 타고 있는지 확인해 주세요.', example_en_5 = 'The dining carriage is located in the middle of the train.', example_ko_5 = '식당 객차는 기차 중간에 위치해 있어요.' WHERE id = 'w_transport_A2_32';
UPDATE words SET example_en_2 = 'Private vehicles are not permitted in the city centre on weekdays.', example_ko_2 = '평일에 도심 내 개인 차량은 허용되지 않아요.', example_en_3 = 'The vehicle broke down and blocked traffic for an hour.', example_ko_3 = '차량이 고장나서 한 시간 동안 교통을 막았어요.', example_en_4 = 'The emergency vehicle arrived within five minutes.', example_ko_4 = '응급 차량이 5분 이내에 도착했어요.', example_en_5 = 'All vehicles must stop at the level crossing when the barrier is down.', example_ko_5 = '차단기가 내려가면 모든 차량은 철도 건널목에서 멈춰야 해요.' WHERE id = 'w_transport_A2_33';
UPDATE words SET example_en_2 = 'The train arrived exactly on time, which rarely happens.', example_ko_2 = '기차가 정확히 제 시간에 도착했는데, 그런 일은 드물어요.', example_en_3 = 'We arrived at the airport with very little time to spare.', example_ko_3 = '공항에 시간이 거의 없는 상태로 도착했어요.', example_en_4 = 'The bus is expected to arrive at half past four.', example_ko_4 = '버스는 4시 30분에 도착할 예정이에요.', example_en_5 = 'She arrived at the station just as the train was pulling in.', example_ko_5 = '기차가 들어오던 그 순간에 역에 도착했어요.' WHERE id = 'w_transport_A2_34';
UPDATE words SET example_en_2 = 'The flight departs from gate twenty-two at noon.', example_ko_2 = '비행기는 정오에 22번 게이트에서 출발해요.', example_en_3 = 'The last ferry departs at nine in the evening.', example_ko_3 = '마지막 페리는 저녁 9시에 출발해요.', example_en_4 = 'We need to depart early to avoid the morning rush hour.', example_ko_4 = '아침 러시아워를 피하려면 일찍 출발해야 해요.', example_en_5 = 'All passengers should be at the gate before the train departs.', example_ko_5 = '기차가 출발하기 전에 모든 승객은 탑승구에 있어야 해요.' WHERE id = 'w_transport_A2_35';
UPDATE words SET example_en_2 = 'My daily commute takes just over an hour each way.', example_ko_2 = '제 일일 통근은 편도로 한 시간 남짓 걸려요.', example_en_3 = 'I switched to cycling to make my commute more enjoyable.', example_ko_3 = '통근을 더 즐겁게 하기 위해 자전거를 타기 시작했어요.', example_en_4 = 'The commute on this line is particularly bad on Mondays.', example_ko_4 = '이 노선의 월요일 통근은 특히 힘들어요.', example_en_5 = 'Working from home two days a week has shortened my commute significantly.', example_ko_5 = '주 2일 재택근무로 통근 시간이 크게 줄었어요.' WHERE id = 'w_transport_B1_01';
UPDATE words SET example_en_2 = 'Congestion in the tunnels caused delays of up to forty minutes.', example_ko_2 = '터널 내 혼잡으로 최대 40분의 지연이 발생했어요.', example_en_3 = 'The city introduced a charge to reduce congestion in the centre.', example_ko_3 = '시내 혼잡을 줄이기 위해 도시에서 요금을 도입했어요.', example_en_4 = 'Congestion is at its worst between seven and nine in the morning.', example_ko_4 = '혼잡은 오전 7시에서 9시 사이에 가장 심해요.', example_en_5 = 'Smart traffic lights have been installed to ease congestion at key junctions.', example_ko_5 = '주요 교차로의 혼잡을 완화하기 위해 스마트 신호등이 설치되었어요.' WHERE id = 'w_transport_B1_02';
UPDATE words SET example_en_2 = 'We set up a carpool with four colleagues who live nearby.', example_ko_2 = '근처에 사는 동료 네 명과 카풀을 조직했어요.', example_en_3 = 'Carpool schemes can significantly reduce the number of vehicles on the road.', example_ko_3 = '카풀 제도는 도로 위 차량 수를 크게 줄일 수 있어요.', example_en_4 = 'The company encourages staff to carpool by offering subsidised parking.', example_ko_4 = '회사는 주차비 지원을 통해 직원들의 카풀을 장려해요.', example_en_5 = 'We take turns driving as part of our carpool arrangement.', example_ko_5 = '카풀 약정의 일환으로 번갈아 운전해요.' WHERE id = 'w_transport_B1_03';
UPDATE words SET example_en_2 = 'The bus terminal was undergoing major renovation works.', example_ko_2 = '버스 터미널이 대규모 리노베이션 공사 중이었어요.', example_en_3 = 'Which terminal does my airline use at this airport?', example_ko_3 = '제 항공사는 이 공항의 어느 터미널을 이용하나요?', example_en_4 = 'The terminal has free Wi-Fi and a range of cafes and shops.', example_ko_4 = '터미널에는 무료 와이파이와 다양한 카페 및 상점이 있어요.', example_en_5 = 'Passengers transferring between terminals should allow at least an hour.', example_ko_5 = '터미널 간 이동 승객은 최소 한 시간은 여유를 두어야 해요.' WHERE id = 'w_transport_B1_04';
UPDATE words SET example_en_2 = 'There was a serious accident at the junction of the two main roads.', example_ko_2 = '두 주요 도로가 만나는 교차로에서 심각한 사고가 발생했어요.', example_en_3 = 'The traffic lights at this junction are often broken.', example_ko_3 = '이 교차로의 신호등이 자주 고장나요.', example_en_4 = 'Turn right at the junction and head straight for two kilometres.', example_ko_4 = '교차로에서 우회전한 뒤 2킬로미터 직진하세요.', example_en_5 = 'The new flyover was built to ease congestion at the main junction.', example_ko_5 = '주요 교차로의 혼잡을 해소하기 위해 새로운 고가도로가 건설되었어요.' WHERE id = 'w_transport_B1_05';
UPDATE words SET example_en_2 = 'Pedestrian safety is a priority in the city''s new transport plan.', example_ko_2 = '보행자 안전은 도시의 새로운 교통 계획에서 최우선 사항이에요.', example_en_3 = 'The street was made fully pedestrian to improve the shopping experience.', example_ko_3 = '쇼핑 경험을 개선하기 위해 거리를 완전한 보행자 전용으로 만들었어요.', example_en_4 = 'Pedestrian crossings were added at every junction along the high street.', example_ko_4 = '번화가의 모든 교차로에 횡단보도가 추가되었어요.', example_en_5 = 'Some pedestrian routes were blocked by the construction work.', example_ko_5 = '건설 공사로 인해 일부 보행자 경로가 막혔어요.' WHERE id = 'w_transport_B1_06';
UPDATE words SET example_en_2 = 'It is illegal to overtake on a solid white line.', example_ko_2 = '실선 흰색 선에서 추월하는 것은 불법이에요.', example_en_3 = 'The lorry tried to overtake on a narrow country road.', example_ko_3 = '트럭이 좁은 시골길에서 추월하려 했어요.', example_en_4 = 'Always check your mirrors before you attempt to overtake.', example_ko_4 = '추월하기 전에 항상 거울을 확인하세요.', example_en_5 = 'The car overtook the bus and then slowed down suddenly.', example_ko_5 = '차가 버스를 추월한 뒤 갑자기 속도를 늦췄어요.' WHERE id = 'w_transport_B1_07';
UPDATE words SET example_en_2 = 'Give way to traffic already on the roundabout.', example_ko_2 = '로터리에 이미 진입한 차량에게 양보하세요.', example_en_3 = 'The roundabout replaced the old traffic lights at the junction.', example_ko_3 = '로터리가 교차로의 기존 신호등을 대체했어요.', example_en_4 = 'Take the second exit at the roundabout to get to the station.', example_ko_4 = '역으로 가려면 로터리에서 두 번째 출구로 나가세요.', example_en_5 = 'The new roundabout has reduced the number of accidents significantly.', example_ko_5 = '새 로터리로 사고 건수가 크게 줄었어요.' WHERE id = 'w_transport_B1_08';
UPDATE words SET example_en_2 = 'The diversion added twenty minutes to our journey.', example_ko_2 = '우회로로 인해 여정에 20분이 추가되었어요.', example_en_3 = 'Signs were placed along the diversion route to guide drivers.', example_ko_3 = '운전자를 안내하기 위해 우회로를 따라 표지판이 설치되었어요.', example_en_4 = 'The tunnel closure meant a long diversion through the town centre.', example_ko_4 = '터널 폐쇄로 인해 도심을 통과하는 긴 우회로를 이용해야 했어요.', example_en_5 = 'A diversion was put in place while emergency repairs were carried out.', example_ko_5 = '긴급 수리가 이루어지는 동안 우회로가 설정되었어요.' WHERE id = 'w_transport_B1_09';
UPDATE words SET example_en_2 = 'The speed limit on this road is sixty kilometres per hour.', example_ko_2 = '이 도로의 제한 속도는 시속 60킬로미터예요.', example_en_3 = 'Drivers who exceed the speed limit face a fine.', example_ko_3 = '제한 속도를 초과하는 운전자는 벌금을 받아요.', example_en_4 = 'The speed limit drops to thirty near the school entrance.', example_ko_4 = '학교 입구 근처에서는 제한 속도가 30킬로미터로 낮아져요.', example_en_5 = 'Speed limit signs were poorly visible due to overgrown hedges.', example_ko_5 = '우거진 나무 때문에 속도 제한 표지판이 잘 보이지 않았어요.' WHERE id = 'w_transport_B1_10';
UPDATE words SET example_en_2 = 'The season ticket is popular among regular commuters.', example_ko_2 = '정기권은 통근자들 사이에서 인기가 많아요.', example_en_3 = 'As a commuter, I spend a lot of time on the platform each week.', example_ko_3 = '통근자로서 매주 승강장에서 많은 시간을 보내요.', example_en_4 = 'The commuter train was packed well beyond its normal capacity.', example_ko_4 = '통근 열차가 평상시 수용 인원을 훨씬 초과했어요.', example_en_5 = 'Long-distance commuters sometimes choose to rent accommodation closer to work.', example_ko_5 = '장거리 통근자들은 때때로 직장과 더 가까운 곳에 숙소를 구하기도 해요.' WHERE id = 'w_transport_B1_11';
UPDATE words SET example_en_2 = 'Please have your boarding pass ready at the gate.', example_ko_2 = '탑승구에서 탑승권을 준비해 두세요.', example_en_3 = 'You can download your boarding pass to your phone.', example_ko_3 = '탑승권을 휴대폰에 다운로드할 수 있어요.', example_en_4 = 'The boarding pass shows your seat number and gate information.', example_ko_4 = '탑승권에는 좌석 번호와 탑승구 정보가 표시되어 있어요.', example_en_5 = 'I forgot to print my boarding pass and had to do it at the airport.', example_ko_5 = '탑승권 출력을 잊어서 공항에서 출력해야 했어요.' WHERE id = 'w_transport_B1_12';
UPDATE words SET example_en_2 = 'The platform number for your train is displayed on the screen above.', example_ko_2 = '열차 승강장 번호는 위쪽 화면에 표시되어 있어요.', example_en_3 = 'Check the platform number before walking all the way to the end.', example_ko_3 = '끝까지 걸어가기 전에 승강장 번호를 확인하세요.', example_en_4 = 'The platform number changed at the last minute, causing confusion.', example_ko_4 = '마지막 순간에 승강장 번호가 바뀌어 혼란이 생겼어요.', example_en_5 = 'Each platform number is announced over the loudspeaker before boarding.', example_ko_5 = '탑승 전에 각 승강장 번호가 스피커로 안내돼요.' WHERE id = 'w_transport_B1_13';
UPDATE words SET example_en_2 = 'Is there a direct flight to London, or do I need to connect?', example_ko_2 = '런던으로 가는 직항 편이 있나요, 아니면 경유해야 하나요?', example_en_3 = 'The direct route saves about thirty minutes compared to the indirect one.', example_ko_3 = '직행 경로는 우회 경로보다 약 30분 절약돼요.', example_en_4 = 'I always prefer a direct service when I am travelling for work.', example_ko_4 = '업무 출장 시에는 항상 직행 서비스를 선호해요.', example_en_5 = 'The direct bus to the airport runs every hour on the hour.', example_ko_5 = '공항으로 가는 직행 버스는 정시마다 운행해요.' WHERE id = 'w_transport_B1_14';
UPDATE words SET example_en_2 = 'The overhead line fault caused disruption to rail services all morning.', example_ko_2 = '가공선 고장으로 오전 내내 철도 서비스에 장애가 발생했어요.', example_en_3 = 'Engineers worked through the night to repair the overhead line.', example_ko_3 = '엔지니어들이 밤새 가공선을 수리하기 위해 작업했어요.', example_en_4 = 'The train relies on the overhead line for its electrical power.', example_ko_4 = '기차는 전기 공급을 위해 가공선에 의존해요.', example_en_5 = 'Overhead line maintenance is scheduled for this weekend.', example_ko_5 = '이번 주말에 가공선 유지보수가 예정되어 있어요.' WHERE id = 'w_transport_B1_15';
UPDATE words SET example_en_2 = 'Motorists must stop at the level crossing when the barriers come down.', example_ko_2 = '차단기가 내려오면 운전자들은 건널목에서 반드시 정지해야 해요.', example_en_3 = 'The level crossing was automated to improve safety.', example_ko_3 = '안전을 향상시키기 위해 건널목이 자동화되었어요.', example_en_4 = 'A lorry got stuck on the level crossing and caused a major delay.', example_ko_4 = '트럭이 건널목에 끼어 큰 지연이 발생했어요.', example_en_5 = 'Level crossings must be treated with great care by all road users.', example_ko_5 = '건널목은 모든 도로 이용자가 매우 주의해야 해요.' WHERE id = 'w_transport_B1_16';
UPDATE words SET example_en_2 = 'The bypass was built to relieve traffic pressure on the town centre.', example_ko_2 = '마을 중심부의 교통 부담을 줄이기 위해 우회도로가 건설되었어요.', example_en_3 = 'Use the bypass to avoid the roadworks on the main road.', example_ko_3 = '큰 도로의 공사를 피하려면 우회도로를 이용하세요.', example_en_4 = 'Residents campaigned against the bypass being built near their homes.', example_ko_4 = '주민들이 우회도로가 자신들의 집 근처에 건설되는 것에 반대 운동을 벌였어요.', example_en_5 = 'The bypass reduces travel time between the two cities by fifteen minutes.', example_ko_5 = '우회도로 덕분에 두 도시 간 이동 시간이 15분 줄어들었어요.' WHERE id = 'w_transport_B1_17';
UPDATE words SET example_en_2 = 'A monthly fare card offers better value than daily tickets.', example_ko_2 = '월간 교통카드는 일일 티켓보다 더 경제적이에요.', example_en_3 = 'You can top up your fare card at any station ticket machine.', example_ko_3 = '역 내 발권기 어디서든 교통카드를 충전할 수 있어요.', example_en_4 = 'My fare card ran out of credit at the worst possible moment.', example_ko_4 = '교통카드의 잔액이 최악의 순간에 다 떨어졌어요.', example_en_5 = 'The fare card can be used on buses, trams, and the metro.', example_ko_5 = '교통카드는 버스, 트램, 지하철 모두 사용할 수 있어요.' WHERE id = 'w_transport_B1_18';
UPDATE words SET example_en_2 = 'The tram runs along the waterfront every eight minutes.', example_ko_2 = '트램은 해안가를 따라 8분마다 운행해요.', example_en_3 = 'Trams share the road with cars and pedestrians in this city.', example_ko_3 = '이 도시에서는 트램이 자동차 및 보행자와 도로를 공유해요.', example_en_4 = 'The new tram line connects the university to the city centre.', example_ko_4 = '새 트램 노선은 대학교와 시내를 연결해요.', example_en_5 = 'Trams are quieter and more eco-friendly than diesel buses.', example_ko_5 = '트램은 디젤 버스보다 조용하고 친환경적이에요.' WHERE id = 'w_transport_B1_19';
UPDATE words SET example_en_2 = 'We took the ferry across the harbour to reach the old town.', example_ko_2 = '구시가지에 가기 위해 항구를 건너는 페리를 탔어요.', example_en_3 = 'The ferry was cancelled because of strong winds and rough seas.', example_ko_3 = '강한 바람과 거친 파도로 페리가 취소되었어요.', example_en_4 = 'The overnight ferry is a budget-friendly way to travel between islands.', example_ko_4 = '야간 페리는 섬 사이를 여행하는 경제적인 방법이에요.', example_en_5 = 'The ferry terminal is a short walk from the train station.', example_ko_5 = '페리 터미널은 기차역에서 걸어서 얼마 안 걸려요.' WHERE id = 'w_transport_B1_20';
UPDATE words SET example_en_2 = 'The cycle lane keeps cyclists separate from fast-moving traffic.', example_ko_2 = '자전거 도로는 자전거 이용자를 빠른 교통으로부터 분리해요.', example_en_3 = 'Motorists should give way to cyclists in the cycle lane.', example_ko_3 = '운전자는 자전거 도로에서 자전거 이용자에게 양보해야 해요.', example_en_4 = 'The new cycle lane made cycling into work much safer.', example_ko_4 = '새 자전거 도로로 자전거 출퇴근이 훨씬 더 안전해졌어요.', example_en_5 = 'Please do not park in the cycle lane — it is dangerous.', example_ko_5 = '자전거 도로에는 주차하지 마세요 — 위험해요.' WHERE id = 'w_transport_B1_21';
UPDATE words SET example_en_2 = 'Gridlock brought the entire city centre to a complete standstill.', example_ko_2 = '극심한 정체로 도심 전체가 완전히 멈췄어요.', example_en_3 = 'The event caused gridlock across most of the major roads.', example_ko_3 = '행사로 인해 주요 도로 대부분에 극심한 정체가 발생했어요.', example_en_4 = 'The city avoided gridlock by introducing a timed entry system.', example_ko_4 = '도시에서 시간대별 진입 시스템을 도입해 교통 마비를 피했어요.', example_en_5 = 'I had never seen gridlock so bad — it took two hours to move one kilometre.', example_ko_5 = '그렇게 심한 교통 마비는 처음이었어요 — 1킬로미터 이동하는 데 두 시간이 걸렸어요.' WHERE id = 'w_transport_B1_22';
UPDATE words SET example_en_2 = 'The new interchange links the metro, tram, and bus networks.', example_ko_2 = '새 환승 센터는 지하철, 트램, 버스 노선망을 연결해요.', example_en_3 = 'The interchange at the central station is the busiest in the country.', example_ko_3 = '중앙역의 환승 센터는 나라에서 가장 붐비는 곳이에요.', example_en_4 = 'There is a covered walkway between the two platforms at the interchange.', example_ko_4 = '환승 센터의 두 승강장 사이에는 지붕 있는 통로가 있어요.', example_en_5 = 'The interchange is currently being expanded to handle more passengers.', example_ko_5 = '환승 센터는 현재 더 많은 승객을 수용하기 위해 확장 중이에요.' WHERE id = 'w_transport_B1_23';
UPDATE words SET example_en_2 = 'During peak hour, every seat on the train is taken.', example_ko_2 = '피크 시간대에는 기차의 모든 자리가 차 있어요.', example_en_3 = 'Fares are often higher during peak hour on commuter lines.', example_ko_3 = '통근 노선에서는 피크 시간대에 요금이 더 높은 경우가 많아요.', example_en_4 = 'I shift my working hours to avoid the peak hour rush.', example_ko_4 = '피크 시간대 혼잡을 피하기 위해 근무 시간을 조정해요.', example_en_5 = 'Peak hour congestion is worst at the main city centre junctions.', example_ko_5 = '피크 시간대 혼잡은 도심 주요 교차로에서 가장 심해요.' WHERE id = 'w_transport_B1_24';
UPDATE words SET example_en_2 = 'The council voted to pedestrianize the historic high street.', example_ko_2 = '의회에서 역사적인 번화가를 보행자 전용으로 전환하기로 의결했어요.', example_en_3 = 'Pedestrianizing the square has made it a much more pleasant place.', example_ko_3 = '광장을 보행자 전용으로 만들어 훨씬 더 쾌적한 공간이 되었어요.', example_en_4 = 'The decision to pedestrianize the road was controversial at first.', example_ko_4 = '도로를 보행자 전용으로 만들기로 한 결정은 처음에는 논란이 있었어요.', example_en_5 = 'Once pedestrianized, the area attracted more visitors and business.', example_ko_5 = '보행자 전용 구역이 된 이후 그 지역은 더 많은 방문객과 상업 활동을 끌어들였어요.' WHERE id = 'w_transport_B1_25';
UPDATE words SET example_en_2 = 'The sat-nav suggested a detour to avoid the traffic on the motorway.', example_ko_2 = '내비게이션이 고속도로 교통을 피하기 위한 우회로를 안내했어요.', example_en_3 = 'We took a detour through the countryside and it was beautiful.', example_ko_3 = '시골을 통과하는 우회로를 택했는데 정말 아름다웠어요.', example_en_4 = 'A ten-minute detour saved us nearly an hour of waiting in traffic.', example_ko_4 = '10분의 우회로 덕분에 교통 체증에서 거의 한 시간을 절약했어요.', example_en_5 = 'The road signs clearly marked the detour during the bridge closure.', example_ko_5 = '다리 폐쇄 중 도로 표지판이 우회로를 명확하게 안내했어요.' WHERE id = 'w_transport_B1_26';
UPDATE words SET example_en_2 = 'You must yield to pedestrians at all marked crossings.', example_ko_2 = '모든 표시된 횡단보도에서 보행자에게 양보해야 해요.', example_en_3 = 'Yield to the right at unmarked intersections.', example_ko_3 = '표시가 없는 교차로에서는 오른쪽 차량에 양보하세요.', example_en_4 = 'Failing to yield can result in a serious fine or penalty points.', example_ko_4 = '양보하지 않으면 상당한 벌금이나 벌점을 받을 수 있어요.', example_en_5 = 'The yield sign means you must give way to all other traffic.', example_ko_5 = '양보 표지판은 모든 다른 교통에 양보해야 함을 의미해요.' WHERE id = 'w_transport_B1_27';
UPDATE words SET example_en_2 = 'The lorry drifted into the oncoming carriageway.', example_ko_2 = '트럭이 반대편 차도로 벗어났어요.', example_en_3 = 'The dual carriageway continues for another fifteen kilometres.', example_ko_3 = '왕복 2차로 도로는 15킬로미터 더 이어져요.', example_en_4 = 'Overtaking on a single carriageway can be very dangerous.', example_ko_4 = '단일 차도에서의 추월은 매우 위험할 수 있어요.', example_en_5 = 'Work is underway to widen the carriageway to three lanes.', example_ko_5 = '차도를 3차선으로 확장하는 공사가 진행 중이에요.' WHERE id = 'w_transport_B1_28';
UPDATE words SET example_en_2 = 'Follow the sign post for the motorway junction.', example_ko_2 = '고속도로 분기점으로 가는 이정표를 따라가세요.', example_en_3 = 'The sign post had been knocked over and was hard to read.', example_ko_3 = '이정표가 넘어져 있어 읽기 어려웠어요.', example_en_4 = 'The sign post showed directions to three different villages.', example_ko_4 = '이정표에 세 마을로 가는 방향이 표시되어 있었어요.', example_en_5 = 'A new sign post was installed at the roundabout to reduce confusion.', example_ko_5 = '혼선을 줄이기 위해 로터리에 새 이정표가 설치되었어요.' WHERE id = 'w_transport_B1_29';
UPDATE words SET example_en_2 = 'The departure lounge has limited seating and gets crowded quickly.', example_ko_2 = '출발 라운지는 좌석이 적어 금방 붐벼요.', example_en_3 = 'You can access the business class departure lounge with your card.', example_ko_3 = '카드로 비즈니스 클래스 출발 라운지를 이용할 수 있어요.', example_en_4 = 'Passengers were held in the departure lounge due to a gate change.', example_ko_4 = '탑승구 변경으로 인해 승객들이 출발 라운지에 대기했어요.', example_en_5 = 'We waited in the departure lounge for nearly two hours before boarding.', example_ko_5 = '탑승하기 전에 출발 라운지에서 거의 두 시간을 기다렸어요.' WHERE id = 'w_transport_B1_30';
UPDATE words SET example_en_2 = 'Please check in at least two hours before your international flight.', example_ko_2 = '국제선 출발 최소 두 시간 전에 체크인해 주세요.', example_en_3 = 'I checked in online the night before to save time at the airport.', example_ko_3 = '공항에서 시간을 절약하기 위해 전날 밤에 온라인 체크인을 했어요.', example_en_4 = 'The check-in desk for budget airlines is often far from the main entrance.', example_ko_4 = '저가 항공사 체크인 데스크는 종종 정문과 멀리 떨어져 있어요.', example_en_5 = 'Your check-in time will be shown on your booking confirmation.', example_ko_5 = '체크인 시간은 예약 확인서에 표시되어 있어요.' WHERE id = 'w_transport_B1_31';
UPDATE words SET example_en_2 = 'You must fasten your seatbelt as soon as you get in the car.', example_ko_2 = '차에 타자마자 안전벨트를 착용해야 해요.', example_en_3 = 'The seatbelt kept the passenger safe during the emergency braking.', example_ko_3 = '비상 제동 중에 안전벨트가 승객을 안전하게 보호했어요.', example_en_4 = 'Passengers who do not wear a seatbelt risk a fine.', example_ko_4 = '안전벨트를 착용하지 않는 승객은 벌금 위험이 있어요.', example_en_5 = 'On the coach, seatbelts are compulsory for all passengers.', example_ko_5 = '코치(버스)에서는 모든 승객의 안전벨트 착용이 의무예요.' WHERE id = 'w_transport_B1_32';
UPDATE words SET example_en_2 = 'The ferry leaves from the harbour at six in the morning.', example_ko_2 = '페리는 아침 6시에 항구에서 출발해요.', example_en_3 = 'The new cruise terminal has transformed the old harbour.', example_ko_3 = '새 크루즈 터미널이 오래된 항구를 탈바꿈시켰어요.', example_en_4 = 'The harbour is sheltered from strong winds by the surrounding hills.', example_ko_4 = '항구는 주변 언덕들이 강한 바람을 막아줘요.', example_en_5 = 'We watched the fishing boats return to the harbour at dusk.', example_ko_5 = '해질 무렵 어선들이 항구로 돌아오는 것을 지켜봤어요.' WHERE id = 'w_transport_B1_33';
UPDATE words SET example_en_2 = 'The motorway connects the capital to the northern cities.', example_ko_2 = '고속도로는 수도를 북부 도시들과 연결해요.', example_en_3 = 'There was a long tailback on the motorway after the accident.', example_ko_3 = '사고 이후 고속도로에 긴 정체가 이어졌어요.', example_en_4 = 'The speed limit on the motorway is usually one hundred and ten kilometres per hour.', example_ko_4 = '고속도로의 제한 속도는 보통 시속 110킬로미터예요.', example_en_5 = 'Do not stop on the motorway unless it is an emergency.', example_ko_5 = '비상 상황이 아닌 경우 고속도로에 차를 세우지 마세요.' WHERE id = 'w_transport_B1_34';
UPDATE words SET example_en_2 = 'The overhead bridge provides a safe crossing over the busy road.', example_ko_2 = '육교는 바쁜 도로를 안전하게 건널 수 있게 해줘요.', example_en_3 = 'Cyclists are encouraged to use the overhead bridge instead of the road.', example_ko_3 = '자전거 이용자들은 도로 대신 육교를 이용하도록 권장받아요.', example_en_4 = 'The overhead bridge connects the two sides of the shopping mall.', example_ko_4 = '육교는 쇼핑몰 양쪽을 연결해요.', example_en_5 = 'The overhead bridge was built to ease pedestrian congestion at the junction.', example_ko_5 = '교차로의 보행자 혼잡을 줄이기 위해 육교가 건설되었어요.' WHERE id = 'w_transport_B1_35';
UPDATE words SET example_en_2 = 'The government has announced a major investment in transport infrastructure.', example_ko_2 = '정부가 교통 인프라에 대한 대규모 투자를 발표했어요.', example_en_3 = 'Ageing infrastructure is one of the biggest challenges facing the rail network.', example_ko_3 = '노후화된 인프라는 철도망이 직면한 가장 큰 과제 중 하나예요.', example_en_4 = 'The city''s cycling infrastructure has improved dramatically over the past five years.', example_ko_4 = '도시의 자전거 인프라는 지난 5년간 극적으로 개선되었어요.', example_en_5 = 'Without adequate infrastructure, public transport cannot function efficiently.', example_ko_5 = '적절한 인프라 없이는 대중교통이 효율적으로 기능할 수 없어요.' WHERE id = 'w_transport_B2_01';
UPDATE words SET example_en_2 = 'The public transit system was redesigned to better serve the suburbs.', example_ko_2 = '대중교통 시스템이 교외 지역을 더 잘 서비스하기 위해 재설계되었어요.', example_en_3 = 'Rapid transit lines can move thousands of passengers per hour.', example_ko_3 = '급행 교통 노선은 시간당 수천 명의 승객을 이동시킬 수 있어요.', example_en_4 = 'Transit-oriented planning encourages development around public transport hubs.', example_ko_4 = '대중교통 중심 계획은 교통 허브 주변 개발을 장려해요.', example_en_5 = 'The transit authority is trialling contactless payment across all routes.', example_ko_5 = '교통 당국이 모든 노선에 걸쳐 비접촉 결제를 시범 운영하고 있어요.' WHERE id = 'w_transport_B2_02';
UPDATE words SET example_en_2 = 'The logistics company manages deliveries across twenty countries.', example_ko_2 = '그 물류 회사는 20개국에 걸친 배송을 관리해요.', example_en_3 = 'Improving port logistics reduced waiting times for cargo ships significantly.', example_ko_3 = '항만 물류 개선으로 화물선 대기 시간이 크게 줄었어요.', example_en_4 = 'The event required careful logistics planning to transport equipment safely.', example_ko_4 = '행사에는 장비를 안전하게 운송하기 위한 세심한 물류 계획이 필요했어요.', example_en_5 = 'Logistics costs have risen sharply due to fuel price increases.', example_ko_5 = '연료비 상승으로 물류 비용이 급격히 올랐어요.' WHERE id = 'w_transport_B2_03';
UPDATE words SET example_en_2 = 'I used the app to navigate through the unfamiliar city centre.', example_ko_2 = '앱을 이용해 낯선 도심을 탐색했어요.', example_en_3 = 'It can be difficult to navigate the metro system without a map.', example_ko_3 = '지도 없이 지하철 시스템을 탐색하기 어려울 수 있어요.', example_en_4 = 'The ship''s captain used GPS to navigate through the narrow strait.', example_ko_4 = '선장이 GPS를 이용해 좁은 해협을 항해했어요.', example_en_5 = 'Learning to navigate public transport independently is a useful skill.', example_ko_5 = '대중교통을 스스로 이용하는 방법을 익히는 것은 유용한 능력이에요.' WHERE id = 'w_transport_B2_04';
UPDATE words SET example_en_2 = 'She planned a detailed itinerary covering eight cities in two weeks.', example_ko_2 = '그녀는 2주 동안 8개 도시를 아우르는 상세한 일정을 계획했어요.', example_en_3 = 'The itinerary includes transfers, accommodation, and local transport.', example_ko_3 = '일정에는 환승, 숙박, 현지 교통이 포함되어 있어요.', example_en_4 = 'Please review the itinerary and let me know if anything needs changing.', example_ko_4 = '일정을 검토하고 변경이 필요한 사항이 있으면 알려 주세요.', example_en_5 = 'A flexible itinerary is helpful when travelling in areas with irregular transport.', example_ko_5 = '교통이 불규칙한 지역을 여행할 때는 유연한 일정이 도움이 돼요.' WHERE id = 'w_transport_B2_05';
UPDATE words SET example_en_2 = 'We hired a chartered bus to take the whole team to the conference.', example_ko_2 = '팀 전체를 컨퍼런스에 데려가기 위해 전세 버스를 빌렸어요.', example_en_3 = 'A chartered flight was arranged for the delegation.', example_ko_3 = '대표단을 위해 전세 항공편이 마련되었어요.', example_en_4 = 'Chartered services are more flexible but significantly more expensive.', example_ko_4 = '전세 서비스는 더 유연하지만 비용이 상당히 더 비싸요.', example_en_5 = 'The company operates chartered ferry crossings for corporate clients.', example_ko_5 = '그 회사는 기업 고객을 위한 전세 페리 운항을 운영해요.' WHERE id = 'w_transport_B2_06';
UPDATE words SET example_en_2 = 'A free shuttle runs between the hotel and the airport every thirty minutes.', example_ko_2 = '호텔과 공항 사이에 30분마다 무료 셔틀이 운행해요.', example_en_3 = 'The airport shuttle stopped running after ten at night.', example_ko_3 = '공항 셔틀은 밤 10시 이후에 운행을 중단했어요.', example_en_4 = 'A shuttle service was provided for participants attending the event.', example_ko_4 = '행사 참가자들을 위한 셔틀 서비스가 제공되었어요.', example_en_5 = 'The shuttle bus connects the two campuses and runs throughout the day.', example_ko_5 = '셔틀버스는 두 캠퍼스를 연결하며 하루 종일 운행해요.' WHERE id = 'w_transport_B2_07';
UPDATE words SET example_en_2 = 'The intercity rail service has been extended to three new cities.', example_ko_2 = '도시 간 철도 서비스가 새로운 세 도시로 연장되었어요.', example_en_3 = 'Intercity buses are a cheap alternative to the high-speed train.', example_ko_3 = '도시 간 버스는 고속 열차의 저렴한 대안이에요.', example_en_4 = 'The intercity motorway handles millions of vehicles each year.', example_ko_4 = '도시 간 고속도로는 매년 수백만 대의 차량이 통행해요.', example_en_5 = 'Intercity transport links are essential for regional economic development.', example_ko_5 = '도시 간 교통 연결은 지역 경제 발전에 필수적이에요.' WHERE id = 'w_transport_B2_08';
UPDATE words SET example_en_2 = 'Motorists must pay a toll before entering the tunnel.', example_ko_2 = '터널에 진입하기 전에 통행료를 납부해야 해요.', example_en_3 = 'The toll on this bridge is collected electronically.', example_ko_3 = '이 다리의 통행료는 전자적으로 수납돼요.', example_en_4 = 'The toll rose by ten percent following the latest government review.', example_ko_4 = '최신 정부 검토 이후 통행료가 10퍼센트 인상되었어요.', example_en_5 = 'Toll-free roads are rare in this region.', example_ko_5 = '이 지역에서 통행료가 없는 도로는 드물어요.' WHERE id = 'w_transport_B2_09';
UPDATE words SET example_en_2 = 'The congestion charge applies to vehicles entering the central zone on weekdays.', example_ko_2 = '혼잡 통행료는 평일 중심 구역에 진입하는 차량에 적용돼요.', example_en_3 = 'Revenue from the congestion charge is reinvested in public transport.', example_ko_3 = '혼잡 통행료 수입은 대중교통에 재투자돼요.', example_en_4 = 'The congestion charge was controversial when it was first introduced.', example_ko_4 = '혼잡 통행료는 처음 도입됐을 때 논란이 있었어요.', example_en_5 = 'Exemptions from the congestion charge apply to electric vehicles.', example_ko_5 = '전기 자동차는 혼잡 통행료 면제 대상이에요.' WHERE id = 'w_transport_B2_10';
UPDATE words SET example_en_2 = 'Passengers are invited to embark from the forward gangway.', example_ko_2 = '승객들은 앞쪽 통로에서 승선하도록 안내됩니다.', example_en_3 = 'We were asked to embark early due to the tight departure schedule.', example_ko_3 = '빠듯한 출항 일정으로 인해 일찍 승선해 달라는 요청을 받았어요.', example_en_4 = 'All passengers must embark with a valid boarding pass.', example_ko_4 = '모든 승객은 유효한 탑승권을 소지하고 승선해야 해요.', example_en_5 = 'The captain gave permission to embark shortly after the safety briefing.', example_ko_5 = '안전 브리핑 직후 선장이 승선 허가를 내렸어요.' WHERE id = 'w_transport_B2_11';
UPDATE words SET example_en_2 = 'Passengers were asked to disembark in an orderly fashion.', example_ko_2 = '승객들은 질서 있게 하선해 달라는 요청을 받았어요.', example_en_3 = 'We disembarked at the wrong stop and had to double back.', example_ko_3 = '잘못된 정류장에서 내려 되돌아가야 했어요.', example_en_4 = 'The ferry allowed passengers to disembark within ten minutes of docking.', example_ko_4 = '페리는 정박 후 10분 이내에 승객들이 하선할 수 있도록 했어요.', example_en_5 = 'You must show your ticket when you disembark at the final destination.', example_ko_5 = '최종 목적지에서 하선할 때 표를 제시해야 해요.' WHERE id = 'w_transport_B2_12';
UPDATE words SET example_en_2 = 'The waybill must accompany all freight shipments by law.', example_ko_2 = '법적으로 모든 화물 수송에는 화물 운송장이 동반되어야 해요.', example_en_3 = 'The driver checked the waybill carefully before loading the lorry.', example_ko_3 = '트럭을 적재하기 전에 운전사가 화물 운송장을 꼼꼼히 확인했어요.', example_en_4 = 'A discrepancy in the waybill caused a delay at customs.', example_ko_4 = '화물 운송장의 불일치로 세관에서 지연이 발생했어요.', example_en_5 = 'Electronic waybills have replaced paper documents in most logistics operations.', example_ko_5 = '전자 화물 운송장이 대부분의 물류 업무에서 종이 서류를 대체했어요.' WHERE id = 'w_transport_B2_13';
UPDATE words SET example_en_2 = 'The traffic management system was able to reroute vehicles automatically.', example_ko_2 = '교통 관리 시스템이 차량을 자동으로 우회시킬 수 있었어요.', example_en_3 = 'We were rerouted via the coastal road after the landslide.', example_ko_3 = '산사태 이후 해안 도로를 통해 우회했어요.', example_en_4 = 'The airline rerouted the flight through a third airport due to fog.', example_ko_4 = '항공사가 안개로 인해 제3 공항을 경유하는 경로로 변경했어요.', example_en_5 = 'Passengers were informed immediately when the service was rerouted.', example_ko_5 = '서비스가 우회될 때 승객들에게 즉시 안내되었어요.' WHERE id = 'w_transport_B2_14';
UPDATE words SET example_en_2 = 'The concourse was busy with travellers rushing for their trains.', example_ko_2 = '콩코스는 기차를 타려고 서두르는 여행객들로 붐볐어요.', example_en_3 = 'The main concourse of the station features a large departures board.', example_ko_3 = '역의 메인 콩코스에는 대형 출발 안내판이 있어요.', example_en_4 = 'Shops and cafes line both sides of the station concourse.', example_ko_4 = '역 콩코스 양쪽에 상점과 카페가 늘어서 있어요.', example_en_5 = 'The renovation doubled the size of the terminal concourse.', example_ko_5 = '리노베이션으로 터미널 콩코스 면적이 두 배로 늘었어요.' WHERE id = 'w_transport_B2_15';
UPDATE words SET example_en_2 = 'The ship was carrying a cargo of electronic goods bound for Europe.', example_ko_2 = '그 선박은 유럽으로 향하는 전자 제품 화물을 싣고 있었어요.', example_en_3 = 'Cargo services operate around the clock at the international port.', example_ko_3 = '국제 항구에서는 화물 서비스가 24시간 운영돼요.', example_en_4 = 'The cargo was inspected by customs officers on arrival.', example_ko_4 = '화물은 도착 시 세관 직원에 의해 검사되었어요.', example_en_5 = 'Air cargo offers faster delivery but at a considerably higher cost.', example_ko_5 = '항공 화물은 더 빠른 배송을 제공하지만 비용이 상당히 더 비싸요.' WHERE id = 'w_transport_B2_16';
UPDATE words SET example_en_2 = 'Please ensure your bag fits within the overhead compartment dimensions.', example_ko_2 = '가방이 머리 위 수납칸 크기에 맞는지 확인해 주세요.', example_en_3 = 'The overhead compartment was already full when I boarded.', example_ko_3 = '탑승했을 때 이미 머리 위 수납칸이 꽉 차 있었어요.', example_en_4 = 'Passengers are reminded not to place heavy items in the overhead compartment.', example_ko_4 = '승객들은 머리 위 수납칸에 무거운 물건을 놓지 말라는 안내를 받아요.', example_en_5 = 'Items left in the overhead compartment may be removed by the crew.', example_ko_5 = '머리 위 수납칸에 남겨진 물건은 승무원이 제거할 수 있어요.' WHERE id = 'w_transport_B2_17';
UPDATE words SET example_en_2 = 'The road grid in the city centre was designed in the nineteenth century.', example_ko_2 = '도심의 도로 격자는 19세기에 설계되었어요.', example_en_3 = 'The bus network uses a grid pattern to ensure coverage across the borough.', example_ko_3 = '버스 네트워크는 자치구 전역에 서비스를 제공하기 위해 격자 패턴을 사용해요.', example_en_4 = 'A grid system makes it easy to navigate the streets of the city.', example_ko_4 = '격자 시스템 덕분에 도시 거리를 탐색하기 쉬워요.', example_en_5 = 'The grid layout of the city allows for efficient bus routing.', example_ko_5 = '도시의 격자 구조 덕분에 효율적인 버스 노선 운영이 가능해요.' WHERE id = 'w_transport_B2_18';
UPDATE words SET example_en_2 = 'All new stations are designed to be fully accessible to wheelchair users.', example_ko_2 = '모든 새 역은 휠체어 이용자가 완전히 접근 가능하도록 설계되어요.', example_en_3 = 'The accessible entrance is located at the rear of the building.', example_ko_3 = '장애인 출입구는 건물 뒤쪽에 위치해 있어요.', example_en_4 = 'Is this bus route accessible for passengers with mobility issues?', example_ko_4 = '이 버스 노선은 이동에 불편이 있는 승객도 이용 가능한가요?', example_en_5 = 'Making public transport accessible is a legal obligation in many countries.', example_ko_5 = '많은 나라에서 대중교통을 접근 가능하게 만드는 것은 법적 의무예요.' WHERE id = 'w_transport_B2_19';
UPDATE words SET example_en_2 = 'I tried to hail a taxi but they all had passengers already.', example_ko_2 = '택시를 잡으려 했지만 모두 승객을 태우고 있었어요.', example_en_3 = 'It is not always easy to hail a cab during heavy rain.', example_ko_3 = '폭우 중에 택시를 잡기가 항상 쉬운 것은 아니에요.', example_en_4 = 'You cannot legally hail a taxi on this side of the road.', example_ko_4 = '이쪽 도로에서는 합법적으로 택시를 잡을 수 없어요.', example_en_5 = 'She stepped out onto the kerb to hail a passing cab.', example_ko_5 = '그녀는 지나가는 택시를 잡기 위해 도로변으로 나갔어요.' WHERE id = 'w_transport_B2_20';
UPDATE words SET example_en_2 = 'The new timetable was designed to streamline connections between routes.', example_ko_2 = '새 시간표는 노선 간 연결을 간소화하기 위해 설계되었어요.', example_en_3 = 'Efforts to streamline the check-in process have reduced queuing time.', example_ko_3 = '체크인 절차 간소화 노력으로 대기 시간이 줄었어요.', example_en_4 = 'The authority plans to streamline its bus network by merging overlapping routes.', example_ko_4 = '당국은 중복 노선을 통합해 버스 네트워크를 간소화할 계획이에요.', example_en_5 = 'Streamlining the border crossing reduced delays by forty percent.', example_ko_5 = '국경 통과 간소화로 지연이 40퍼센트 감소했어요.' WHERE id = 'w_transport_B2_21';
UPDATE words SET example_en_2 = 'The headway on this line has been reduced to improve frequency.', example_ko_2 = '이 노선의 배차 간격이 운행 빈도를 높이기 위해 줄어들었어요.', example_en_3 = 'A shorter headway means passengers wait less time at the stop.', example_ko_3 = '배차 간격이 짧아지면 승객들이 정류장에서 기다리는 시간이 줄어요.', example_en_4 = 'The headway during off-peak hours drops to thirty minutes.', example_ko_4 = '비혼잡 시간대의 배차 간격은 30분으로 늘어나요.', example_en_5 = 'Maintaining consistent headway is critical for a reliable service.', example_ko_5 = '안정적인 서비스를 위해 일관된 배차 간격 유지가 매우 중요해요.' WHERE id = 'w_transport_B2_22';
UPDATE words SET example_en_2 = 'Freight carried by rail is generally more fuel-efficient than road haulage.', example_ko_2 = '철도로 운반되는 화물은 일반적으로 도로 운송보다 연료 효율이 높아요.', example_en_3 = 'The port handles over a million tonnes of freight each year.', example_ko_3 = '항구는 매년 100만 톤 이상의 화물을 처리해요.', example_en_4 = 'Rising fuel costs have pushed many companies to shift freight to rail.', example_ko_4 = '연료 비용 상승으로 많은 회사들이 화물을 철도로 전환했어요.', example_en_5 = 'Freight trains run overnight to avoid competing with passenger services.', example_ko_5 = '화물 열차는 여객 서비스와 경쟁을 피하기 위해 야간에 운행해요.' WHERE id = 'w_transport_B2_23';
UPDATE words SET example_en_2 = 'The bridge''s suspension cables are inspected twice a year.', example_ko_2 = '다리의 현수 케이블은 연 2회 점검을 받아요.', example_en_3 = 'The vehicle''s suspension was badly damaged by the potholed road.', example_ko_3 = '차량의 서스펜션이 패인 도로로 인해 크게 손상되었어요.', example_en_4 = 'A suspension of services was announced due to the severe weather.', example_ko_4 = '악기상으로 인해 서비스 일시 중단이 발표되었어요.', example_en_5 = 'The driver was issued with a three-month licence suspension.', example_ko_5 = '운전자는 3개월 면허 정지 처분을 받았어요.' WHERE id = 'w_transport_B2_24';
UPDATE words SET example_en_2 = 'Emergency vehicles always have access to the priority lane.', example_ko_2 = '응급 차량은 항상 우선 차선을 이용할 수 있어요.', example_en_3 = 'The priority lane reduces journey times for buses significantly.', example_ko_3 = '우선 차선 덕분에 버스의 이동 시간이 크게 줄어요.', example_en_4 = 'Only vehicles with three or more occupants may use the priority lane.', example_ko_4 = '탑승자가 3명 이상인 차량만 우선 차선을 이용할 수 있어요.', example_en_5 = 'The priority lane operates from seven in the morning to seven in the evening.', example_ko_5 = '우선 차선은 오전 7시부터 오후 7시까지 운영돼요.' WHERE id = 'w_transport_B2_25';
UPDATE words SET example_en_2 = 'The bus was operating well beyond its normal passenger capacity.', example_ko_2 = '버스가 정상 수용 인원을 훨씬 초과해서 운행하고 있었어요.', example_en_3 = 'The new rolling stock has a greater capacity than the old trains.', example_ko_3 = '새 차량은 기존 열차보다 수용 인원이 더 많아요.', example_en_4 = 'Capacity constraints are the main reason for service unreliability.', example_ko_4 = '수용 능력 제약이 서비스 불안정의 주된 이유예요.', example_en_5 = 'The airport is already operating at full capacity during peak season.', example_ko_5 = '공항은 성수기 동안 이미 최대 용량으로 운영되고 있어요.' WHERE id = 'w_transport_B2_26';
UPDATE words SET example_en_2 = 'The interchange hub connects all five major transport modes in one location.', example_ko_2 = '환승 허브는 한 곳에서 다섯 가지 주요 교통 수단을 모두 연결해요.', example_en_3 = 'The new interchange hub was opened to improve cross-city connectivity.', example_ko_3 = '도시 전반의 연결성을 개선하기 위해 새로운 환승 허브가 개통되었어요.', example_en_4 = 'Passengers can transfer seamlessly at the interchange hub with one ticket.', example_ko_4 = '승객들은 환승 허브에서 하나의 티켓으로 원활하게 환승할 수 있어요.', example_en_5 = 'The interchange hub has dramatically reduced journey times across the region.', example_ko_5 = '환승 허브가 지역 전반의 이동 시간을 크게 단축시켰어요.' WHERE id = 'w_transport_B2_27';
UPDATE words SET example_en_2 = 'The government provides a subsidy to keep rural bus fares affordable.', example_ko_2 = '정부는 농촌 버스 요금을 저렴하게 유지하기 위해 보조금을 지원해요.', example_en_3 = 'Without the subsidy, the ferry service would not be commercially viable.', example_ko_3 = '보조금 없이는 페리 서비스가 상업적으로 수익성이 없을 거예요.', example_en_4 = 'The transport subsidy was cut, leading to fare increases across the network.', example_ko_4 = '교통 보조금이 삭감되어 노선 전체의 요금이 인상되었어요.', example_en_5 = 'Public transport subsidies are essential to ensure social equity.', example_ko_5 = '사회적 형평성을 보장하기 위해 대중교통 보조금이 필수적이에요.' WHERE id = 'w_transport_B2_28';
UPDATE words SET example_en_2 = 'The app supports multimodal journey planning across bus, rail, and ferry.', example_ko_2 = '앱은 버스, 철도, 페리를 아우르는 복합 수단 여정 계획을 지원해요.', example_en_3 = 'A multimodal approach is key to reducing dependence on private cars.', example_ko_3 = '복합 수단 방식은 자가용 의존도를 줄이는 핵심이에요.', example_en_4 = 'The city''s multimodal transport strategy has won national recognition.', example_ko_4 = '도시의 복합 수단 교통 전략이 국가적 인정을 받았어요.', example_en_5 = 'Multimodal tickets allow seamless travel across different providers.', example_ko_5 = '복합 수단 티켓으로 다양한 교통 서비스 제공자 간 원활한 이동이 가능해요.' WHERE id = 'w_transport_B2_29';
UPDATE words SET example_en_2 = 'The rail corridor linking the two capitals is being upgraded.', example_ko_2 = '두 수도를 잇는 철도 회랑이 업그레이드되고 있어요.', example_en_3 = 'The transport corridor runs along the coast for three hundred kilometres.', example_ko_3 = '교통 회랑은 해안을 따라 300킬로미터 이어져요.', example_en_4 = 'New housing is planned along the corridor served by the new metro line.', example_ko_4 = '새 지하철 노선이 지나는 회랑을 따라 새 주택이 계획되어 있어요.', example_en_5 = 'Freight movement through the corridor has increased by thirty percent.', example_ko_5 = '회랑을 통한 화물 이동이 30퍼센트 증가했어요.' WHERE id = 'w_transport_B2_30';
UPDATE words SET example_en_2 = 'The station''s accessibility was improved by installing new lifts and ramps.', example_ko_2 = '새로운 엘리베이터와 경사로 설치로 역의 접근성이 개선되었어요.', example_en_3 = 'Accessibility for passengers with disabilities is a legal requirement.', example_ko_3 = '장애인 승객을 위한 접근성은 법적 요건이에요.', example_en_4 = 'The report highlighted significant gaps in accessibility on older bus routes.', example_ko_4 = '보고서는 오래된 버스 노선의 접근성에서 상당한 격차를 지적했어요.', example_en_5 = 'Accessibility improvements have benefited not just disabled passengers but all travellers.', example_ko_5 = '접근성 개선은 장애인 승객뿐만 아니라 모든 여행자에게 도움이 되었어요.' WHERE id = 'w_transport_B2_31';
UPDATE words SET example_en_2 = 'Carbon emissions from aviation account for a significant share of global pollution.', example_ko_2 = '항공 분야의 탄소 배출량은 전 세계 오염에서 상당한 비중을 차지해요.', example_en_3 = 'The new electric buses produce zero tailpipe emissions.', example_ko_3 = '새 전기 버스는 배기관 배출가스가 전혀 없어요.', example_en_4 = 'The city has set a target to cut transport emissions by fifty percent by 2035.', example_ko_4 = '도시는 2035년까지 교통 배출량을 50퍼센트 줄이는 목표를 세웠어요.', example_en_5 = 'Stricter emission standards have been applied to all new vehicles.', example_ko_5 = '모든 신규 차량에 더 엄격한 배출 기준이 적용되었어요.' WHERE id = 'w_transport_B2_32';
UPDATE words SET example_en_2 = 'The airline is expanding its fleet with twenty new aircraft.', example_ko_2 = '항공사가 20대의 새 항공기로 기단을 확장하고 있어요.', example_en_3 = 'The ageing bus fleet needs to be replaced within five years.', example_ko_3 = '노후화된 버스 기단은 5년 이내에 교체되어야 해요.', example_en_4 = 'A modern fleet of electric trams has been introduced on the main line.', example_ko_4 = '주요 노선에 현대적인 전기 트램 기단이 도입되었어요.', example_en_5 = 'The entire taxi fleet in the city will be electric by 2030.', example_ko_5 = '도시의 모든 택시가 2030년까지 전기차로 전환될 거예요.' WHERE id = 'w_transport_B2_33';
UPDATE words SET example_en_2 = 'On-demand bus services respond to passenger requests in real time.', example_ko_2 = '수요 대응형 버스 서비스는 실시간으로 승객 요청에 응답해요.', example_en_3 = 'The on-demand ferry service proved popular in rural coastal communities.', example_ko_3 = '수요 대응형 페리 서비스는 농촌 해안 지역 사회에서 인기를 얻었어요.', example_en_4 = 'On-demand transport is more flexible but less predictable than scheduled services.', example_ko_4 = '수요 대응형 교통은 더 유연하지만 정기 서비스보다 예측하기 어려워요.', example_en_5 = 'The city trialled an on-demand minibus service in areas with low demand.', example_ko_5 = '도시는 수요가 낮은 지역에서 수요 대응형 미니버스 서비스를 시범 운영했어요.' WHERE id = 'w_transport_B2_34';
UPDATE words SET example_en_2 = 'The ship''s manifest listed all cargo on board and its destination.', example_ko_2 = '선박의 화물 목록에는 적재된 모든 화물과 목적지가 나열되어 있었어요.', example_en_3 = 'Customs officials checked the manifest against the actual cargo.', example_ko_3 = '세관 직원들이 화물 목록을 실제 화물과 대조했어요.', example_en_4 = 'The passenger manifest showed that the flight was fully booked.', example_ko_4 = '탑승자 명단에 비행기가 만석으로 예약되어 있다고 나타났어요.', example_en_5 = 'An accurate manifest is essential for border and customs compliance.', example_ko_5 = '정확한 화물 목록은 국경 및 세관 규정 준수를 위해 필수적이에요.' WHERE id = 'w_transport_B2_35';
UPDATE words SET example_en_2 = 'Intermodal freight involves moving cargo seamlessly between ship, rail, and truck.', example_ko_2 = '복합 운송은 선박, 철도, 트럭 간에 화물을 원활하게 이동시키는 것을 포함해요.', example_en_3 = 'An intermodal terminal was built adjacent to the deep-sea port.', example_ko_3 = '심해 항구 인근에 복합 운송 터미널이 건설되었어요.', example_en_4 = 'Intermodal containers have standardised the global shipping industry.', example_ko_4 = '복합 운송 컨테이너는 글로벌 해운 산업을 표준화했어요.', example_en_5 = 'The company invested in intermodal logistics to cut delivery times and costs.', example_ko_5 = '회사는 납기 시간과 비용을 줄이기 위해 복합 운송 물류에 투자했어요.' WHERE id = 'w_transport_C1_01';
UPDATE words SET example_en_2 = 'Urban mobility solutions must cater to diverse groups, including the elderly and disabled.', example_ko_2 = '도시 이동성 솔루션은 노인과 장애인을 포함한 다양한 그룹을 고려해야 해요.', example_en_3 = 'Shared urban mobility schemes have grown rapidly in cities across Asia.', example_ko_3 = '공유 도시 이동성 계획은 아시아 전역 도시에서 빠르게 성장했어요.', example_en_4 = 'The conference focused on new technologies for urban mobility improvement.', example_ko_4 = '컨퍼런스는 도시 이동성 개선을 위한 새로운 기술에 초점을 맞췄어요.', example_en_5 = 'Urban mobility data is collected by sensors embedded across the transport network.', example_ko_5 = '도시 이동성 데이터는 교통 네트워크 전체에 내장된 센서로 수집돼요.' WHERE id = 'w_transport_C1_02';
UPDATE words SET example_en_2 = 'Ridesharing platforms allow users to split travel costs with strangers going the same way.', example_ko_2 = '라이드셰어링 플랫폼을 통해 같은 방향으로 가는 낯선 사람과 이동 비용을 나눌 수 있어요.', example_en_3 = 'Ridesharing has reduced the number of single-occupancy vehicles during rush hour.', example_ko_3 = '라이드셰어링이 러시아워 동안 1인 탑승 차량 수를 줄였어요.', example_en_4 = 'The ridesharing app connects drivers and passengers in under two minutes.', example_ko_4 = '라이드셰어링 앱은 2분 이내에 운전자와 승객을 연결해요.', example_en_5 = 'Regulatory pressure on ridesharing companies has increased as their market share has grown.', example_ko_5 = '라이드셰어링 업체의 시장 점유율이 커지면서 규제 압박도 강해졌어요.' WHERE id = 'w_transport_C1_03';
UPDATE words SET example_en_2 = 'Autonomous trams are already operating on dedicated lines in some European cities.', example_ko_2 = '자율 주행 트램이 일부 유럽 도시에서 이미 전용 노선을 운행하고 있어요.', example_en_3 = 'The company is testing autonomous vehicles on a closed circuit before public deployment.', example_ko_3 = '회사는 공개 배포 전에 폐쇄 회로에서 자율 주행 차량을 테스트하고 있어요.', example_en_4 = 'Autonomous shuttles are being trialled as a last-mile solution in suburban areas.', example_ko_4 = '자율 주행 셔틀이 교외 지역의 라스트마일 솔루션으로 시험 운용되고 있어요.', example_en_5 = 'Public trust is one of the biggest barriers to the adoption of autonomous transport.', example_ko_5 = '대중의 신뢰가 자율 주행 교통 도입의 가장 큰 장벽 중 하나예요.' WHERE id = 'w_transport_C1_04';
UPDATE words SET example_en_2 = 'Sustainable transport policies prioritise walking, cycling, and public transit over private cars.', example_ko_2 = '지속 가능한 교통 정책은 자가용보다 도보, 자전거, 대중교통을 우선시해요.', example_en_3 = 'Shifting to sustainable transport modes is central to meeting climate targets.', example_ko_3 = '지속 가능한 교통 수단으로 전환하는 것은 기후 목표 달성의 핵심이에요.', example_en_4 = 'The city received an award for its commitment to sustainable transport planning.', example_ko_4 = '도시는 지속 가능한 교통 계획에 대한 헌신으로 상을 받았어요.', example_en_5 = 'Investment in sustainable transport infrastructure pays dividends over the long term.', example_ko_5 = '지속 가능한 교통 인프라에 대한 투자는 장기적으로 성과를 거둬요.' WHERE id = 'w_transport_C1_05';
UPDATE words SET example_en_2 = 'The transport network covers every district in the city, from the suburbs to the centre.', example_ko_2 = '교통 네트워크는 교외에서 중심부까지 도시의 모든 구역을 커버해요.', example_en_3 = 'Upgrading the network''s signal infrastructure is a priority this decade.', example_ko_3 = '이번 10년 동안 네트워크 신호 인프라 업그레이드가 우선 과제예요.', example_en_4 = 'A connected network of cycling routes was launched across the borough.', example_ko_4 = '자치구 전역에 연결된 자전거 노선 네트워크가 시작되었어요.', example_en_5 = 'Network disruptions ripple out across all connecting services.', example_ko_5 = '네트워크 혼란은 모든 연결 서비스에 파급 영향을 미쳐요.' WHERE id = 'w_transport_C1_06';
UPDATE words SET example_en_2 = 'The airport serves as the main international hub for the region.', example_ko_2 = '공항은 이 지역의 주요 국제 허브 역할을 해요.', example_en_3 = 'The new bus hub will centralise services that are currently spread across three depots.', example_ko_3 = '새 버스 허브는 현재 세 차고지에 분산된 서비스를 중앙화할 거예요.', example_en_4 = 'A hub-and-spoke model is used to organise the national ferry network.', example_ko_4 = '허브 앤드 스포크 모델이 국가 페리 네트워크를 구성하는 데 사용돼요.', example_en_5 = 'Passengers arriving at the hub can connect to twenty different regional services.', example_ko_5 = '허브에 도착한 승객들은 20개의 다양한 지역 서비스를 연결할 수 있어요.' WHERE id = 'w_transport_C1_07';
UPDATE words SET example_en_2 = 'Throughput at the port has doubled since the new terminal opened.', example_ko_2 = '새 터미널이 개항한 이후 항구의 처리량이 두 배로 늘었어요.', example_en_3 = 'Network throughput is measured in the number of passengers moved per hour.', example_ko_3 = '네트워크 처리량은 시간당 이동 승객 수로 측정돼요.', example_en_4 = 'Bottlenecks in the system reduce overall throughput significantly.', example_ko_4 = '시스템 내 병목 현상이 전체 처리량을 크게 줄여요.', example_en_5 = 'Increasing throughput without compromising safety is the key challenge.', example_ko_5 = '안전을 타협하지 않고 처리량을 늘리는 것이 핵심 과제예요.' WHERE id = 'w_transport_C1_08';
UPDATE words SET example_en_2 = 'The electrification of the main line was completed three years ahead of schedule.', example_ko_2 = '주요 노선의 전철화가 예정보다 3년 앞당겨 완료되었어요.', example_en_3 = 'Electrification significantly reduces noise and air pollution along the rail corridor.', example_ko_3 = '전철화는 철도 회랑을 따라 소음과 대기 오염을 크게 줄여요.', example_en_4 = 'The government committed to full electrification of the bus fleet by 2030.', example_ko_4 = '정부는 2030년까지 버스 기단의 완전 전기화를 약속했어요.', example_en_5 = 'Electrification of rural rail lines requires significant upfront capital investment.', example_ko_5 = '농촌 철도 노선의 전철화에는 상당한 초기 자본 투자가 필요해요.' WHERE id = 'w_transport_C1_09';
UPDATE words SET example_en_2 = 'Reducing dwell time at each stop increases the overall speed of the service.', example_ko_2 = '각 정류장의 정차 시간을 줄이면 서비스의 전체 속도가 높아져요.', example_en_3 = 'Contactless payment has reduced dwell time on busy bus routes.', example_ko_3 = '비접촉 결제로 혼잡한 버스 노선의 정차 시간이 줄었어요.', example_en_4 = 'Engineers aim to bring dwell time at the terminus down to under two minutes.', example_ko_4 = '엔지니어들은 종착지에서의 정차 시간을 2분 이내로 줄이는 것을 목표로 해요.', example_en_5 = 'Longer dwell times occur when a large number of passengers board at once.', example_ko_5 = '많은 승객이 한꺼번에 탑승할 때 정차 시간이 길어져요.' WHERE id = 'w_transport_C1_10';
UPDATE words SET example_en_2 = 'The port city serves as the gateway to a vast hinterland of agricultural regions.', example_ko_2 = '항구 도시는 광대한 농업 지역 배후지의 관문 역할을 해요.', example_en_3 = 'Improving transport links to the hinterland is key to regional development.', example_ko_3 = '배후지와의 교통 연결을 개선하는 것이 지역 개발의 핵심이에요.', example_en_4 = 'The railway penetrates deep into the hinterland, opening up remote areas to trade.', example_ko_4 = '철도는 배후지 깊숙이 뻗어 교역을 위한 오지를 개척해요.', example_en_5 = 'Without good road access, the hinterland remains economically isolated.', example_ko_5 = '도로 접근이 원활하지 않으면 배후지는 경제적으로 고립된 상태로 남아요.' WHERE id = 'w_transport_C1_11';
UPDATE words SET example_en_2 = 'Transit-oriented development creates walkable communities around rail stations.', example_ko_2 = '대중교통 중심 개발은 철도역 주변에 걸어다닐 수 있는 주거 공동체를 만들어요.', example_en_3 = 'The city adopted a transit-oriented development strategy to reduce car dependency.', example_ko_3 = '도시는 자가용 의존도를 줄이기 위해 대중교통 중심 개발 전략을 채택했어요.', example_en_4 = 'Transit-oriented development has transformed former industrial land into vibrant neighbourhoods.', example_ko_4 = '대중교통 중심 개발이 이전 산업 단지를 활기찬 주거 지역으로 탈바꿈시켰어요.', example_en_5 = 'Research shows that transit-oriented development boosts ridership and reduces pollution.', example_ko_5 = '연구에 따르면 대중교통 중심 개발이 승객 수를 늘리고 오염을 줄여요.' WHERE id = 'w_transport_C1_12';
UPDATE words SET example_en_2 = 'Feeder services collect passengers from rural stops and connect them to the main line.', example_ko_2 = '피더 서비스는 농촌 정류장에서 승객을 모아 주요 노선과 연결해요.', example_en_3 = 'Without adequate feeder services, the new metro line will struggle to attract riders.', example_ko_3 = '충분한 피더 서비스 없이는 새 지하철 노선이 승객을 유치하는 데 어려움을 겪을 거예요.', example_en_4 = 'A new feeder service was launched to serve the growing residential estates on the outskirts.', example_ko_4 = '외곽의 성장하는 주거 단지를 위한 새로운 피더 서비스가 시작되었어요.', example_en_5 = 'Feeder buses run on a half-hourly basis to connect the village to the nearest station.', example_ko_5 = '피더 버스는 30분 간격으로 마을과 가장 가까운 역을 연결하며 운행해요.' WHERE id = 'w_transport_C1_13';
UPDATE words SET example_en_2 = 'The modal split in this city favours private cars over public transport.', example_ko_2 = '이 도시의 수단 분담률은 대중교통보다 자가용을 선호하는 쪽으로 기울어져 있어요.', example_en_3 = 'Policy makers are trying to shift the modal split towards cycling and walking.', example_ko_3 = '정책 입안자들이 수단 분담률을 자전거와 도보 쪽으로 이동시키려 하고 있어요.', example_en_4 = 'The modal split changed significantly after the new metro opened.', example_ko_4 = '새 지하철이 개통된 후 수단 분담률이 크게 변화했어요.', example_en_5 = 'Understanding the local modal split is essential for effective transport planning.', example_ko_5 = '효과적인 교통 계획을 위해서는 현지 수단 분담률을 이해하는 것이 필수예요.' WHERE id = 'w_transport_C1_14';
UPDATE words SET example_en_2 = 'Induced demand explains why building more roads does not always reduce congestion.', example_ko_2 = '유발 수요는 도로를 더 많이 건설해도 혼잡이 항상 줄지 않는 이유를 설명해요.', example_en_3 = 'Planners must account for induced demand when expanding highway capacity.', example_ko_3 = '계획자들은 고속도로 용량을 확장할 때 유발 수요를 고려해야 해요.', example_en_4 = 'The theory of induced demand has become central to modern transport economics.', example_ko_4 = '유발 수요 이론은 현대 교통 경제학의 핵심이 되었어요.', example_en_5 = 'Critics of road expansion often cite induced demand as a key counterargument.', example_ko_5 = '도로 확장 반대론자들은 유발 수요를 핵심 반론으로 자주 인용해요.' WHERE id = 'w_transport_C1_15';
UPDATE words SET example_en_2 = 'The authority used compulsory purchase to acquire the right-of-way for the new line.', example_ko_2 = '당국은 새 노선을 위한 통행권을 확보하기 위해 강제 취득을 사용했어요.', example_en_3 = 'Vehicles must yield to trams, which have a statutory right-of-way.', example_ko_3 = '차량은 법정 통행 우선권을 가진 트램에 양보해야 해요.', example_en_4 = 'Disputes over right-of-way can delay infrastructure projects by years.', example_ko_4 = '통행권 분쟁은 인프라 사업을 수년간 지연시킬 수 있어요.', example_en_5 = 'Establishing a clear right-of-way is the first step in any new rail project.', example_ko_5 = '명확한 통행권 확보는 모든 새 철도 사업의 첫 번째 단계예요.' WHERE id = 'w_transport_C1_16';
UPDATE words SET example_en_2 = 'The Victorian-era viaduct still carries passenger trains across the valley.', example_ko_2 = '빅토리아 시대의 고가교가 여전히 계곡을 가로질러 여객 열차를 운행해요.', example_en_3 = 'Engineers are assessing whether the viaduct can handle heavier rolling stock.', example_ko_3 = '엔지니어들이 고가교가 더 무거운 차량을 감당할 수 있는지 평가 중이에요.', example_en_4 = 'The new urban viaduct carries the metro line above the city streets.', example_ko_4 = '새 도시 고가교는 도시 거리 위로 지하철 노선을 연결해요.', example_en_5 = 'Restoration of the listed viaduct is expected to cost millions.', example_ko_5 = '등재된 고가교의 복원에는 수백만이 들 것으로 예상돼요.' WHERE id = 'w_transport_C1_17';
UPDATE words SET example_en_2 = 'The transport sector must decarbonize rapidly to meet the Paris Agreement targets.', example_ko_2 = '교통 부문은 파리 협정 목표를 달성하기 위해 빠르게 탈탄소화해야 해요.', example_en_3 = 'Electrifying the vehicle fleet is the fastest way to decarbonize urban transport.', example_ko_3 = '차량 기단 전기화는 도시 교통을 탈탄소화하는 가장 빠른 방법이에요.', example_en_4 = 'Politicians have pledged to decarbonize rail transport within ten years.', example_ko_4 = '정치인들이 10년 이내에 철도 교통을 탈탄소화하겠다고 약속했어요.', example_en_5 = 'It is technically challenging to decarbonize aviation and shipping.', example_ko_5 = '항공과 해운을 탈탄소화하는 것은 기술적으로 어려워요.' WHERE id = 'w_transport_C1_18';
UPDATE words SET example_en_2 = 'Last-mile connectivity is often the weakest point of any public transport journey.', example_ko_2 = '라스트마일 연결성은 종종 모든 대중교통 여정에서 가장 취약한 부분이에요.', example_en_3 = 'Electric scooters and shared bikes are being deployed to improve last-mile connectivity.', example_ko_3 = '전동 킥보드와 공유 자전거가 라스트마일 연결성을 개선하기 위해 배치되고 있어요.', example_en_4 = 'A subsidy scheme was introduced to improve last-mile connectivity in rural areas.', example_ko_4 = '농촌 지역의 라스트마일 연결성을 개선하기 위한 보조금 제도가 도입되었어요.', example_en_5 = 'Good last-mile connectivity makes the difference between a route being used or avoided.', example_ko_5 = '좋은 라스트마일 연결성은 노선 이용 여부를 결정하는 차이를 만들어요.' WHERE id = 'w_transport_C1_19';
UPDATE words SET example_en_2 = 'Grade separation eliminates the conflict between road traffic and rail at busy crossings.', example_ko_2 = '입체 교차는 바쁜 건널목에서 도로 교통과 철도 간의 충돌을 제거해요.', example_en_3 = 'The grade separation project will involve building an underpass beneath the tracks.', example_ko_3 = '입체 교차 사업은 선로 아래에 지하도를 건설하는 것을 포함해요.', example_en_4 = 'Grade separation is expensive but dramatically improves safety and capacity.', example_ko_4 = '입체 교차는 비용이 많이 들지만 안전성과 용량을 크게 개선해요.', example_en_5 = 'Several level crossings will be replaced by grade separation as part of the upgrade.', example_ko_5 = '업그레이드의 일환으로 여러 건널목이 입체 교차로 대체될 거예요.' WHERE id = 'w_transport_C1_20';
UPDATE words SET example_en_2 = 'Signal priority allows trams to hold green lights longer at intersections.', example_ko_2 = '신호 우선권으로 트램이 교차로에서 녹색 신호를 더 오래 유지할 수 있어요.', example_en_3 = 'Bus rapid transit systems often include signal priority to improve journey times.', example_ko_3 = '버스 급행 교통 시스템에는 종종 이동 시간을 개선하기 위한 신호 우선권이 포함돼요.', example_en_4 = 'Emergency vehicles are automatically granted signal priority at all major junctions.', example_ko_4 = '응급 차량은 모든 주요 교차로에서 자동으로 신호 우선권이 부여돼요.', example_en_5 = 'Signal priority technology has reduced average journey times on the express bus route.', example_ko_5 = '신호 우선권 기술로 급행 버스 노선의 평균 이동 시간이 단축되었어요.' WHERE id = 'w_transport_C1_21';
UPDATE words SET example_en_2 = 'Zone pricing charges travellers more if they cross into a higher-price zone.', example_ko_2 = '구역 요금제는 더 높은 요금 구역으로 이동하면 더 많이 부과해요.', example_en_3 = 'The zone pricing model was simplified to make it easier for passengers to understand.', example_ko_3 = '구역 요금제가 승객들이 이해하기 쉽도록 단순화되었어요.', example_en_4 = 'Under zone pricing, travelling during peak hours in the central zone costs more.', example_ko_4 = '구역 요금제에서는 중심 구역에서 피크 시간대에 이동하면 비용이 더 들어요.', example_en_5 = 'Zone pricing encourages passengers to travel at off-peak times or by alternative routes.', example_ko_5 = '구역 요금제는 승객들이 비혼잡 시간대나 대안 경로로 이동하도록 유도해요.' WHERE id = 'w_transport_C1_22';
UPDATE words SET example_en_2 = 'Operational resilience ensures services continue even when disruptions occur.', example_ko_2 = '운영 회복력은 혼란이 발생해도 서비스가 지속될 수 있도록 해요.', example_en_3 = 'The new signalling system was designed with operational resilience in mind.', example_ko_3 = '새 신호 시스템은 운영 회복력을 고려해 설계되었어요.', example_en_4 = 'Transport authorities conducted stress tests to assess operational resilience.', example_ko_4 = '교통 당국이 운영 회복력을 평가하기 위한 스트레스 테스트를 실시했어요.', example_en_5 = 'Improving operational resilience reduces the impact of unexpected delays on passengers.', example_ko_5 = '운영 회복력 향상은 예상치 못한 지연이 승객에게 미치는 영향을 줄여요.' WHERE id = 'w_transport_C1_23';
UPDATE words SET example_en_2 = 'Fleet management software tracks every vehicle''s location in real time.', example_ko_2 = '기단 관리 소프트웨어는 모든 차량의 위치를 실시간으로 추적해요.', example_en_3 = 'Efficient fleet management can significantly reduce fuel and maintenance costs.', example_ko_3 = '효율적인 기단 관리로 연료 및 유지보수 비용을 크게 절감할 수 있어요.', example_en_4 = 'The authority centralised its fleet management operations to improve efficiency.', example_ko_4 = '당국이 효율성 향상을 위해 기단 관리 업무를 중앙화했어요.', example_en_5 = 'Modern fleet management systems alert operators to vehicles that need servicing.', example_ko_5 = '현대적인 기단 관리 시스템은 운영자에게 서비스가 필요한 차량을 알려줘요.' WHERE id = 'w_transport_C1_24';
UPDATE words SET example_en_2 = 'Demand forecasting is used to decide how many trains to run on a given day.', example_ko_2 = '수요 예측은 특정 날에 몇 대의 열차를 운행할지 결정하는 데 사용돼요.', example_en_3 = 'Accurate demand forecasting prevents both overcrowding and empty vehicles.', example_ko_3 = '정확한 수요 예측은 과밀 승차와 공차 운행을 모두 방지해요.', example_en_4 = 'The transport planner used demographic data to improve demand forecasting.', example_ko_4 = '교통 계획자가 인구 통계 데이터를 이용해 수요 예측을 개선했어요.', example_en_5 = 'Demand forecasting models have become much more accurate with the use of AI.', example_ko_5 = 'AI 활용으로 수요 예측 모델이 훨씬 더 정확해졌어요.' WHERE id = 'w_transport_C1_25';
UPDATE words SET example_en_2 = 'The new rolling stock is quieter, faster, and more energy-efficient.', example_ko_2 = '새 차량은 더 조용하고 빠르며 에너지 효율도 더 높아요.', example_en_3 = 'Procuring new rolling stock is a long and complex process.', example_ko_3 = '새로운 차량을 조달하는 것은 길고 복잡한 과정이에요.', example_en_4 = 'The ageing rolling stock is no longer fit for purpose and must be replaced.', example_ko_4 = '노후화된 차량은 더 이상 목적에 맞지 않아 교체되어야 해요.', example_en_5 = 'Rolling stock manufacturers competed for a large government contract.', example_ko_5 = '차량 제조사들이 대규모 정부 계약을 위해 경쟁했어요.' WHERE id = 'w_transport_C1_26';
UPDATE words SET example_en_2 = 'The transit pass gives unlimited travel on all bus and metro routes for one month.', example_ko_2 = '교통 정기권으로 한 달 동안 모든 버스 및 지하철 노선을 무제한 이용할 수 있어요.', example_en_3 = 'A transit pass is far cheaper than buying individual tickets each day.', example_ko_3 = '교통 정기권은 매일 개별 티켓을 구매하는 것보다 훨씬 저렴해요.', example_en_4 = 'The student transit pass is subsidised by the city government.', example_ko_4 = '학생 교통 정기권은 시 정부의 보조금을 받아요.', example_en_5 = 'Senior citizens can obtain a concessionary transit pass at reduced cost.', example_ko_5 = '노인들은 할인된 가격으로 노인 할인 교통 정기권을 받을 수 있어요.' WHERE id = 'w_transport_C1_27';
UPDATE words SET example_en_2 = 'Trackwork over the weekend will cause significant disruption to rail services.', example_ko_2 = '주말 선로 작업으로 인해 철도 서비스에 상당한 혼란이 발생할 거예요.', example_en_3 = 'Planned trackwork is essential to maintain the safety of the network.', example_ko_3 = '계획된 선로 작업은 네트워크의 안전을 유지하는 데 필수적이에요.', example_en_4 = 'Passengers are advised to allow extra time due to ongoing trackwork.', example_ko_4 = '진행 중인 선로 작업으로 인해 여유 시간을 두도록 안내 드려요.', example_en_5 = 'The trackwork programme is expected to last three years.', example_ko_5 = '선로 작업 프로그램은 3년간 지속될 것으로 예상돼요.' WHERE id = 'w_transport_C1_28';
UPDATE words SET example_en_2 = 'Interoperability between rail networks allows trains to cross national borders without stopping.', example_ko_2 = '철도 네트워크 간 상호 운용성 덕분에 기차가 정차 없이 국경을 넘을 수 있어요.', example_en_3 = 'The lack of interoperability between ticketing systems frustrates commuters.', example_ko_3 = '발권 시스템 간 상호 운용성 부재가 통근자들을 불편하게 해요.', example_en_4 = 'Technical interoperability is a prerequisite for a unified European rail area.', example_ko_4 = '기술적 상호 운용성은 통합 유럽 철도 지역을 위한 전제 조건이에요.', example_en_5 = 'Achieving interoperability across platforms requires significant standardisation.', example_ko_5 = '플랫폼 전반의 상호 운용성 달성을 위해서는 상당한 표준화가 필요해요.' WHERE id = 'w_transport_C1_29';
UPDATE words SET example_en_2 = 'Paratransit services are critical for passengers who cannot use standard public transport.', example_ko_2 = '특별 교통 서비스는 일반 대중교통을 이용할 수 없는 승객들에게 매우 중요해요.', example_en_3 = 'A paratransit booking must be made at least twenty-four hours in advance.', example_ko_3 = '특별 교통 예약은 최소 24시간 전에 이루어져야 해요.', example_en_4 = 'Funding for paratransit has been protected despite wider budget cuts.', example_ko_4 = '광범위한 예산 삭감에도 불구하고 특별 교통에 대한 자금 지원은 유지되었어요.', example_en_5 = 'The paratransit driver is trained to assist passengers with complex mobility needs.', example_ko_5 = '특별 교통 기사는 복잡한 이동 요구가 있는 승객을 돕는 교육을 받았어요.' WHERE id = 'w_transport_C1_30';
UPDATE words SET example_en_2 = 'A modal shift from road to rail is necessary to reduce carbon emissions.', example_ko_2 = '탄소 배출을 줄이기 위해 도로에서 철도로의 수단 전환이 필요해요.', example_en_3 = 'The government is investing in cycle infrastructure to encourage modal shift.', example_ko_3 = '정부가 수단 전환을 장려하기 위해 자전거 인프라에 투자하고 있어요.', example_en_4 = 'A modal shift towards public transport could reduce urban congestion significantly.', example_ko_4 = '대중교통으로의 수단 전환은 도시 혼잡을 크게 줄일 수 있어요.', example_en_5 = 'Achieving a meaningful modal shift requires both infrastructure and behavioural change.', example_ko_5 = '의미 있는 수단 전환을 달성하려면 인프라와 행동 변화가 모두 필요해요.' WHERE id = 'w_transport_C1_31';
UPDATE words SET example_en_2 = 'The government was accused of overshoot in its rail investment projections.', example_ko_2 = '정부가 철도 투자 예측에서 과잉 추정을 했다는 비난을 받았어요.', example_en_3 = 'Traffic overshoot at the junction caused knock-on delays throughout the network.', example_ko_3 = '교차로에서의 교통 과부하가 네트워크 전체에 연쇄 지연을 초래했어요.', example_en_4 = 'Budget overshoot on the infrastructure project led to a parliamentary inquiry.', example_ko_4 = '인프라 사업의 예산 초과로 의회 조사가 이루어졌어요.', example_en_5 = 'Engineers warned of capacity overshoot if no new lines were added.', example_ko_5 = '엔지니어들이 새 노선을 추가하지 않으면 용량 초과가 발생할 것이라고 경고했어요.' WHERE id = 'w_transport_C1_32';
UPDATE words SET example_en_2 = 'The interline agreement allows passengers to use one ticket across both rail networks.', example_ko_2 = '노선 간 협약으로 승객들이 두 철도 네트워크 모두에서 하나의 티켓을 사용할 수 있어요.', example_en_3 = 'An interline agreement was signed between the two competing ferry operators.', example_ko_3 = '두 경쟁 페리 운영사 간에 노선 간 협약이 체결되었어요.', example_en_4 = 'Interline agreements are standard practice in the international aviation industry.', example_ko_4 = '노선 간 협약은 국제 항공 산업에서 표준 관행이에요.', example_en_5 = 'The interline agreement broke down after the two operators failed to agree on revenue sharing.', example_ko_5 = '두 운영사가 수익 배분에 합의하지 못해 노선 간 협약이 결렬되었어요.' WHERE id = 'w_transport_C1_33';
UPDATE words SET example_en_2 = 'The signalling system was upgraded to allow closer spacing between trains.', example_ko_2 = '신호 시스템이 열차 간 간격을 더 좁힐 수 있도록 업그레이드되었어요.', example_en_3 = 'A failure in the signalling system caused widespread cancellations across the network.', example_ko_3 = '신호 시스템 고장으로 네트워크 전체에 광범위한 취소가 발생했어요.', example_en_4 = 'The new European Train Control signalling system is being rolled out progressively.', example_ko_4 = '새로운 유럽 열차 제어 신호 시스템이 단계적으로 도입되고 있어요.', example_en_5 = 'Modern signalling systems use digital technology rather than traditional track circuits.', example_ko_5 = '현대적인 신호 시스템은 기존 궤도 회로 대신 디지털 기술을 사용해요.' WHERE id = 'w_transport_C1_34';
UPDATE words SET example_en_2 = 'Curbside management determines who can load, unload, and park on a given street.', example_ko_2 = '도로변 관리는 특정 도로에서 누가 짐을 싣고 내리고 주차할 수 있는지 결정해요.', example_en_3 = 'The city reformed its curbside management policy to prioritise deliveries over private parking.', example_ko_3 = '도시는 개인 주차보다 배송을 우선시하는 방향으로 도로변 관리 정책을 개혁했어요.', example_en_4 = 'Curbside management is increasingly important as e-commerce delivery volumes grow.', example_ko_4 = '전자상거래 배송량이 늘면서 도로변 관리가 점점 더 중요해지고 있어요.', example_en_5 = 'Poor curbside management leads to illegal parking that blocks cycle lanes and bus stops.', example_ko_5 = '도로변 관리 미흡으로 자전거 도로와 버스 정류장을 막는 불법 주차가 발생해요.' WHERE id = 'w_transport_C1_35';
UPDATE words SET example_en_2 = 'Telematics data from fleet vehicles allows operators to monitor driver behaviour.', example_ko_2 = '기단 차량의 원격 측정 데이터를 통해 운영자가 운전 행동을 모니터링할 수 있어요.', example_en_3 = 'Insurance companies use telematics to offer usage-based premium pricing.', example_ko_3 = '보험 회사들은 원격 측정을 이용해 이용 기반 보험료 책정을 제공해요.', example_en_4 = 'Telematics systems can detect harsh braking events and alert fleet managers.', example_ko_4 = '원격 측정 시스템은 급제동 사건을 감지하고 기단 관리자에게 알릴 수 있어요.', example_en_5 = 'The transport authority uses telematics to optimise bus scheduling in real time.', example_ko_5 = '교통 당국은 원격 측정을 이용해 버스 일정을 실시간으로 최적화해요.' WHERE id = 'w_transport_C2_01';
UPDATE words SET example_en_2 = 'Decarbonization of the heavy freight sector requires a fundamental shift in technology.', example_ko_2 = '중량 화물 부문의 탈탄소화는 기술의 근본적인 전환이 필요해요.', example_en_3 = 'The government published a roadmap for the decarbonization of all surface transport.', example_ko_3 = '정부가 모든 지상 교통의 탈탄소화를 위한 로드맵을 발표했어요.', example_en_4 = 'Decarbonization targets are driving huge investment in electric vehicle technology.', example_ko_4 = '탈탄소화 목표가 전기차 기술에 대한 막대한 투자를 이끌고 있어요.', example_en_5 = 'Progress on decarbonization in aviation has been slower than in other transport modes.', example_ko_5 = '항공 분야의 탈탄소화 진전은 다른 교통 수단보다 더디게 이루어졌어요.' WHERE id = 'w_transport_C2_02';
UPDATE words SET example_en_2 = 'Micromobility options such as e-scooters are reshaping short urban journeys.', example_ko_2 = '전동 킥보드와 같은 마이크로 모빌리티 옵션이 단거리 도시 이동을 재편하고 있어요.', example_en_3 = 'Cities are grappling with how to regulate micromobility safely.', example_ko_3 = '도시들이 마이크로 모빌리티를 안전하게 규제하는 방법을 고민하고 있어요.', example_en_4 = 'A well-designed micromobility network requires dedicated infrastructure and clear rules.', example_ko_4 = '잘 설계된 마이크로 모빌리티 네트워크는 전용 인프라와 명확한 규칙이 필요해요.', example_en_5 = 'Micromobility has grown fastest in cities with warm climates and flat terrain.', example_ko_5 = '마이크로 모빌리티는 따뜻한 기후와 평탄한 지형을 가진 도시에서 가장 빠르게 성장했어요.' WHERE id = 'w_transport_C2_03';
UPDATE words SET example_en_2 = 'The hyperloop promises to connect cities hundreds of kilometres apart in minutes.', example_ko_2 = '하이퍼루프는 수백 킬로미터 떨어진 도시들을 몇 분 안에 연결하겠다고 약속해요.', example_en_3 = 'Several companies are competing to build the world''s first operational hyperloop system.', example_ko_3 = '세계 최초의 운영 하이퍼루프 시스템을 건설하기 위해 여러 회사들이 경쟁하고 있어요.', example_en_4 = 'Hyperloop technology still faces significant engineering and regulatory hurdles.', example_ko_4 = '하이퍼루프 기술은 아직 상당한 공학적·규제적 장애물에 직면해 있어요.', example_en_5 = 'Proponents argue that hyperloop could revolutionize intercity transport within a generation.', example_ko_5 = '지지자들은 하이퍼루프가 한 세대 안에 도시 간 교통을 혁신할 수 있다고 주장해요.' WHERE id = 'w_transport_C2_04';
UPDATE words SET example_en_2 = 'Geospatial analysis reveals where transport gaps are most acute across the city.', example_ko_2 = '공간 분석을 통해 도시 전역에서 교통 격차가 가장 심한 곳을 파악할 수 있어요.', example_en_3 = 'The planning team used geospatial analysis to identify optimal locations for new bus stops.', example_ko_3 = '계획 팀이 공간 분석을 이용해 새 버스 정류장의 최적 위치를 파악했어요.', example_en_4 = 'Geospatial analysis integrates population data with existing transport route maps.', example_ko_4 = '공간 분석은 인구 데이터와 기존 교통 노선 지도를 통합해요.', example_en_5 = 'Advances in geospatial analysis have transformed evidence-based transport planning.', example_ko_5 = '공간 분석의 발전이 근거 기반 교통 계획을 변화시켰어요.' WHERE id = 'w_transport_C2_05';
UPDATE words SET example_en_2 = 'Actuarial modelling is used to price risk in transport insurance products.', example_ko_2 = '보험 계리 모델링은 교통 보험 상품의 위험을 가격 책정하는 데 사용돼요.', example_en_3 = 'The firm employed actuarial modelling to forecast long-term infrastructure maintenance costs.', example_ko_3 = '그 회사는 장기 인프라 유지 비용을 예측하기 위해 보험 계리 모델링을 활용했어요.', example_en_4 = 'Actuarial modelling informed the decision to extend the rail franchise by seven years.', example_ko_4 = '보험 계리 모델링이 철도 운영권을 7년 연장하는 결정에 정보를 제공했어요.', example_en_5 = 'Without robust actuarial modelling, public-private partnerships carry excessive financial risk.', example_ko_5 = '강력한 보험 계리 모델링 없이는 공민 파트너십이 과도한 재정적 위험을 감수해요.' WHERE id = 'w_transport_C2_06';
UPDATE words SET example_en_2 = 'Vehicle-to-grid technology enables electric cars to supply power back to the grid.', example_ko_2 = '차량-전력망 기술은 전기차가 전력망에 전력을 다시 공급할 수 있게 해요.', example_en_3 = 'Vehicle-to-grid schemes could help balance electricity demand during peak periods.', example_ko_3 = '차량-전력망 계획은 피크 시간대의 전력 수요 균형을 맞추는 데 도움이 될 수 있어요.', example_en_4 = 'The pilot programme tested vehicle-to-grid charging at a large bus depot.', example_ko_4 = '시범 프로그램이 대형 버스 차고지에서 차량-전력망 충전을 시험했어요.', example_en_5 = 'Vehicle-to-grid technology represents a significant step towards smart energy management.', example_ko_5 = '차량-전력망 기술은 스마트 에너지 관리를 향한 중요한 단계를 나타내요.' WHERE id = 'w_transport_C2_07';
UPDATE words SET example_en_2 = 'Congestion pricing uses variable charges to discourage driving at peak times.', example_ko_2 = '혼잡 가격제는 가변 요금을 사용해 피크 시간대 운전을 억제해요.', example_en_3 = 'A well-designed congestion pricing scheme can generate revenue for public transport investment.', example_ko_3 = '잘 설계된 혼잡 가격제는 대중교통 투자를 위한 수입을 창출할 수 있어요.', example_en_4 = 'Congestion pricing has been shown to reduce traffic volumes in central urban areas.', example_ko_4 = '혼잡 가격제는 도심 교통량을 줄이는 효과가 있는 것으로 입증되었어요.', example_en_5 = 'Critics of congestion pricing argue that it disproportionately burdens lower-income drivers.', example_ko_5 = '혼잡 가격제 비판론자들은 그것이 저소득 운전자들에게 불균형적으로 부담을 준다고 주장해요.' WHERE id = 'w_transport_C2_08';
UPDATE words SET example_en_2 = 'The externality of noise pollution from motorways is rarely factored into road pricing.', example_ko_2 = '고속도로의 소음 공해 외부성은 도로 요금에 거의 반영되지 않아요.', example_en_3 = 'Carbon emissions are the classic transport externality that market prices fail to capture.', example_ko_3 = '탄소 배출은 시장 가격이 포착하지 못하는 전형적인 교통 외부성이에요.', example_en_4 = 'Internalising the externality of road transport requires a combination of taxes and regulations.', example_ko_4 = '도로 교통의 외부성을 내부화하려면 세금과 규제의 조합이 필요해요.', example_en_5 = 'Economists argue that failure to price the externality of congestion leads to overuse of roads.', example_ko_5 = '경제학자들은 혼잡 외부성의 가격 책정 실패가 도로의 과도한 이용을 초래한다고 주장해요.' WHERE id = 'w_transport_C2_09';
UPDATE words SET example_en_2 = 'Autonomous vehicle liability is contested between manufacturers, software developers, and insurers.', example_ko_2 = '자율 주행 차량 책임은 제조사, 소프트웨어 개발자, 보험사 간에 다투어지고 있어요.', example_en_3 = 'Current legislation has not kept pace with the complex issues of autonomous vehicle liability.', example_ko_3 = '현행 법률은 자율 주행 차량 책임의 복잡한 문제를 따라가지 못하고 있어요.', example_en_4 = 'Defining autonomous vehicle liability is one of the most contentious issues in transport law.', example_ko_4 = '자율 주행 차량 책임 정의는 교통 법규에서 가장 논쟁이 많은 문제 중 하나예요.', example_en_5 = 'Without clarity on autonomous vehicle liability, insurers are reluctant to offer coverage.', example_ko_5 = '자율 주행 차량 책임이 명확하지 않으면 보험사들이 보장을 제공하기를 꺼려해요.' WHERE id = 'w_transport_C2_10';
UPDATE words SET example_en_2 = 'Breakthroughs in propulsion technology could make long-haul electric flight viable.', example_ko_2 = '추진 기술의 혁신이 장거리 전기 비행을 실용화할 수 있어요.', example_en_3 = 'Hydrogen-based propulsion technology is being tested on short-haul rail routes.', example_ko_3 = '수소 기반 추진 기술이 단거리 철도 노선에서 시험되고 있어요.', example_en_4 = 'The choice of propulsion technology has major implications for emissions and infrastructure.', example_ko_4 = '추진 기술의 선택은 배출량과 인프라에 중대한 영향을 미쳐요.', example_en_5 = 'Investment in propulsion technology is accelerating as fuel costs and climate targets intensify.', example_ko_5 = '연료 비용과 기후 목표가 강화되면서 추진 기술에 대한 투자가 가속화되고 있어요.' WHERE id = 'w_transport_C2_11';
UPDATE words SET example_en_2 = 'A smart motorway uses variable speed limits and managed lanes to reduce congestion.', example_ko_2 = '스마트 고속도로는 가변 제한 속도와 관리 차선을 이용해 혼잡을 줄여요.', example_en_3 = 'The smart motorway system detects incidents and automatically alerts drivers.', example_ko_3 = '스마트 고속도로 시스템이 사고를 감지하고 자동으로 운전자에게 알려요.', example_en_4 = 'Critics have raised safety concerns about the all-lane running aspect of smart motorway design.', example_ko_4 = '비평가들은 스마트 고속도로 설계의 전 차선 주행 방식에 대한 안전 우려를 제기했어요.', example_en_5 = 'Smart motorway technology is being considered for expansion across the national road network.', example_ko_5 = '스마트 고속도로 기술이 국가 도로망 전체로 확장하는 것이 검토되고 있어요.' WHERE id = 'w_transport_C2_12';
UPDATE words SET example_en_2 = 'The infrastructure deficit in rural areas means many communities lack reliable transport.', example_ko_2 = '농촌 지역의 인프라 부족은 많은 지역 사회가 안정적인 교통 수단이 없다는 것을 의미해요.', example_en_3 = 'Closing the infrastructure deficit will require sustained investment over decades.', example_ko_3 = '인프라 부족을 해소하려면 수십 년에 걸친 지속적인 투자가 필요해요.', example_en_4 = 'The infrastructure deficit is widening as populations grow but funding remains flat.', example_ko_4 = '인구는 증가하는데 자금 지원은 그대로여서 인프라 부족이 확대되고 있어요.', example_en_5 = 'An infrastructure deficit review was commissioned to identify the most urgent priorities.', example_ko_5 = '가장 시급한 우선 사항을 파악하기 위해 인프라 부족 검토가 의뢰되었어요.' WHERE id = 'w_transport_C2_13';
UPDATE words SET example_en_2 = 'MAAS integrates all transport modes into a single digital platform accessible by smartphone.', example_ko_2 = 'MaaS는 모든 교통 수단을 스마트폰으로 접근 가능한 단일 디지털 플랫폼에 통합해요.', example_en_3 = 'The city piloted a MAAS scheme to reduce car ownership among younger residents.', example_ko_3 = '도시는 젊은 거주자들의 자가용 소유를 줄이기 위한 MaaS 계획을 시범 운영했어요.', example_en_4 = 'Achieving true MAAS requires seamless data sharing between competing transport providers.', example_ko_4 = '진정한 MaaS를 실현하려면 경쟁 교통 서비스 제공자 간의 원활한 데이터 공유가 필요해요.', example_en_5 = 'MAAS could transform how people plan and pay for their daily commutes.', example_ko_5 = 'MaaS는 사람들이 일상 통근을 계획하고 결제하는 방식을 바꿀 수 있어요.' WHERE id = 'w_transport_C2_14';
UPDATE words SET example_en_2 = 'The regulatory sandbox allowed autonomous vehicle trials without full compliance requirements.', example_ko_2 = '규제 샌드박스는 완전한 준수 요건 없이 자율 주행 차량 시험을 허용했어요.', example_en_3 = 'A regulatory sandbox was created to test new drone delivery services in urban areas.', example_ko_3 = '도시 지역에서 새로운 드론 배송 서비스를 시험하기 위한 규제 샌드박스가 만들어졌어요.', example_en_4 = 'The regulatory sandbox approach balances innovation with appropriate consumer protection.', example_ko_4 = '규제 샌드박스 접근 방식은 혁신과 적절한 소비자 보호 사이의 균형을 맞춰요.', example_en_5 = 'Several ride-sharing startups were invited to test services within the regulatory sandbox.', example_ko_5 = '여러 라이드셰어링 스타트업이 규제 샌드박스 내에서 서비스를 시험하도록 초대받았어요.' WHERE id = 'w_transport_C2_15';
UPDATE words SET example_en_2 = 'The energy density of aviation fuel is far higher than that of current batteries.', example_ko_2 = '항공 연료의 에너지 밀도는 현재 배터리보다 훨씬 높아요.', example_en_3 = 'Improving energy density is the key technical challenge for electric vehicle batteries.', example_ko_3 = '에너지 밀도 향상이 전기차 배터리의 핵심 기술 과제예요.', example_en_4 = 'The energy density of hydrogen makes it attractive for use in heavy transport.', example_ko_4 = '수소의 에너지 밀도는 중량 교통 수단에서의 사용을 매력적으로 만들어요.', example_en_5 = 'Solid-state batteries promise a step change in energy density for electric vehicles.', example_ko_5 = '고체 전지는 전기차를 위한 에너지 밀도의 획기적인 개선을 약속해요.' WHERE id = 'w_transport_C2_16';
UPDATE words SET example_en_2 = 'The catenation of multiple train units allows the service to be extended during busy periods.', example_ko_2 = '여러 열차 편성의 연결로 혼잡 시간대에 서비스를 연장할 수 있어요.', example_en_3 = 'Catenation of trailers is common in long-haul road freight operations.', example_ko_3 = '트레일러 연결은 장거리 도로 화물 운송에서 흔한 방식이에요.', example_en_4 = 'The timetable was adjusted to allow catenation at the main junction station.', example_ko_4 = '주요 분기 역에서의 연결을 허용하기 위해 시간표가 조정되었어요.', example_en_5 = 'Catenation of bus units is used on high-demand routes to increase passenger capacity.', example_ko_5 = '버스 편성 연결은 승객 수용 능력을 높이기 위해 수요가 높은 노선에서 사용돼요.' WHERE id = 'w_transport_C2_17';
UPDATE words SET example_en_2 = 'The airline purchased carbon offsets to compensate for its annual emissions.', example_ko_2 = '항공사가 연간 배출량을 상쇄하기 위해 탄소 상쇄권을 구입했어요.', example_en_3 = 'Carbon offset schemes have been criticised for allowing polluters to avoid real change.', example_ko_3 = '탄소 상쇄 계획은 오염 유발자들이 실질적인 변화를 피하게 해준다는 비판을 받아왔어요.', example_en_4 = 'The rail operator planted trees as part of a carbon offset commitment.', example_ko_4 = '철도 운영사가 탄소 상쇄 약속의 일환으로 나무를 심었어요.', example_en_5 = 'Regulators are debating whether carbon offset schemes genuinely reduce overall emissions.', example_ko_5 = '규제 기관들이 탄소 상쇄 계획이 전체 배출량을 실질적으로 줄이는지에 대해 논의하고 있어요.' WHERE id = 'w_transport_C2_18';
UPDATE words SET example_en_2 = 'Improving the freight modal split means moving more goods by rail and less by road.', example_ko_2 = '화물 수단 분담률 개선은 더 많은 화물을 도로 대신 철도로 이동시키는 것을 의미해요.', example_en_3 = 'Government subsidies for rail freight are intended to shift the freight modal split.', example_ko_3 = '철도 화물에 대한 정부 보조금은 화물 수단 분담률을 바꾸기 위한 것이에요.', example_en_4 = 'The freight modal split varies widely between countries depending on geography and policy.', example_ko_4 = '화물 수단 분담률은 지리와 정책에 따라 나라마다 크게 달라요.', example_en_5 = 'Measuring the freight modal split accurately requires comprehensive data collection.', example_ko_5 = '화물 수단 분담률을 정확히 측정하려면 포괄적인 데이터 수집이 필요해요.' WHERE id = 'w_transport_C2_19';
UPDATE words SET example_en_2 = 'Connected vehicles share data with each other and with roadside infrastructure.', example_ko_2 = '연결 차량은 서로와 도로변 인프라와 데이터를 공유해요.', example_en_3 = 'The connected vehicle programme aims to reduce accidents by improving hazard awareness.', example_ko_3 = '연결 차량 프로그램은 위험 인식을 높여 사고를 줄이는 것을 목표로 해요.', example_en_4 = 'A connected vehicle fleet can be managed and rerouted centrally in real time.', example_ko_4 = '연결 차량 기단은 실시간으로 중앙에서 관리 및 우회될 수 있어요.', example_en_5 = 'Privacy concerns around connected vehicle data collection remain a significant policy issue.', example_ko_5 = '연결 차량 데이터 수집에 관한 개인 정보 보호 우려는 여전히 중요한 정책 사안이에요.' WHERE id = 'w_transport_C2_20';
UPDATE words SET example_en_2 = 'Land use integration ensures that new housing developments are served by adequate transport.', example_ko_2 = '토지 이용 통합은 새로운 주거 개발 지역에 적절한 교통 서비스가 제공되도록 보장해요.', example_en_3 = 'Poor land use integration is a major cause of car dependency in suburban areas.', example_ko_3 = '토지 이용 통합 미흡이 교외 지역 자가용 의존의 주요 원인이에요.', example_en_4 = 'The planning authority enforced land use integration guidelines for all major developments.', example_ko_4 = '계획 당국이 모든 주요 개발에 토지 이용 통합 지침을 시행했어요.', example_en_5 = 'Land use integration between transport and housing policy has historically been weak.', example_ko_5 = '교통 및 주택 정책 간의 토지 이용 통합은 역사적으로 미흡했어요.' WHERE id = 'w_transport_C2_21';
UPDATE words SET example_en_2 = 'The value of time is a key parameter in transport cost-benefit analysis.', example_ko_2 = '시간 가치는 교통 비용-편익 분석에서 핵심 매개변수예요.', example_en_3 = 'The value of time varies significantly between business travellers and leisure passengers.', example_ko_3 = '시간 가치는 비즈니스 여행자와 여가 승객 사이에 크게 차이가 있어요.', example_en_4 = 'Transport economists use the value of time to justify investment in faster rail links.', example_ko_4 = '교통 경제학자들은 더 빠른 철도 연결에 대한 투자를 정당화하기 위해 시간 가치를 사용해요.', example_en_5 = 'Higher-income travellers typically place a greater value of time on their journeys.', example_ko_5 = '고소득 여행자들은 일반적으로 자신의 이동에 더 높은 시간 가치를 부여해요.' WHERE id = 'w_transport_C2_22';
UPDATE words SET example_en_2 = 'Peak spreading encourages travellers to shift journeys to slightly earlier or later times.', example_ko_2 = '피크 분산은 여행자들이 이동 시간을 조금 더 일찍 또는 늦게 전환하도록 장려해요.', example_en_3 = 'Flexible working hours have contributed significantly to peak spreading.', example_ko_3 = '유연 근무제가 피크 분산에 크게 기여했어요.', example_en_4 = 'Peak spreading reduces the pressure on infrastructure at the busiest times.', example_ko_4 = '피크 분산은 가장 바쁜 시간대에 인프라에 대한 부담을 줄여요.', example_en_5 = 'Pricing incentives are often used to encourage peak spreading among commuters.', example_ko_5 = '가격 인센티브는 통근자들 사이에서 피크 분산을 장려하기 위해 자주 사용돼요.' WHERE id = 'w_transport_C2_23';
UPDATE words SET example_en_2 = 'The government issued an infrastructure bond to fund the new metro line.', example_ko_2 = '정부가 새 지하철 노선 자금 조달을 위해 인프라 채권을 발행했어요.', example_en_3 = 'Infrastructure bonds attract long-term institutional investors such as pension funds.', example_ko_3 = '인프라 채권은 연금 펀드와 같은 장기 기관 투자자들을 끌어들여요.', example_en_4 = 'The infrastructure bond market has grown as governments seek private capital.', example_ko_4 = '정부가 민간 자본을 유치하면서 인프라 채권 시장이 성장했어요.', example_en_5 = 'Ratings agencies assess infrastructure bonds based on projected traffic revenues.', example_ko_5 = '신용 평가 기관들이 예상 교통 수입을 기반으로 인프라 채권을 평가해요.' WHERE id = 'w_transport_C2_24';
UPDATE words SET example_en_2 = 'Induced traffic is the additional vehicle trips generated when road capacity is increased.', example_ko_2 = '유발 교통량은 도로 용량이 증가할 때 발생하는 추가 차량 통행이에요.', example_en_3 = 'Research consistently shows that induced traffic offsets much of the benefit of new roads.', example_ko_3 = '연구에 따르면 유발 교통량이 새 도로의 혜택 대부분을 상쇄해요.', example_en_4 = 'The environmental impact assessment must account for induced traffic from the new motorway.', example_ko_4 = '환경 영향 평가는 새 고속도로로 인한 유발 교통량을 고려해야 해요.', example_en_5 = 'Planners who ignore induced traffic often underestimate the long-term congestion impact.', example_ko_5 = '유발 교통량을 무시하는 계획자들은 종종 장기적인 혼잡 영향을 과소평가해요.' WHERE id = 'w_transport_C2_25';
UPDATE words SET example_en_2 = 'Truck platooning could reduce fuel consumption by up to fifteen percent.', example_ko_2 = '트럭 군집 주행은 연료 소비를 최대 15퍼센트까지 줄일 수 있어요.', example_en_3 = 'Platooning requires highly reliable vehicle-to-vehicle communication systems.', example_ko_3 = '군집 주행은 매우 신뢰성 높은 차량 간 통신 시스템이 필요해요.', example_en_4 = 'The highway authority designated a lane for platooning trials on the motorway.', example_ko_4 = '고속도로 당국이 고속도로에서의 군집 주행 시험을 위한 차선을 지정했어요.', example_en_5 = 'Platooning is most effective on long, straight motorway sections with predictable traffic.', example_ko_5 = '군집 주행은 교통이 예측 가능한 길고 직선적인 고속도로 구간에서 가장 효과적이에요.' WHERE id = 'w_transport_C2_26';
UPDATE words SET example_en_2 = 'Stochastic demand models account for the inherent unpredictability of passenger behaviour.', example_ko_2 = '확률적 수요 모델은 승객 행동의 본질적인 예측 불가능성을 고려해요.', example_en_3 = 'Planning a transport network based only on average demand ignores stochastic variation.', example_ko_3 = '평균 수요만을 기반으로 교통 네트워크를 계획하는 것은 확률적 변동을 무시하는 거예요.', example_en_4 = 'The simulation used stochastic demand inputs to test the system under different scenarios.', example_ko_4 = '시뮬레이션은 다양한 시나리오에서 시스템을 테스트하기 위해 확률적 수요 입력값을 사용했어요.', example_en_5 = 'Stochastic demand modelling helps operators plan for both peak and low-ridership scenarios.', example_ko_5 = '확률적 수요 모델링은 운영자가 피크 및 저승객 시나리오 모두를 계획하는 데 도움이 돼요.' WHERE id = 'w_transport_C2_27';
UPDATE words SET example_en_2 = 'Electrolysis produces hydrogen that can be used as a clean fuel for trains and buses.', example_ko_2 = '전기 분해는 기차와 버스의 청정 연료로 사용될 수 있는 수소를 생성해요.', example_en_3 = 'Green hydrogen produced by electrolysis offers a pathway to decarbonize heavy transport.', example_ko_3 = '전기 분해로 생산된 그린 수소는 중량 교통을 탈탄소화할 수 있는 경로를 제공해요.', example_en_4 = 'The cost of electrolysis is falling rapidly as renewable energy becomes cheaper.', example_ko_4 = '재생 에너지가 저렴해지면서 전기 분해 비용이 빠르게 하락하고 있어요.', example_en_5 = 'Scaling up electrolysis capacity is essential for a hydrogen-based transport future.', example_ko_5 = '수소 기반 교통의 미래를 위해 전기 분해 용량을 확대하는 것이 필수적이에요.' WHERE id = 'w_transport_C2_28';
UPDATE words SET example_en_2 = 'Right-of-way acquisition is often the longest stage of any new rail project.', example_ko_2 = '통행권 취득은 종종 새로운 철도 사업의 가장 긴 단계예요.', example_en_3 = 'Disputes over right-of-way acquisition delayed the bypass by three years.', example_ko_3 = '통행권 취득 분쟁으로 우회도로가 3년 지연되었어요.', example_en_4 = 'The authority used compulsory purchase powers to complete right-of-way acquisition.', example_ko_4 = '당국이 통행권 취득을 완료하기 위해 강제 매수 권한을 사용했어요.', example_en_5 = 'Transparent and fair right-of-way acquisition processes help maintain public trust.', example_ko_5 = '투명하고 공정한 통행권 취득 절차는 대중의 신뢰를 유지하는 데 도움이 돼요.' WHERE id = 'w_transport_C2_29';
UPDATE words SET example_en_2 = 'The operational expenditure of the metro system exceeds its fare revenue each year.', example_ko_2 = '지하철 시스템의 운영 지출은 매년 요금 수입을 초과해요.', example_en_3 = 'Reducing operational expenditure without cutting services is a key management challenge.', example_ko_3 = '서비스를 삭감하지 않고 운영 지출을 줄이는 것이 핵심 관리 과제예요.', example_en_4 = 'Technology upgrades can reduce long-term operational expenditure significantly.', example_ko_4 = '기술 업그레이드로 장기 운영 지출을 크게 줄일 수 있어요.', example_en_5 = 'The subsidy covers the gap between operational expenditure and farebox revenue.', example_ko_5 = '보조금이 운영 지출과 요금 수입 간의 차이를 메워요.' WHERE id = 'w_transport_C2_30';
UPDATE words SET example_en_2 = 'The catenary must be maintained regularly to ensure reliable train operation.', example_ko_2 = '안정적인 열차 운행을 위해 가선은 정기적으로 유지보수되어야 해요.', example_en_3 = 'A fallen catenary wire caused services to be suspended for several hours.', example_ko_3 = '가선이 끊어져 수 시간 동안 서비스가 중단되었어요.', example_en_4 = 'Extending the catenary to rural routes is a major challenge of rail electrification.', example_ko_4 = '농촌 노선까지 가선을 연장하는 것은 철도 전철화의 주요 과제예요.', example_en_5 = 'Automated drones are being tested to inspect the catenary more efficiently.', example_ko_5 = '가선을 더 효율적으로 점검하기 위해 자동화 드론이 시험되고 있어요.' WHERE id = 'w_transport_C2_31';
UPDATE words SET example_en_2 = 'Modal integration allows passengers to plan and pay for multimodal trips using a single account.', example_ko_2 = '수단 통합을 통해 승객들이 단일 계정으로 복합 수단 여정을 계획하고 결제할 수 있어요.', example_en_3 = 'The city''s modal integration strategy brought together rail, bus, and bike-share operators.', example_ko_3 = '도시의 수단 통합 전략이 철도, 버스, 공유 자전거 운영사를 한데 모았어요.', example_en_4 = 'Effective modal integration requires shared data standards across all providers.', example_ko_4 = '효과적인 수단 통합을 위해서는 모든 서비스 제공자에 걸쳐 공유된 데이터 표준이 필요해요.', example_en_5 = 'Modal integration improves the passenger experience and encourages public transport use.', example_ko_5 = '수단 통합은 승객 경험을 개선하고 대중교통 이용을 장려해요.' WHERE id = 'w_transport_C2_32';
UPDATE words SET example_en_2 = 'Transport poverty affects communities where public services are infrequent or non-existent.', example_ko_2 = '교통 빈곤은 대중 서비스가 드물거나 없는 지역 사회에 영향을 미쳐요.', example_en_3 = 'Addressing transport poverty requires targeted investment in underserved areas.', example_ko_3 = '교통 빈곤 해결을 위해서는 서비스가 부족한 지역에 대한 집중 투자가 필요해요.', example_en_4 = 'Research links transport poverty to reduced access to employment and healthcare.', example_ko_4 = '연구는 교통 빈곤을 고용 및 의료 서비스에 대한 접근성 저하와 연결시켜요.', example_en_5 = 'Transport poverty is often overlooked in urban policy but has profound social consequences.', example_ko_5 = '교통 빈곤은 도시 정책에서 종종 간과되지만 심각한 사회적 결과를 초래해요.' WHERE id = 'w_transport_C2_33';
UPDATE words SET example_en_2 = 'The navigation system guided the driver from waypoint to waypoint across the route.', example_ko_2 = '내비게이션 시스템이 경로 전반에 걸쳐 웨이포인트에서 웨이포인트로 운전자를 안내했어요.', example_en_3 = 'Each waypoint in the delivery schedule was updated in real time using GPS data.', example_ko_3 = '배송 일정의 각 웨이포인트가 GPS 데이터를 이용해 실시간으로 업데이트되었어요.', example_en_4 = 'The pilot logged each waypoint in the flight plan before departure.', example_ko_4 = '파일럿이 출발 전에 비행 계획의 각 웨이포인트를 기록했어요.', example_en_5 = 'A waypoint mismatch caused the autonomous vehicle to deviate from its planned route.', example_ko_5 = '웨이포인트 불일치로 자율 주행 차량이 계획된 경로에서 벗어났어요.' WHERE id = 'w_transport_C2_34';
UPDATE words SET example_en_2 = 'Service resilience was tested during the extended strike action last winter.', example_ko_2 = '지난 겨울 장기 파업 동안 서비스 회복력이 시험대에 올랐어요.', example_en_3 = 'Building service resilience into the timetable reduces the impact of unplanned disruptions.', example_ko_3 = '시간표에 서비스 회복력을 반영하면 계획되지 않은 혼란의 영향을 줄여요.', example_en_4 = 'The authority published a service resilience plan to reassure passengers.', example_ko_4 = '당국이 승객들을 안심시키기 위해 서비스 회복력 계획을 발표했어요.', example_en_5 = 'Investing in redundant infrastructure is essential for long-term service resilience.', example_ko_5 = '장기적인 서비스 회복력을 위해 이중화 인프라에 투자하는 것이 필수적이에요.' WHERE id = 'w_transport_C2_35';
