  ex2 = 'Could we split the bill three ways?', ex2_ko = '계산서를 셋이서 나눠 낼 수 있나요?',
  ex3 = 'Could we split the bill evenly?', ex3_ko = '계산서 똑같이 나눠 낼 수 있나요?',
