  ex3 = 'I saw this cheaper at your competitor. Can you match the price?', ex3_ko = '경쟁사에서 더 싼 걸 봤어요. 가격을 맞춰주실 수 있나요?',
  ex4 = 'My colleague bought this for less yesterday. Can you match the price?', ex4_ko = '동료가 어제 이걸 더 싸게 샀어요. 가격을 맞춰주실 수 있나요?',
