UPDATE sentences SET
  ex1 = 'We''re looking for a long-term supplier with a proven track record in quality assurance.', ex1_ko = '품질 보증에 있어서 검증된 실적을 가진 장기 공급업체를 찾고 있어요.',
  ex2 = 'We''re looking for a long-term supplier with experience in sustainable manufacturing.', ex2_ko = '지속 가능한 제조 경험이 있는 장기 공급업체를 찾고 있어요.',
  ex3 = 'We''re looking for a long-term logistics partner with a proven track record in on-time delivery.', ex3_ko = '정시 배송에 있어서 검증된 실적을 가진 장기 물류 파트너를 찾고 있어요.',
  ex4 = 'We''re looking for a long-term distributor with an established network in Southeast Asia.', ex4_ko = '동남아시아에 구축된 네트워크를 가진 장기 유통업체를 찾고 있어요.',
  ex5 = 'We''re looking for a long-term retail partner with a proven ability to manage high-volume orders.', ex5_ko = '대량 주문 관리 능력이 검증된 장기 소매 파트너를 찾고 있어요.'
