UPDATE sentences SET
  ex1 = 'We need to carry out due diligence on your supply chain before finalising the contract.', ex1_ko = '계약을 확정하기 전에 공급망에 대한 실사를 진행해야 해요.',
  ex2 = 'We need to carry out due diligence on your financials before finalising the agreement.', ex2_ko = '계약을 확정하기 전에 재무 상황에 대한 실사를 진행해야 해요.',
  ex3 = 'We need to carry out due diligence on your compliance records before proceeding.', ex3_ko = '진행하기 전에 규정 준수 기록에 대한 실사를 진행해야 해요.',
  ex4 = 'We need to carry out due diligence on all proposed partners before making a decision.', ex4_ko = '결정을 내리기 전에 모든 제안된 파트너에 대한 실사를 진행해야 해요.',
  ex5 = 'We need to carry out due diligence on the intellectual property claims before signing.', ex5_ko = '서명 전에 지식재산권 주장에 대한 실사를 진행해야 해요.'
