UPDATE sentences SET
  ex1 = 'I''ve been experiencing chronic lower back pain for several months.', ex1_ko = '수개월째 만성 허리 통증을 겪고 있어요.',
  ex2 = 'I''ve been experiencing chronic lower back pain for several months and it''s affecting my sleep.', ex2_ko = '수개월째 만성 허리 통증을 겪고 있고 수면에도 영향을 주고 있어요.',
  ex3 = 'She''s been experiencing chronic lower back pain since her car accident.', ex3_ko = '그녀는 교통사고 이후로 만성 허리 통증을 겪고 있어요.',
  ex4 = 'He has been experiencing chronic lower back pain and was referred to a physiotherapist.', ex4_ko = '그는 만성 허리 통증을 겪어 물리 치료사에게 의뢰됐어요.',
  ex5 = 'Chronic lower back pain can often be managed with targeted exercise and posture correction.', ex5_ko = '만성 허리 통증은 목표 운동과 자세 교정으로 관리할 수 있는 경우가 많아요.'
WHERE id = 's_health_B1_01';

UPDATE sentences SET
  ex1 = 'The pain gets worse when I sit for a long time.', ex1_ko = '오래 앉아 있으면 통증이 심해져요.',
  ex2 = 'The pain gets worse when I sit for a long time or stand up suddenly.', ex2_ko = '오래 앉아 있거나 갑자기 일어설 때 통증이 심해져요.',
  ex3 = 'Her pain gets worse when she sits for long periods without a break.', ex3_ko = '그녀는 쉬지 않고 오래 앉아 있으면 통증이 심해져요.',
  ex4 = 'He noticed the pain gets worse when he works at his desk all day.', ex4_ko = '그는 하루 종일 책상에 앉아 일할 때 통증이 심해진다는 것을 알게 됐어요.',
  ex5 = 'If the pain gets worse when sitting, try adjusting your chair and taking regular breaks.', ex5_ko = '앉을 때 통증이 심해진다면 의자를 조정하고 정기적으로 휴식을 취해 보세요.'
WHERE id = 's_health_B1_02';

UPDATE sentences SET
  ex1 = 'Could you refer me to a specialist?', ex1_ko = '전문의에게 의뢰해 주실 수 있나요?',
  ex2 = 'Could you refer me to a specialist for a second opinion?', ex2_ko = '다른 의견을 듣기 위해 전문의에게 의뢰해 주실 수 있나요?',
  ex3 = 'She asked her GP to refer her to a specialist for her chronic condition.', ex3_ko = '그녀는 일반의에게 만성 질환 때문에 전문의에게 의뢰해 달라고 요청했어요.',
  ex4 = 'He was relieved when his doctor agreed to refer him to a specialist.', ex4_ko = '그는 의사가 전문의 의뢰에 동의했을 때 안도했어요.',
  ex5 = 'If your condition is not improving, it is reasonable to ask for a referral to a specialist.', ex5_ko = '상태가 나아지지 않는다면 전문의 의뢰를 요청하는 것이 합리적이에요.'
WHERE id = 's_health_B1_03';

UPDATE sentences SET
  ex1 = 'What are the side effects of this medication?', ex1_ko = '이 약의 부작용은 무엇인가요?',
  ex2 = 'What are the side effects of this medication and how long do they last?', ex2_ko = '이 약의 부작용은 무엇이고 얼마나 지속되나요?',
  ex3 = 'She asked the pharmacist about the side effects of the new medication.', ex3_ko = '그녀는 새 약의 부작용에 대해 약사에게 물었어요.',
  ex4 = 'He was concerned about the side effects of the medication before starting the course.', ex4_ko = '그는 복용을 시작하기 전에 약의 부작용이 걱정됐어요.',
  ex5 = 'Always ask about the side effects of any new medication your doctor prescribes.', ex5_ko = '의사가 처방하는 새 약의 부작용은 항상 물어보세요.'
WHERE id = 's_health_B1_04';

UPDATE sentences SET
  ex1 = 'I''d like to discuss my test results.', ex1_ko = '검사 결과를 상담하고 싶어요.',
  ex2 = 'I''d like to discuss my test results and understand what they mean.', ex2_ko = '검사 결과를 상담하고 결과가 무엇을 의미하는지 이해하고 싶어요.',
  ex3 = 'She made an appointment specifically to discuss her test results with the doctor.', ex3_ko = '그녀는 의사와 검사 결과를 상담하기 위해 특별히 예약을 했어요.',
  ex4 = 'He was nervous but relieved after he got to discuss his test results.', ex4_ko = '그는 긴장했지만 검사 결과를 상담한 후 안도했어요.',
  ex5 = 'Never leave a consultation without fully discussing your test results.', ex5_ko = '검사 결과를 충분히 상담하지 않고 진료를 마치지 마세요.'
WHERE id = 's_health_B1_05';

UPDATE sentences SET
  ex1 = 'The doctor told me to avoid spicy food.', ex1_ko = '의사가 자극적인 음식을 피하라고 했어요.',
  ex2 = 'The doctor told me to avoid spicy food and eat smaller meals more often.', ex2_ko = '의사가 자극적인 음식을 피하고 더 자주 소량씩 먹으라고 했어요.',
  ex3 = 'She was frustrated when the doctor told her to avoid spicy food, which she loves.', ex3_ko = '그녀는 자신이 좋아하는 자극적인 음식을 피하라는 의사의 말에 실망했어요.',
  ex4 = 'He followed the doctor''s advice to avoid spicy food and felt much better.', ex4_ko = '그는 자극적인 음식을 피하라는 의사의 조언을 따랐고 훨씬 나아졌어요.',
  ex5 = 'If your doctor tells you to avoid spicy food, try experimenting with milder flavors instead.', ex5_ko = '의사가 자극적인 음식을 피하라고 하면 대신 순한 맛을 시도해 보세요.'
