UPDATE sentences SET
  ex1 = 'I''ve been prescribed physiotherapy for my knee.', ex1_ko = '무릎 때문에 물리 치료를 처방받았어요.',
  ex2 = 'I''ve been prescribed physiotherapy for my knee and I have sessions twice a week.', ex2_ko = '무릎 때문에 물리 치료를 처방받았고 일주일에 두 번 치료를 받아요.',
  ex3 = 'She was prescribed physiotherapy after her knee surgery to regain strength.', ex3_ko = '그녀는 무릎 수술 후 근력을 회복하기 위해 물리 치료를 처방받았어요.',
  ex4 = 'He was prescribed physiotherapy for his knee and noticed improvement within weeks.', ex4_ko = '그는 무릎 물리 치료를 처방받았고 몇 주 안에 호전을 느꼈어요.',
  ex5 = 'Physiotherapy prescribed for a knee injury works best when you follow it consistently.', ex5_ko = '무릎 부상을 위해 처방된 물리 치료는 꾸준히 따를 때 가장 효과적이에요.'
