-- B2

UPDATE sentences SET
  ex1 = 'Maintaining a balanced diet is crucial for long-term health.', ex1_ko = '균형 잡힌 식단을 유지하는 것은 장기적인 건강에 매우 중요해요.',
  ex2 = 'Maintaining a balanced diet is crucial for long-term health and disease prevention.', ex2_ko = '균형 잡힌 식단을 유지하는 것은 장기적인 건강과 질병 예방에 매우 중요해요.',
  ex3 = 'She believes that maintaining a balanced diet is crucial and plans her meals carefully.', ex3_ko = '그녀는 균형 잡힌 식단 유지가 중요하다고 믿으며 식단을 신중하게 계획해요.',
  ex4 = 'Doctors agree that maintaining a balanced diet is crucial for managing chronic conditions.', ex4_ko = '의사들은 균형 잡힌 식단 유지가 만성 질환 관리에 매우 중요하다는 데 동의해요.',
  ex5 = 'Even small improvements in diet can make maintaining a balanced diet feel more achievable.', ex5_ko = '식단에서 작은 개선만으로도 균형 잡힌 식단 유지를 더 달성 가능하게 느끼게 해줘요.'
WHERE id = 's_health_B2_01';

UPDATE sentences SET
  ex1 = 'Regular cardiovascular exercise can significantly reduce the risk of heart disease.', ex1_ko = '규칙적인 심혈관 운동은 심장 질환의 위험을 크게 줄일 수 있어요.',
  ex2 = 'Regular cardiovascular exercise can significantly reduce the risk of heart disease and stroke.', ex2_ko = '규칙적인 심혈관 운동은 심장 질환과 뇌졸중의 위험을 크게 줄일 수 있어요.',
  ex3 = 'She started regular cardiovascular exercise after her doctor warned her about her heart disease risk.', ex3_ko = '그녀는 의사가 심장 질환 위험을 경고한 후 규칙적인 심혈관 운동을 시작했어요.',
  ex4 = 'He lowered his blood pressure significantly through regular cardiovascular exercise.', ex4_ko = '그는 규칙적인 심혈관 운동을 통해 혈압을 크게 낮췄어요.',
  ex5 = 'Even thirty minutes of moderate cardiovascular exercise five days a week makes a significant difference.', ex5_ko = '일주일에 5일 30분씩 적당한 심혈관 운동만으로도 큰 차이가 생겨요.'
WHERE id = 's_health_B2_02';

UPDATE sentences SET
  ex1 = 'Chronic stress can have a profound impact on your immune system.', ex1_ko = '만성 스트레스는 면역 체계에 심각한 영향을 미칠 수 있어요.',
  ex2 = 'Chronic stress can have a profound impact on your immune system and make you more prone to illness.', ex2_ko = '만성 스트레스는 면역 체계에 심각한 영향을 미치고 질병에 더 취약하게 만들 수 있어요.',
  ex3 = 'She learned how chronic stress can have a profound impact on overall health through her medical studies.', ex3_ko = '그녀는 의학 공부를 통해 만성 스트레스가 전반적인 건강에 어떤 심각한 영향을 미칠 수 있는지 배웠어요.',
  ex4 = 'He was surprised to discover that chronic stress had been affecting his immune system for years.', ex4_ko = '그는 만성 스트레스가 수년간 면역 체계에 영향을 미쳐 왔다는 것을 알고 놀랐어요.',
  ex5 = 'Addressing chronic stress through mindfulness and exercise can help restore a healthy immune system.', ex5_ko = '마음 챙김과 운동을 통해 만성 스트레스를 해결하면 건강한 면역 체계를 회복하는 데 도움이 돼요.'
WHERE id = 's_health_B2_03';

UPDATE sentences SET
  ex1 = 'I''d like a second opinion before proceeding with surgery.', ex1_ko = '수술을 진행하기 전에 다른 의사의 의견을 듣고 싶어요.',
  ex2 = 'I''d like a second opinion before proceeding with surgery, as it''s a major procedure.', ex2_ko = '수술은 큰 시술이므로 진행 전에 다른 의사의 의견을 듣고 싶어요.',
  ex3 = 'She decided she''d like a second opinion before proceeding with surgery and made a new appointment.', ex3_ko = '그녀는 수술을 진행하기 전에 다른 의사의 의견을 듣기로 하고 새 예약을 했어요.',
  ex4 = 'He was glad he sought a second opinion before proceeding with surgery, as the new doctor suggested alternatives.', ex4_ko = '그는 수술 전에 다른 의견을 구해 다행이었어요. 새 의사가 대안을 제안했거든요.',
  ex5 = 'It is always your right to seek a second opinion before proceeding with any major surgery.', ex5_ko = '큰 수술을 진행하기 전에 다른 의견을 구하는 것은 항상 여러분의 권리예요.'
WHERE id = 's_health_B2_04';

UPDATE sentences SET
  ex1 = 'Poor sleep hygiene is closely linked to metabolic disorders.', ex1_ko = '나쁜 수면 위생은 대사 장애와 밀접하게 관련되어 있어요.',
  ex2 = 'Poor sleep hygiene is closely linked to metabolic disorders, including obesity and diabetes.', ex2_ko = '나쁜 수면 위생은 비만과 당뇨병을 포함한 대사 장애와 밀접하게 관련되어 있어요.',
  ex3 = 'Research confirms that poor sleep hygiene is closely linked to long-term metabolic health issues.', ex3_ko = '연구는 나쁜 수면 위생이 장기적인 대사 건강 문제와 밀접하게 관련되어 있음을 확인해요.',
  ex4 = 'She improved her metabolic health by addressing the poor sleep hygiene that was affecting her.', ex4_ko = '그녀는 자신을 괴롭히던 나쁜 수면 위생을 개선해 대사 건강을 향상시켰어요.',
  ex5 = 'Establishing a regular bedtime routine can dramatically improve poor sleep hygiene over time.', ex5_ko = '규칙적인 취침 루틴을 만들면 시간이 지나면서 나쁜 수면 위생을 크게 개선할 수 있어요.'
WHERE id = 's_health_B2_05';

UPDATE sentences SET
  ex1 = 'The prognosis depends largely on how early the condition is detected.', ex1_ko = '예후는 상태가 얼마나 일찍 발견되느냐에 크게 달려 있어요.',
  ex2 = 'The prognosis depends largely on how early the condition is detected and treated.', ex2_ko = '예후는 상태가 얼마나 일찍 발견되고 치료되느냐에 크게 달려 있어요.',
  ex3 = 'The doctor explained that the prognosis depends largely on early detection and lifestyle changes.', ex3_ko = '의사는 예후가 조기 발견과 생활 습관 변화에 크게 달려 있다고 설명했어요.',
  ex4 = 'She was told her prognosis depends largely on how well she responds to the initial treatment.', ex4_ko = '그녀는 예후가 초기 치료에 얼마나 잘 반응하느냐에 크게 달려 있다는 말을 들었어요.',
  ex5 = 'Regular screening programs exist precisely because the prognosis depends so heavily on early detection.', ex5_ko = '정기 검진 프로그램이 존재하는 것은 바로 예후가 조기 발견에 크게 달려 있기 때문이에요.'
WHERE id = 's_health_B2_06';

UPDATE sentences SET
  ex1 = 'Preventive healthcare is far more cost-effective than treating illness.', ex1_ko = '예방적 의료는 질병 치료보다 훨씬 비용 효율적이에요.',
  ex2 = 'Preventive healthcare is far more cost-effective than treating illness once it has progressed.', ex2_ko = '예방적 의료는 질병이 진행된 후 치료하는 것보다 훨씬 비용 효율적이에요.',
  ex3 = 'She advocates strongly for preventive healthcare, believing it is far more cost-effective.', ex3_ko = '그녀는 예방적 의료가 훨씬 비용 효율적이라고 믿으며 강력히 지지해요.',
  ex4 = 'The report showed that preventive healthcare is far more cost-effective for national health budgets.', ex4_ko = '보고서는 예방적 의료가 국가 보건 예산에 훨씬 비용 효율적임을 보여줬어요.',
  ex5 = 'Investing in preventive healthcare now is far more cost-effective than managing chronic disease later.', ex5_ko = '지금 예방적 의료에 투자하는 것이 나중에 만성 질환을 관리하는 것보다 훨씬 비용 효율적이에요.'
WHERE id = 's_health_B2_07';

-- C1

UPDATE sentences SET
  ex1 = 'Given the comorbidities involved, we need to approach treatment cautiously.', ex1_ko = '관련된 동반 질환을 고려해 치료에 신중하게 접근해야 해요.',
  ex2 = 'Given the comorbidities involved, we need to approach treatment cautiously and monitor for interactions.', ex2_ko = '관련된 동반 질환을 고려해 치료에 신중하게 접근하고 상호 작용을 모니터링해야 해요.',
  ex3 = 'The specialist noted that given the comorbidities, a multidisciplinary team would be needed.', ex3_ko = '전문의는 동반 질환을 고려할 때 다학제 팀이 필요할 것이라고 언급했어요.',
  ex4 = 'She understood why the doctor was proceeding slowly given the comorbidities she had developed.', ex4_ko = '그녀는 자신이 발생시킨 동반 질환을 감안해 의사가 천천히 진행하는 이유를 이해했어요.',
  ex5 = 'Treatment plans for patients with comorbidities require careful coordination between multiple specialists.', ex5_ko = '동반 질환 환자의 치료 계획은 여러 전문의 간의 신중한 조율이 필요해요.'
WHERE id = 's_health_C1_01';

UPDATE sentences SET
  ex1 = 'The etiology of this autoimmune condition remains poorly understood.', ex1_ko = '이 자가 면역 질환의 원인은 아직 잘 이해되지 않고 있어요.',
  ex2 = 'The etiology of this autoimmune condition remains poorly understood, making treatment challenging.', ex2_ko = '이 자가 면역 질환의 원인은 아직 잘 이해되지 않아 치료가 어려워요.',
  ex3 = 'Researchers have been investigating the etiology of the autoimmune condition for over a decade.', ex3_ko = '연구자들이 10년 이상 이 자가 면역 질환의 원인을 조사해 왔어요.',
  ex4 = 'She was told that the etiology of her condition remains unclear and further tests are needed.', ex4_ko = '그녀는 자신의 질환의 원인이 아직 불명확하고 추가 검사가 필요하다는 말을 들었어요.',
  ex5 = 'Understanding the etiology of autoimmune conditions is essential for developing targeted therapies.', ex5_ko = '자가 면역 질환의 원인을 이해하는 것은 표적 치료법 개발에 필수적이에요.'
WHERE id = 's_health_C1_02';

UPDATE sentences SET
  ex1 = 'We should consider prophylactic treatment to prevent recurrence.', ex1_ko = '재발을 예방하기 위해 예방적 치료를 고려해야 해요.',
  ex2 = 'We should consider prophylactic treatment to prevent recurrence, especially given the patient''s history.', ex2_ko = '특히 환자의 병력을 감안해 재발을 예방하기 위한 예방적 치료를 고려해야 해요.',
  ex3 = 'The committee recommended prophylactic treatment to prevent recurrence in high-risk patients.', ex3_ko = '위원회는 고위험 환자의 재발 예방을 위한 예방적 치료를 권고했어요.',
  ex4 = 'She agreed to start prophylactic treatment to prevent the recurrence that had troubled her before.', ex4_ko = '그녀는 이전에 문제가 됐던 재발을 예방하기 위해 예방적 치료를 시작하기로 동의했어요.',
  ex5 = 'Prophylactic treatment to prevent recurrence is often more manageable than treating a full relapse.', ex5_ko = '재발을 예방하는 예방적 치료는 완전한 재발을 치료하는 것보다 대체로 더 관리하기 쉬워요.'
WHERE id = 's_health_C1_03';

UPDATE sentences SET
  ex1 = 'Elevated biomarkers suggest the presence of systemic inflammation.', ex1_ko = '상승된 생체 지표는 전신 염증의 존재를 시사해요.',
  ex2 = 'Elevated biomarkers suggest the presence of systemic inflammation that needs further investigation.', ex2_ko = '상승된 생체 지표는 추가 조사가 필요한 전신 염증의 존재를 시사해요.',
  ex3 = 'The doctor explained that elevated biomarkers in the blood test suggest systemic inflammation.', ex3_ko = '의사는 혈액 검사의 상승된 생체 지표가 전신 염증을 시사한다고 설명했어요.',
  ex4 = 'She was referred to a specialist after elevated biomarkers suggested ongoing systemic inflammation.', ex4_ko = '상승된 생체 지표가 지속적인 전신 염증을 시사해 그녀는 전문의에게 의뢰됐어요.',
  ex5 = 'Monitoring elevated biomarkers over time helps track whether systemic inflammation is responding to treatment.', ex5_ko = '상승된 생체 지표를 시간에 따라 모니터링하면 전신 염증이 치료에 반응하고 있는지 추적하는 데 도움이 돼요.'
WHERE id = 's_health_C1_04';

UPDATE sentences SET
  ex1 = 'The patient has been in remission for over eighteen months.', ex1_ko = '환자는 18개월 이상 완화 상태에 있어요.',
  ex2 = 'The patient has been in remission for over eighteen months with no signs of recurrence.', ex2_ko = '환자는 18개월 이상 재발 징후 없이 완화 상태에 있어요.',
  ex3 = 'She was delighted to hear that she had been in remission for over eighteen months.', ex3_ko = '그녀는 18개월 이상 완화 상태에 있다는 말을 듣고 기뻤어요.',
  ex4 = 'After being in remission for over eighteen months, he was cautiously optimistic about the future.', ex4_ko = '18개월 이상 완화 상태를 유지한 후 그는 미래에 대해 조심스럽게 낙관적이었어요.',
  ex5 = 'Regular monitoring is still necessary even when a patient has been in remission for a long time.', ex5_ko = '환자가 오랫동안 완화 상태에 있더라도 정기적인 모니터링은 여전히 필요해요.'
WHERE id = 's_health_C1_05';

UPDATE sentences SET
  ex1 = 'There is a significant risk of thrombosis with prolonged immobility.', ex1_ko = '장시간 움직이지 않으면 혈전증의 위험이 크게 높아져요.',
  ex2 = 'There is a significant risk of thrombosis with prolonged immobility, especially during long flights.', ex2_ko = '장시간 비행처럼 오래 움직이지 않으면 혈전증의 위험이 크게 높아져요.',
  ex3 = 'Nurses reminded patients that there is a significant risk of thrombosis with prolonged bed rest.', ex3_ko = '간호사들은 환자들에게 장시간 침상 안정을 취하면 혈전증의 위험이 크게 높아진다고 상기시켰어요.',
  ex4 = 'He wore compression socks to reduce the risk of thrombosis during his long-haul flight.', ex4_ko = '그는 장거리 비행 중 혈전증 위험을 줄이기 위해 압박 양말을 착용했어요.',
  ex5 = 'Patients recovering from surgery should move frequently to reduce the risk of thrombosis.', ex5_ko = '수술에서 회복 중인 환자들은 혈전증 위험을 줄이기 위해 자주 움직여야 해요.'
WHERE id = 's_health_C1_06';

UPDATE sentences SET
  ex1 = 'Her symptoms are consistent with an autoimmune etiology.', ex1_ko = '그녀의 증상은 자가 면역 원인과 일치해요.',
  ex2 = 'Her symptoms are consistent with an autoimmune etiology, though further testing is required to confirm.', ex2_ko = '그녀의 증상은 자가 면역 원인과 일치하지만 확인을 위해 추가 검사가 필요해요.',
  ex3 = 'The rheumatologist concluded that her symptoms are consistent with an autoimmune etiology.', ex3_ko = '류마티스 전문의는 그녀의 증상이 자가 면역 원인과 일치한다고 결론지었어요.',
  ex4 = 'He was referred to a specialist after his GP noted his symptoms are consistent with an autoimmune condition.', ex4_ko = '일반의가 그의 증상이 자가 면역 질환과 일치한다고 판단해 그는 전문의에게 의뢰됐어요.',
  ex5 = 'When symptoms are consistent with an autoimmune etiology, early intervention can prevent serious complications.', ex5_ko = '증상이 자가 면역 원인과 일치할 때 조기 개입은 심각한 합병증을 예방할 수 있어요.'
WHERE id = 's_health_C1_07';

-- C2

UPDATE sentences SET
  ex1 = 'The pharmacokinetics of this compound are highly variable between patients.', ex1_ko = '이 화합물의 약동학은 환자 간에 매우 가변적이에요.',
  ex2 = 'The pharmacokinetics of this compound are highly variable between patients, requiring individualized dosing.', ex2_ko = '이 화합물의 약동학은 환자 간에 매우 가변적이어서 개별화된 투여량이 필요해요.',
  ex3 = 'Researchers found that the pharmacokinetics of this compound are influenced by age and liver function.', ex3_ko = '연구자들은 이 화합물의 약동학이 나이와 간 기능의 영향을 받는다는 것을 발견했어요.',
  ex4 = 'She studied the pharmacokinetics of the compound before proposing a new dosing schedule.', ex4_ko = '그녀는 새로운 투여 일정을 제안하기 전에 화합물의 약동학을 연구했어요.',
  ex5 = 'Understanding the pharmacokinetics of a drug is essential for optimizing therapeutic outcomes.', ex5_ko = '치료 결과를 최적화하기 위해서는 약물의 약동학을 이해하는 것이 필수적이에요.'
WHERE id = 's_health_C2_01';

UPDATE sentences SET
  ex1 = 'Histopathological findings confirmed the presence of carcinogenesis at the cellular level.', ex1_ko = '조직 병리학적 소견이 세포 수준에서 발암 과정의 존재를 확인했어요.',
  ex2 = 'Histopathological findings confirmed the presence of carcinogenesis, prompting immediate oncological referral.', ex2_ko = '조직 병리학적 소견이 발암 과정의 존재를 확인해 즉각적인 종양학 의뢰가 이루어졌어요.',
  ex3 = 'The pathologist explained that histopathological findings confirmed early-stage carcinogenesis in the tissue.', ex3_ko = '병리학자는 조직 병리학적 소견이 조직에서 초기 단계의 발암 과정을 확인했다고 설명했어요.',
  ex4 = 'She was alarmed when histopathological findings confirmed carcinogenesis, but reassured by the early stage.', ex4_ko = '그녀는 조직 병리학적 소견이 발암 과정을 확인했을 때 놀랐지만 초기 단계라는 사실에 안심했어요.',
  ex5 = 'When histopathological findings confirm carcinogenesis, a multidisciplinary team will develop a treatment plan.', ex5_ko = '조직 병리학적 소견이 발암 과정을 확인하면 다학제 팀이 치료 계획을 수립할 거예요.'
WHERE id = 's_health_C2_02';

UPDATE sentences SET
  ex1 = 'Prolonged immunosuppression increases the risk of nosocomial infections.', ex1_ko = '장기간의 면역 억제는 병원 감염의 위험을 높여요.',
  ex2 = 'Prolonged immunosuppression increases the risk of nosocomial infections and requires vigilant monitoring.', ex2_ko = '장기간의 면역 억제는 병원 감염의 위험을 높이며 세심한 모니터링이 필요해요.',
  ex3 = 'The transplant team warned that prolonged immunosuppression significantly increases infection risk.', ex3_ko = '이식 팀은 장기간의 면역 억제가 감염 위험을 크게 높인다고 경고했어요.',
  ex4 = 'She developed a nosocomial infection as a consequence of prolonged immunosuppression following the transplant.', ex4_ko = '그녀는 이식 후 장기간의 면역 억제의 결과로 병원 감염이 생겼어요.',
  ex5 = 'Strict hygiene protocols are critical for patients on prolonged immunosuppression to avoid nosocomial infections.', ex5_ko = '장기간의 면역 억제를 받는 환자들에게는 병원 감염을 피하기 위해 엄격한 위생 프로토콜이 중요해요.'
WHERE id = 's_health_C2_03';

UPDATE sentences SET
  ex1 = 'The sequelae of the cerebrovascular event require ongoing neurological monitoring.', ex1_ko = '뇌혈관 사건의 후유증에는 지속적인 신경학적 모니터링이 필요해요.',
  ex2 = 'The sequelae of the cerebrovascular event require ongoing neurological monitoring and rehabilitation therapy.', ex2_ko = '뇌혈관 사건의 후유증에는 지속적인 신경학적 모니터링과 재활 치료가 필요해요.',
  ex3 = 'The neurologist explained that the sequelae of the cerebrovascular event could persist for years.', ex3_ko = '신경과 의사는 뇌혈관 사건의 후유증이 수년간 지속될 수 있다고 설명했어요.',
  ex4 = 'She understood that managing the sequelae of the cerebrovascular event would require a long-term care plan.', ex4_ko = '그녀는 뇌혈관 사건의 후유증을 관리하려면 장기적인 치료 계획이 필요하다는 것을 이해했어요.',
  ex5 = 'Prompt treatment of a cerebrovascular event reduces the severity of its long-term sequelae significantly.', ex5_ko = '뇌혈관 사건을 신속하게 치료하면 장기적인 후유증의 심각도를 크게 줄여요.'
WHERE id = 's_health_C2_04';

UPDATE sentences SET
  ex1 = 'Iatrogenic complications were documented in three percent of cases.', ex1_ko = '의인성 합병증이 전체 사례의 3%에서 기록됐어요.',
  ex2 = 'Iatrogenic complications were documented in three percent of cases during the clinical trial.', ex2_ko = '임상 시험 동안 의인성 합병증이 전체 사례의 3%에서 기록됐어요.',
  ex3 = 'The hospital reviewed its protocols after iatrogenic complications were documented in several patients.', ex3_ko = '병원은 여러 환자에서 의인성 합병증이 기록된 후 프로토콜을 검토했어요.',
  ex4 = 'She published research on iatrogenic complications and their impact on patient recovery times.', ex4_ko = '그녀는 의인성 합병증과 환자 회복 시간에 대한 영향에 관한 연구를 발표했어요.',
  ex5 = 'Reducing iatrogenic complications requires continuous staff training and rigorous procedural standards.', ex5_ko = '의인성 합병증을 줄이려면 지속적인 직원 교육과 엄격한 절차 기준이 필요해요.'
WHERE id = 's_health_C2_05';

UPDATE sentences SET
  ex1 = 'Teratogenic effects were observed in preclinical studies, warranting caution in pregnant patients.', ex1_ko = '전임상 연구에서 최기형성 효과가 관찰되어 임산부에게 주의가 필요해요.',
  ex2 = 'Teratogenic effects were observed in preclinical studies, so the drug is contraindicated during pregnancy.', ex2_ko = '전임상 연구에서 최기형성 효과가 관찰되어 임신 중 이 약의 사용은 금기예요.',
  ex3 = 'The regulatory review flagged teratogenic effects observed in preclinical studies of the compound.', ex3_ko = '규제 검토에서 화합물의 전임상 연구에서 관찰된 최기형성 효과가 표시됐어요.',
  ex4 = 'She advised against the medication after teratogenic effects were observed in animal studies.', ex4_ko = '동물 연구에서 최기형성 효과가 관찰된 후 그녀는 해당 약물에 반대 의견을 냈어요.',
  ex5 = 'Any drug showing teratogenic effects in preclinical studies must carry a clear pregnancy warning.', ex5_ko = '전임상 연구에서 최기형성 효과를 보이는 약물에는 명확한 임신 경고가 있어야 해요.'
WHERE id = 's_health_C2_06';

UPDATE sentences SET
  ex1 = 'The anaphylactic response was attributed to cross-reactivity between structurally similar antigens.', ex1_ko = '아나필락시스 반응은 구조적으로 유사한 항원 간의 교차 반응성 때문인 것으로 밝혀졌어요.',
  ex2 = 'The anaphylactic response was attributed to cross-reactivity between structurally similar antigens in the medication.', ex2_ko = '아나필락시스 반응은 약물 내 구조적으로 유사한 항원 간의 교차 반응성 때문인 것으로 밝혀졌어요.',
  ex3 = 'Investigating the anaphylactic response revealed cross-reactivity as the underlying mechanism.', ex3_ko = '아나필락시스 반응을 조사한 결과 교차 반응성이 근본 메커니즘임이 밝혀졌어요.',
  ex4 = 'She presented a case study on anaphylactic responses attributed to cross-reactivity at the medical conference.', ex4_ko = '그녀는 의학 학술대회에서 교차 반응성으로 인한 아나필락시스 반응에 대한 사례 연구를 발표했어요.',
  ex5 = 'Understanding cross-reactivity helps clinicians predict and prevent anaphylactic responses in at-risk patients.', ex5_ko = '교차 반응성을 이해하면 임상의가 위험군 환자의 아나필락시스 반응을 예측하고 예방하는 데 도움이 돼요.'
WHERE id = 's_health_C2_07';
