UPDATE sentences SET
  ex1 = 'Permafrost thaw is projected to release gigatons of carbon, potentially creating a runaway feedback loop.',
  ex1_ko = '영구 동토층 해빙은 기가톤의 탄소를 방출하여 잠재적으로 폭주 피드백 루프를 만들 것으로 예측돼요.',
  ex2 = 'Permafrost thaw is projected to release gigatons of carbon, potentially creating a runaway feedback loop that exceeds current model projections.',
