UPDATE sentences SET
  ex1 = 'Teleconnections demonstrate that seemingly localised climate events can propagate disruptions across hemispheres.',
  ex1_ko = '원격연결은 겉보기에 지역적인 기후 사건이 반구 전체에 걸쳐 교란을 전파할 수 있음을 보여 줘요.',
