UPDATE sentences SET
  ex1 = 'Performance analytics has transformed the way teams approach match preparation.', ex1_ko = '경기력 분석학은 팀들이 경기 준비에 접근하는 방식을 변화시켰어요.',
  ex2 = 'Performance analytics has transformed the way teams approach match preparation over the last decade.', ex2_ko = '경기력 분석학은 지난 10년간 팀들이 경기 준비에 접근하는 방식을 변화시켰어요.',
  ex3 = 'She argues that performance analytics has transformed the way teams approach match preparation at every level.', ex3_ko = '그녀는 경기력 분석학이 모든 수준에서 팀들이 경기 준비에 접근하는 방식을 변화시켰다고 주장해요.',
  ex4 = 'Performance analytics has transformed the way teams approach match preparation, but some coaches remain sceptical.', ex4_ko = '경기력 분석학은 팀들이 경기 준비에 접근하는 방식을 변화시켰지만, 여전히 회의적인 코치들도 있어요.',
  ex5 = 'It is difficult to imagine elite football without the role performance analytics now plays in match preparation.', ex5_ko = '경기 준비에서 경기력 분석학이 현재 하는 역할 없이 엘리트 축구를 상상하기는 어려워요.'
WHERE id = 's_sports_B2_01';

UPDATE sentences SET
  ex1 = 'The data suggests that high-pressing tactics significantly increase the chance of winning.', ex1_ko = '데이터에 따르면 고압박 전술은 승리 가능성을 크게 높인다고 해요.',
  ex2 = 'The data suggests that high-pressing tactics significantly increase the chance of winning when applied consistently.', ex2_ko = '데이터에 따르면 고압박 전술을 일관되게 적용하면 승리 가능성을 크게 높인다고 해요.',
  ex3 = 'She cited research showing that the data suggests high-pressing tactics significantly increase the chance of winning.', ex3_ko = '그녀는 데이터에 따르면 고압박 전술이 승리 가능성을 크게 높인다는 것을 보여주는 연구를 인용했어요.',
  ex4 = 'The data suggests that high-pressing tactics significantly increase the chance of winning, provided the squad is fit enough.', ex4_ko = '데이터에 따르면, 선수단이 충분히 체력이 좋다면 고압박 전술이 승리 가능성을 크게 높인다고 해요.',
  ex5 = 'Not everyone agrees, but the data suggests that high-pressing tactics significantly increase the chance of winning long-term.', ex5_ko = '모두가 동의하는 것은 아니지만, 데이터에 따르면 고압박 전술이 장기적으로 승리 가능성을 크게 높인다고 해요.'
WHERE id = 's_sports_B2_02';

UPDATE sentences SET
  ex1 = 'Without proper periodization, athletes risk overtraining and burnout.', ex1_ko = '적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠져요.',
  ex2 = 'Without proper periodization, athletes risk overtraining and burnout regardless of their talent.', ex2_ko = '적절한 주기화 없이는 재능에 상관없이 선수들이 과훈련과 번아웃의 위험에 빠져요.',
  ex3 = 'She learned the hard way that without proper periodization, athletes risk overtraining and burnout.', ex3_ko = '그녀는 적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠진다는 것을 어렵게 배웠어요.',
  ex4 = 'Without proper periodization, athletes risk overtraining and burnout, which can end careers prematurely.', ex4_ko = '적절한 주기화 없이는 선수들이 과훈련과 번아웃의 위험에 빠지고, 이는 선수 생활을 조기에 끝낼 수 있어요.',
  ex5 = 'Sports scientists emphasise that without proper periodization, athletes risk overtraining and burnout even during successful seasons.', ex5_ko = '스포츠 과학자들은 적절한 주기화 없이는 성공적인 시즌 중에도 선수들이 과훈련과 번아웃의 위험에 빠질 수 있다고 강조해요.'
WHERE id = 's_sports_B2_03';

UPDATE sentences SET
  ex1 = 'Her tactical awareness sets her apart from other players in the league.', ex1_ko = '그녀의 전술적 인식이 리그의 다른 선수들과 그녀를 차별화해요.',
  ex2 = 'Her tactical awareness sets her apart from other players in the league, especially in high-pressure moments.', ex2_ko = '그녀의 전술적 인식은 특히 고압적인 순간에 리그의 다른 선수들과 그녀를 차별화해요.',
  ex3 = 'Scouts noticed early that her tactical awareness would set her apart from other players.', ex3_ko = '스카우터들은 그녀의 전술적 인식이 다른 선수들과 그녀를 차별화할 것임을 일찍 알아챘어요.',
  ex4 = 'Her tactical awareness sets her apart from other players in the league, and coaches appreciate her vision.', ex4_ko = '그녀의 전술적 인식이 리그의 다른 선수들과 그녀를 차별화하며, 코치들은 그녀의 시야를 높이 평가해요.',
  ex5 = 'It is her tactical awareness more than her physical ability that sets her apart from other players in the league.', ex5_ko = '그녀를 리그의 다른 선수들과 차별화하는 것은 신체적 능력보다 전술적 인식이에요.'
