UPDATE sentences SET
  ex1 = 'Do I need to transfer to get to Gangnam?', ex1_ko = '강남까지 가려면 환승해야 하나요?',
  ex2 = 'Is there a direct line to Gangnam, or do I need to transfer?', ex2_ko = '강남으로 가는 직행 노선이 있나요, 아니면 환승해야 하나요?',
  ex3 = 'How many times do I need to transfer to get to Gangnam?', ex3_ko = '강남까지 가려면 몇 번 환승해야 하나요?',
  ex4 = 'Which station should I transfer at to get to Gangnam?', ex4_ko = '강남에 가려면 어느 역에서 환승해야 하나요?',
  ex5 = 'You only need to transfer once — at City Hall — to get to Gangnam.', ex5_ko = '강남까지 가려면 시청에서 한 번만 환승하면 돼요.'
