UPDATE sentences SET
  ex1 = 'Where do I transfer for the red line?', ex1_ko = '빨간 노선으로 갈아타려면 어디서 환승하나요?',
  ex2 = 'Which platform do I use to transfer to the red line?', ex2_ko = '빨간 노선으로 환승하려면 어느 승강장을 이용하나요?',
  ex3 = 'Could you tell me where to change for the red line?', ex3_ko = '빨간 노선으로 갈아타는 곳을 알려 주실 수 있나요?',
  ex4 = 'I need to get to the red line — where should I transfer?', ex4_ko = '빨간 노선으로 가야 하는데 어디서 환승해야 하나요?',
  ex5 = 'The transfer for the red line is at the next station — just follow the signs.', ex5_ko = '빨간 노선 환승은 다음 역에서 할 수 있어요 — 표지판을 따라가세요.'
