UPDATE sentences SET
  ex1 = 'What time is the next train to Seoul?', ex1_ko = '서울행 다음 열차는 몇 시인가요?',
  ex2 = 'Could you check when the next train to Seoul departs?', ex2_ko = '서울행 다음 열차가 언제 출발하는지 확인해 주실 수 있나요?',
  ex3 = 'I have missed my train — what time is the next one to Seoul?', ex3_ko = '기차를 놓쳤는데 서울행 다음 열차는 몇 시인가요?',
  ex4 = 'The next train to Seoul leaves at quarter past three from platform two.', ex4_ko = '서울행 다음 열차는 3시 15분에 2번 승강장에서 출발해요.',
  ex5 = 'Is there still a train to Seoul after nine in the evening?', ex5_ko = '저녁 9시 이후에도 서울행 열차가 있나요?'
